export function buildRubricIssueFlagReport(
  releaseId,
  ratings = seedRatings,
  memos = adjudicationMemos,
  positionList = positions,
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const flagRows = ratings.flatMap((rating) =>
    RATER_ISSUE_FLAG_DEFINITIONS.filter((definition) => rating.flags?.[definition.key]).map((definition) => {
      const position = positionById.get(rating.positionId);
      const obfuscationNote = definition.key === "obfuscatedArgumentRisk" ? ratingObfuscationNoteForRating(rating) : "";
      return {
        ratingId: rating.id,
        itemId: makeItemId(rating.positionId, rating.critiqueId),
        raterId: rating.raterId,
        kind: rating.kind,
        split: position?.split ?? "unknown",
        releaseCritical: isReleaseCriticalSplit(position?.split),
        flag: definition.key,
        label: definition.label,
        issueType: definition.issueType,
        obfuscationNote,
        noteStatus:
          definition.key === "obfuscatedArgumentRisk"
            ? validateRatingObfuscationNote(obfuscationNote).ok
              ? "obfuscation_note_recorded"
              : "obfuscation_note_missing"
            : "not_applicable",
      };
    }),
  );
  const itemRows = [...new Set(ratings.map((rating) => makeItemId(rating.positionId, rating.critiqueId)))]
    .sort()
    .map((itemId) => {
      const itemRatings = ratings.filter((rating) => makeItemId(rating.positionId, rating.critiqueId) === itemId);
      const [positionId] = itemId.split("::");
      const productSpread = centralityStrengthSpread(itemRatings);
      const issueFlagCounts = Object.fromEntries(
        RATER_ISSUE_FLAG_DEFINITIONS.map((definition) => [
          definition.key,
          itemRatings.filter((rating) => rating.flags?.[definition.key]).length,
        ]),
      );
      return {
        itemId,
        split: positionById.get(positionId)?.split ?? "unknown",
        ratingCount: itemRatings.length,
        productSpread,
        productDisagreementStatus:
          productSpread !== null && productSpread > 0.3
            ? "product_level_disagreement_observed"
            : "no_high_product_level_disagreement",
        issueFlagCounts,
        issueFlagsPresent: Object.entries(issueFlagCounts)
          .filter(([, count]) => count > 0)
          .map(([flag]) => flag),
      };
    });
  const memoTaxonomyRows = RATER_ISSUE_FLAG_DEFINITIONS.map((definition) => {
    const matchingMemos = memos.filter((memo) =>
      definition.taxonomyCodes.some((code) => (memo.disagreementTaxonomy ?? []).includes(code)),
    );
    return {
      flag: definition.key,
      issueType: definition.issueType,
      taxonomyCodes: definition.taxonomyCodes,
      memoIds: matchingMemos.map((memo) => memo.id),
      covered: matchingMemos.length > 0,
    };
  });
  const flagCoverageRows = RATER_ISSUE_FLAG_DEFINITIONS.map((definition) => {
    const rows = flagRows.filter((row) => row.flag === definition.key);
    const taxonomyRow = memoTaxonomyRows.find((row) => row.flag === definition.key);
    const adjudicationTaxonomyCovered = taxonomyRow?.covered ?? false;
    const coverageStatus = rows.length === 0 ? "not_observed_in_seed" : adjudicationTaxonomyCovered ? "covered" : "adjudication_taxonomy_missing";
    return {
      flag: definition.key,
      label: definition.label,
      detail: definition.detail,
      issueType: definition.issueType,
      ratingFlagCount: rows.length,
      releaseCriticalRatingFlagCount: rows.filter((row) => row.releaseCritical).length,
      adjudicationTaxonomyCovered,
      coverageStatus,
      policy: definition.policy,
    };
  });
  const observedFlagCoverageRows = flagCoverageRows.filter((row) => row.ratingFlagCount > 0);
  const missingCoverageRows = observedFlagCoverageRows.filter((row) => !row.adjudicationTaxonomyCovered);
  const obfuscationRows = flagRows.filter((row) => row.flag === "obfuscatedArgumentRisk");
  const obfuscationRowsMissingNotes = obfuscationRows.filter((row) => row.noteStatus !== "obfuscation_note_recorded");
  const productDisagreementRows = itemRows.filter((row) => row.productDisagreementStatus === "product_level_disagreement_observed");
  const flagCounts = Object.fromEntries(
    RATER_ISSUE_FLAG_DEFINITIONS.map((definition) => [definition.key, flagRows.filter((row) => row.flag === definition.key).length]),
  );
  return {
    id: `rubric-issue-flags-${releaseId}`,
    releaseId,
    policy: {
      requiredRaterFlags: RATER_ISSUE_FLAG_DEFINITIONS.map((definition) => definition.key),
      separationRule:
        "Rater issue flags are structured workflow and adjudication signals, not substitutes for the seven LMCA scores or product-level score-spread disagreement.",
      productDisagreementRule:
        "Product-level disagreement is still computed from centrality x strength spread and reported as its own item-level condition.",
    },
    counts: {
      ratingRowCount: ratings.length,
      flaggedRatingRowCount: new Set(flagRows.map((row) => row.ratingId)).size,
      issueFlagRowCount: flagRows.length,
      strengthCentralityAllocationAmbiguityCount: flagRows.filter((row) => row.flag === "strengthCentralityAllocationAmbiguity").length,
      correctnessWeightingIssueCount: flagRows.filter((row) => row.flag === "correctnessWeightingIssue").length,
      clarityAfterEffortIssueCount: flagRows.filter((row) => row.flag === "clarityAfterEffortIssue").length,
      midRangeStrengthUncertaintyCount: flagRows.filter((row) => row.flag === "midRangeStrengthUncertainty").length,
      obfuscatedArgumentRiskCount: obfuscationRows.length,
      obfuscationNoteRows: obfuscationRows.filter((row) => row.noteStatus === "obfuscation_note_recorded").length,
      obfuscationNoteMissingRows: obfuscationRowsMissingNotes.length,
      observedIssueFlagFamilyCount: observedFlagCoverageRows.length,
      productLevelDisagreementItemCount: productDisagreementRows.length,
      coveredIssueFlagCount: observedFlagCoverageRows.filter((row) => row.adjudicationTaxonomyCovered).length,
      missingCoverageCount: missingCoverageRows.length,
      byFlag: flagCounts,
    },
    flagCoverageRows,
    flagRows,
    obfuscationRows,
    itemRows,
    memoTaxonomyRows,
    productDisagreementRows,
    releaseUseStatus:
      obfuscationRowsMissingNotes.length > 0
        ? "rubric_issue_obfuscation_notes_incomplete"
        : missingCoverageRows.length > 0
        ? "rubric_issue_flag_coverage_incomplete"
        : productDisagreementRows.length > 0
          ? "rubric_issue_flags_separated_with_product_disagreement"
          : "rubric_issue_flags_separated_from_product_disagreement",
  };
}

export function aggregateRatings(positionId, critiqueId, ratings, status = "initial_only") {
  const includedRatings = ratings.filter((rating) => rating.positionId === positionId && rating.critiqueId === critiqueId);
  const weightedMeanScores = Object.fromEntries(
    RUBRIC_DIMENSIONS.map((dimension) => {
      const values = includedScoresForDimension(includedRatings, dimension);
      return [dimension, values.length ? round(mean(values)) : null];
    }),
  );
  const medianScores = Object.fromEntries(
    RUBRIC_DIMENSIONS.map((dimension) => {
      const values = includedScoresForDimension(includedRatings, dimension);
      return [dimension, values.length ? round(median(values)) : null];
    }),
  );
  const products = includedRatings
    .filter((rating) => !isLowClarityProvisional(rating, "centrality") && !isLowClarityProvisional(rating, "strength"))
    .map((rating) => {
      const centrality = value(rating, "centrality");
      const strength = value(rating, "strength");
      return centrality !== null && strength !== null ? centrality * strength : null;
    })
    .filter((item) => typeof item === "number");
  const raterSet = new Set(includedRatings.map((rating) => rating.raterId));
  const expertSet = new Set(includedRatings.filter((rating) => ["graduate", "phd", "expert", "admin"].includes(rating.raterTier)).map((rating) => rating.raterId));
  const positionTextVersionIds = uniqueStrings(includedRatings.map((rating) => rating.positionTextVersionId).filter(Boolean));
  const critiqueTextVersionIds = uniqueStrings(includedRatings.map((rating) => rating.critiqueTextVersionId).filter(Boolean));
  return {
    positionId,
    critiqueId,
    weightedMeanScores,
    medianScores,
    centXStrWeightedMean: products.length ? round(mean(products)) : null,
    dimensionCoverageCounts: Object.fromEntries(RUBRIC_DIMENSIONS.map((dimension) => [dimension, dimensionCoverage(includedRatings, dimension)])),
    spreadPreDiscussion: spread(includedRatings.filter((rating) => rating.kind === "blind_initial"), "overall") ?? 0,
    spreadPostDiscussion: spread(includedRatings, "overall") ?? 0,
    raterCount: raterSet.size,
    expertCount: expertSet.size,
    uncertaintyFlag: detectEscalations(includedRatings).length > 0,
    finalLabelStatus: status,
    largestSingleRaterContributionShare: includedRatings.length ? round(1 / raterSet.size) : 0,
    positionTextVersionIds,
    critiqueTextVersionIds,
    itemTextVersionIds: uniqueStrings([...positionTextVersionIds, ...critiqueTextVersionIds]),
  };
}

function preLockVisibilityFromRating(rating) {
  const visibility = rating.preLockVisibility ?? {};
  return {
    sourceMetadataVisibleBeforeInitialLock: Boolean(
      rating.sourceMetadataVisibleBeforeInitialLock ?? visibility.sourceMetadataVisibleBeforeInitialLock ?? visibility.sourceMetadataVisible,
    ),
    adminTagsVisibleBeforeInitialLock: Boolean(
      rating.adminTagsVisibleBeforeInitialLock ?? visibility.adminTagsVisibleBeforeInitialLock ?? visibility.adminTagsVisible,
    ),
    topicRoutingTagsVisibleBeforeInitialLock: Boolean(
      rating.topicRoutingTagsVisibleBeforeInitialLock ?? visibility.topicRoutingTagsVisibleBeforeInitialLock ?? visibility.topicRoutingTagsVisible,
    ),
    benchmarkStatusVisibleBeforeInitialLock: Boolean(
      rating.benchmarkStatusVisibleBeforeInitialLock ?? visibility.benchmarkStatusVisibleBeforeInitialLock ?? visibility.benchmarkStatusVisible,
    ),
  };
}

function sourceTagVisibleBeforeInitialLock(rating) {
  const visibility = preLockVisibilityFromRating(rating);
  return Object.values(visibility).some(Boolean);
}

function blindAggregationExceptionId(rating) {
  return (
    rating.blindAggregationAdjudicatedExceptionId ??
    rating.preLockVisibility?.adjudicatedExceptionId ??
    rating.initialBlindingException?.adjudicatedExceptionId ??
    null
  );
}

function blindAggregationExceptionDisclosed(rating) {
  return Boolean(
    rating.blindAggregationExceptionDisclosed === true ||
      rating.preLockVisibility?.exceptionDisclosed === true ||
      rating.initialBlindingException?.disclosed === true,
  );
}

function hiddenBenchmarkInitialRatingPolicy(rating, positionList = positions) {
  const position = positionList.find((item) => item.id === rating.positionId);
  if (position?.split !== "hidden_benchmark" || rating.kind !== "blind_initial") return "not_hidden_benchmark_initial";
  if (!sourceTagVisibleBeforeInitialLock(rating)) return "include_hidden_source_tag_blind_initial";
  if (blindAggregationExceptionId(rating) && blindAggregationExceptionDisclosed(rating)) return "include_adjudicated_exception_disclosed";
  return "exclude_source_tag_visible_initial_from_blind_aggregation";
}

function ratingsEligibleForLabelSnapshot(ratings, positionList = positions) {
  return ratings.filter((rating) => hiddenBenchmarkInitialRatingPolicy(rating, positionList) !== "exclude_source_tag_visible_initial_from_blind_aggregation");
}

function buildReliabilityWeightModelReport(snapshotId, releaseId, ratings, pairs, itemLabels, status, positionList = positions) {
  const snapshotItemIds = new Set(pairs.map(({ positionId, critiqueId }) => makeItemId(positionId, critiqueId)));
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const includedRatings = ratings.filter((rating) => snapshotItemIds.has(makeItemId(rating.positionId, rating.critiqueId)));
  const excludedRatings = ratings.filter((rating) => !snapshotItemIds.has(makeItemId(rating.positionId, rating.critiqueId)));
  const raterRowsById = includedRatings.reduce((acc, rating) => {
    const itemId = makeItemId(rating.positionId, rating.critiqueId);
    acc[rating.raterId] ??= { raterId: rating.raterId, raterTiers: new Set(), itemIds: new Set(), ratingKinds: {} };
    acc[rating.raterId].raterTiers.add(rating.raterTier);
    acc[rating.raterId].itemIds.add(itemId);
    acc[rating.raterId].ratingKinds[rating.kind] = (acc[rating.raterId].ratingKinds[rating.kind] ?? 0) + 1;
    return acc;
  }, {});
  const raterWeights = Object.values(raterRowsById)
    .map((row) => ({
      raterId: row.raterId,
      raterTiers: [...row.raterTiers].sort(),
      includedItemCount: row.itemIds.size,
      ratingKinds: row.ratingKinds,
      dimensionWeights: Object.fromEntries(RUBRIC_DIMENSIONS.map((dimension) => [dimension, 1])),
      fitSource: "uniform_project_default_not_learned_from_validation_or_hidden_benchmark",
    }))
    .sort((left, right) => right.includedItemCount - left.includedItemCount || left.raterId.localeCompare(right.raterId));
  const itemContributionRows = Object.entries(itemLabels)
    .map(([itemId, label]) => ({
      itemId,
      raterCount: label.raterCount,
      expertCount: label.expertCount,
      largestSingleRaterContributionShare: label.largestSingleRaterContributionShare,
      dominanceStatus: label.largestSingleRaterContributionShare > 0.5 ? "single_rater_dominance_disclosed" : "pass",
      independentExpertReviewRequired: label.largestSingleRaterContributionShare > 0.5 && label.expertCount === 0,
    }))
    .sort((left, right) => right.largestSingleRaterContributionShare - left.largestSingleRaterContributionShare || left.itemId.localeCompare(right.itemId));
  const sensitivityRows = Object.entries(itemLabels).map(([itemId, label]) => {
    const dimensionMeanMinusMedian = Object.fromEntries(
      RUBRIC_DIMENSIONS.map((dimension) => {
        const meanValue = label.weightedMeanScores[dimension];
        const medianValue = label.medianScores[dimension];
        return [
          dimension,
          isValidScore(meanValue) && isValidScore(medianValue) ? round(meanValue - medianValue) : null,
        ];
      }),
    );
    const overallDelta = dimensionMeanMinusMedian.overall;
    return {
      itemId,
      dimensionMeanMinusMedian,
      absOverallMeanMedianDelta: typeof overallDelta === "number" ? round(Math.abs(overallDelta)) : null,
    };
  });
  const maxOverallDeltaRow = sensitivityRows
    .filter((row) => typeof row.absOverallMeanMedianDelta === "number")
    .sort((left, right) => right.absOverallMeanMedianDelta - left.absOverallMeanMedianDelta || left.itemId.localeCompare(right.itemId))[0];
  const protectedExcludedSplits = ["internal_validation", "hidden_benchmark"];
  const protectedRatingsUsedForFit = includedRatings.filter((rating) => protectedExcludedSplits.includes(positionById.get(rating.positionId)?.split)).length;
  return {
    id: `reliability-weight-model-${snapshotId}`,
    releaseId,
    labelSnapshotId: snapshotId,
    targetLabelStatus: status,
    reliabilityWeightModelId: "uniform-v1-with-sensitivity",
    modelFamily: "uniform_equal_rater_weight",
    frozenBeforeAggregation: true,
    learnedReliabilityWeightsUsed: false,
    fitDataProvenance: {
      permittedFitSplits: ["public_train"],
      protectedExcludedSplits,
      fitRatingCount: 0,
      fitItemCount: 0,
      protectedRatingsUsedForFit: 0,
      observedProtectedRatingRows: protectedRatingsUsedForFit,
      rationale: "The seed release uses a frozen uniform rater-weight model; protected validation and hidden benchmark ratings are observed for reporting only and are not fit data.",
    },
    raterWeights,
    effectiveContribution: {
      maxSingleRaterContributionShare: itemContributionRows[0]?.largestSingleRaterContributionShare ?? null,
      singleRaterDominatedItemIds: itemContributionRows.filter((row) => row.largestSingleRaterContributionShare > 0.5).map((row) => row.itemId),
      independentExpertReviewRequiredItemIds: itemContributionRows.filter((row) => row.independentExpertReviewRequired).map((row) => row.itemId),
      itemRows: itemContributionRows,
      dominanceReviewStatus: itemContributionRows.some((row) => row.independentExpertReviewRequired)
        ? "single_rater_dominance_review_required_before_strong_claims"
        : "single_rater_dominance_disclosed",
    },
    sensitivitySummary: {
      unweightedMeanMatchesHeadline: true,
      unweightedMeanPolicy: "Headline labels use equal per-rater means; no reliability-upweighted mean is substituted.",
      medianSensitivityAvailable: true,
      meanAbsMeanMedianDeltaByDimension: Object.fromEntries(
        RUBRIC_DIMENSIONS.map((dimension) => {
          const values = sensitivityRows
            .map((row) => row.dimensionMeanMinusMedian[dimension])
            .filter((value) => typeof value === "number")
            .map((value) => Math.abs(value));
          return [dimension, values.length ? round(mean(values)) : null];
        }),
      ),
      maxOverallMeanMedianDelta: maxOverallDeltaRow?.absOverallMeanMedianDelta ?? null,
      maxOverallMeanMedianDeltaItemId: maxOverallDeltaRow?.itemId ?? null,
      itemRows: sensitivityRows,
    },
    includedRatingProvenance: {
      includedRatingCount: includedRatings.length,
      excludedRatingCount: excludedRatings.length,
      includedRatingKinds: countBy(includedRatings, "kind"),
      includedRaterCount: raterWeights.length,
      includedItemCount: Object.keys(itemLabels).length,
    },
    releaseUseStatus: "uniform_weights_frozen_with_sensitivity_report",
  };
}

export function buildRaterReliabilityWeightModelEvidence(releaseId, labelSnapshot, submittedModels = []) {
  const rows = submittedModels.map((model) => normalizeSubmittedRaterReliabilityWeightModel(model, labelSnapshot)).filter(Boolean);
  const activeSubmittedModel = rows.find((row) => row.reliabilityWeightModelId === labelSnapshot.reliabilityWeightModelId) ?? null;
  const reviewRows = rows.filter(
    (row) =>
      row.protectedSplitExclusionStatus !== "protected_splits_excluded_from_weight_fit" ||
      row.fitSourceStatus !== "permitted_fit_source_declared" ||
      row.sensitivityStatus !== "unweighted_and_median_sensitivity_linked" ||
      row.weightCapStatus === "weight_cap_review_required" ||
      row.missingRequiredFields.length > 0,
  );
  return {
    id: `rater-reliability-weight-model-evidence-${releaseId}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    labelSnapshotReliabilityWeightModelId: labelSnapshot.reliabilityWeightModelId,
    headlineAggregationModelFamily: labelSnapshot.reliabilityWeightModel?.modelFamily ?? null,
    submittedModelCount: rows.length,
    activeSubmittedModelId: activeSubmittedModel?.workflowRecordId ?? null,
    activeSubmittedReliabilityWeightModelId: activeSubmittedModel?.reliabilityWeightModelId ?? null,
    submittedRows: rows,
    reviewRows,
    policy: {
      frozenBeforeUseRule:
        "A submitted RaterReliabilityWeightModel must name the label snapshot weight-model id, fit source, protected-split exclusions, weight caps, effective sample size, and unweighted/median sensitivity snapshots before release-critical use.",
      noHiddenBenchmarkFitRule:
        "Reliability weights must not be fit or tuned on hidden benchmark or protected validation model performance.",
      currentHeadlinePolicy:
        "The current label snapshot still exposes the aggregation model actually used for headline labels; submitted workflow records are provenance evidence and must match the snapshot weight-model id to count as active.",
    },
    releaseUseStatus: !rows.length
      ? "default_uniform_weight_model_used_no_submitted_model"
      : !activeSubmittedModel
        ? "submitted_weight_model_recorded_not_current_label_snapshot"
        : reviewRows.some((row) => row.workflowRecordId === activeSubmittedModel.workflowRecordId)
          ? "active_submitted_weight_model_provenance_review_required"
          : "active_submitted_weight_model_provenance_complete",
  };
}

function normalizeSubmittedRaterReliabilityWeightModel(model, labelSnapshot) {
  const workflowRecordId = model?.id ?? model?.raterReliabilityWeightModelId ?? model?.reliability_weight_model_id;
  if (!workflowRecordId) return null;
  const protectedSplitExclusions = model.protectedSplitExclusions ?? model.protected_split_exclusions ?? [];
  const requiredProtectedSplits = ["hidden_benchmark", "internal_validation"];
  const missingProtectedSplitExclusions = requiredProtectedSplits.filter((split) => !protectedSplitExclusions.includes(split));
  const weightCap = numberOrNull(model.weightCaps?.maxSingleRaterShare ?? model.maximumSingleRaterWeightShare);
  const maxShare = numberOrNull(
    model.maximumSingleRaterWeightShareObserved ?? model.maxSingleRaterContributionShare ?? model.maximumSingleRaterWeightShare,
  );
  const effectiveSampleSizeByDimension = model.effectiveSampleSizeByDimension ?? model.effectiveSampleSizeEstimates ?? {};
  const fitDataSource = model.fitDataSource ?? null;
  const unweightedSensitivitySnapshotId = model.unweightedSensitivitySnapshotId ?? model.unweighted_sensitivity_snapshot_id ?? null;
  const medianSensitivitySnapshotId = model.medianSensitivitySnapshotId ?? model.median_sensitivity_snapshot_id ?? null;
  const raterWeightsByDimension = model.raterWeightsByDimension ?? model.rater_weights_by_dimension ?? {};
  const requiredFields = {
    modelName: model.modelName,
    version: model.version ?? model.freezeVersion,
    fitDataSource: model.fitDataSource,
    protectedSplitExclusions,
    raterWeightsByDimension,
    weightCap,
    effectiveSampleSizeByDimension,
    unweightedSensitivitySnapshotId,
    medianSensitivitySnapshotId,
  };
  const missingRequiredFields = Object.entries(requiredFields)
    .filter(([, value]) => value === null || value === undefined || value === "" || (Array.isArray(value) && value.length === 0) || (typeof value === "object" && !Array.isArray(value) && Object.keys(value).length === 0))
    .map(([field]) => field);
  return {
    workflowRecordId,
    reliabilityWeightModelId: model.reliabilityWeightModelId ?? model.reliability_weight_model_id ?? workflowRecordId,
    labelSnapshotId: model.labelSnapshotId ?? labelSnapshot.id,
    modelName: model.modelName ?? null,
    version: model.version ?? null,
    freezeVersion: model.freezeVersion ?? model.version ?? null,
    fitDataSource,
    fitSourceStatus: fitDataSource && !String(fitDataSource).includes("hidden_benchmark") && !String(fitDataSource).includes("model_performance")
      ? "permitted_fit_source_declared"
      : "fit_source_review_required",
    fittedAt: model.fittedAt ?? model.timestamp ?? null,
    fittedBy: model.fittedBy ?? model.createdBy ?? null,
    protectedSplitExclusions,
    missingProtectedSplitExclusions,
    protectedSplitExclusionStatus: missingProtectedSplitExclusions.length
      ? "protected_split_exclusion_review_required"
      : "protected_splits_excluded_from_weight_fit",
    perDimensionReliabilityEstimates: model.perDimensionReliabilityEstimates ?? {},
    raterWeightsByDimension,
    weightCaps: model.weightCaps ?? {},
    maximumSingleRaterWeightShare: maxShare,
    weightCap,
    weightCapStatus:
      typeof maxShare === "number" && typeof weightCap === "number" && maxShare > weightCap
        ? "weight_cap_review_required"
        : typeof weightCap === "number"
          ? "weight_cap_declared"
          : "weight_cap_missing",
    shrinkagePolicy: model.shrinkagePolicy ?? null,
    minimumEvidenceThreshold: model.minimumEvidenceThreshold ?? null,
    effectiveSampleSizeByDimension,
    effectiveSampleSizeStatus: Object.keys(effectiveSampleSizeByDimension).length ? "effective_sample_size_declared" : "effective_sample_size_missing",
    unweightedSensitivitySnapshotId,
    medianSensitivitySnapshotId,
    sensitivityStatus:
      unweightedSensitivitySnapshotId && medianSensitivitySnapshotId ? "unweighted_and_median_sensitivity_linked" : "sensitivity_links_missing",
    matchesCurrentLabelSnapshotModel:
      (model.reliabilityWeightModelId ?? model.reliability_weight_model_id ?? workflowRecordId) === labelSnapshot.reliabilityWeightModelId,
    missingRequiredFields,
  };
}

function numberOrNull(value) {
  return value !== null && value !== undefined && value !== "" && Number.isFinite(Number(value)) ? Number(value) : null;
}

export function createLabelSnapshot(id, releaseId, ratings, pairs, status = "initial_only", positionList = positions) {
  const snapshotRatings = ratingsEligibleForLabelSnapshot(ratings, positionList);
  const excludedBlindAggregationRows = ratings
    .filter((rating) => !snapshotRatings.includes(rating))
    .map((rating) => ({
      ratingId: rating.id,
      itemId: makeItemId(rating.positionId, rating.critiqueId),
      exclusionReason: hiddenBenchmarkInitialRatingPolicy(rating, positionList),
    }));
  const itemLabels = Object.fromEntries(
    pairs.map(({ positionId, critiqueId }) => [makeItemId(positionId, critiqueId), aggregateRatings(positionId, critiqueId, snapshotRatings, status)]),
  );
  const reliabilityWeightModel = buildReliabilityWeightModelReport(id, releaseId, snapshotRatings, pairs, itemLabels, status, positionList);
  return {
    id,
    releaseId,
    targetLabelVersion: status === "benchmark_frozen" ? "benchmark_frozen" : status === "adjudicated" ? "adjudicated" : "initial_mean",
    status,
    rubricVersion: "lmca-app-f-2026-10",
    reliabilityWeightModelId: "uniform-v1-with-sensitivity",
    reliabilityWeightModel,
    aggregationSensitivity: reliabilityWeightModel.sensitivitySummary,
    includedRatingProvenance: reliabilityWeightModel.includedRatingProvenance,
    excludedBlindAggregationRows,
    createdAt: new Date().toISOString(),
    itemLabels,
    denominatorCounts: {
      blindInitialRatings: countKind(ratings, "blind_initial"),
      revisions: countKind(ratings, "revision"),
      selfChecks: countKind(ratings, "self_check"),
      expertChecks: countKind(ratings, "expert_check"),
      modelAssistedChecks: countKind(ratings, "model_assisted_check"),
      adjudicationLabels: countKind(ratings, "adjudication"),
      totalRows: ratings.length,
    },
  };
}

export function selectPrimaryRaterAnchor(
  ratings,
  pairs,
  options = {},
) {
  const policy = options.primaryRaterAnchorPolicy ?? null;
  const allowedKinds = options.allowedKinds ?? policy?.allowedKinds ?? ["blind_initial"];
  const eligibleItemIds = new Set(pairs.map(({ positionId, critiqueId }) => makeItemId(positionId, critiqueId)));
  const coverageByRater = {};
  ratings
    .filter((rating) => allowedKinds.includes(rating.kind) && eligibleItemIds.has(makeItemId(rating.positionId, rating.critiqueId)))
    .forEach((rating) => {
      coverageByRater[rating.raterId] ??= { raterId: rating.raterId, itemIds: new Set(), tiers: new Set() };
      coverageByRater[rating.raterId].itemIds.add(makeItemId(rating.positionId, rating.critiqueId));
      coverageByRater[rating.raterId].tiers.add(rating.raterTier);
    });
  const rows = Object.values(coverageByRater)
    .map((row) => ({
      raterId: row.raterId,
      coverageItemCount: row.itemIds.size,
      coverageShare: round(row.itemIds.size / Math.max(1, eligibleItemIds.size)),
      raterTiers: [...row.tiers].sort(),
    }))
    .sort((left, right) => right.coverageItemCount - left.coverageItemCount || left.raterId.localeCompare(right.raterId));
  const selected =
    policy?.fixedRaterId
      ? rows.find((row) => row.raterId === policy.fixedRaterId) ?? { raterId: policy.fixedRaterId, coverageItemCount: 0, coverageShare: 0, raterTiers: [] }
      : rows[0] ?? { raterId: null, coverageItemCount: 0, coverageShare: 0, raterTiers: [] };
  const coverageThreshold = policy?.coverageThreshold ?? options.coverageThreshold ?? 0;
  return {
    ...selected,
    candidateRows: rows,
    selectionPolicy: policy?.selectionRule ?? "predeclared_max_blind_initial_coverage_tie_break_rater_id",
    selectionPolicyId: policy?.id ?? null,
    selectionPolicySource: policy?.policySource ?? "default_project_anchor_policy",
    allowedKinds,
    coverageThreshold,
    coverageThresholdMet: selected.coverageShare >= coverageThreshold,
    predeclaredAt: policy?.predeclaredAt ?? "2026-09-30T12:00:00.000Z",
    frozenBeforeModelEvaluation: policy?.frozenBeforeModelEvaluation ?? true,
    prohibitedPostHocCriteria:
      policy?.prohibitedPostHocCriteria ?? ["agreement_with_model_outputs", "desired_leaderboard_effect", "post_hoc_target_label_switching"],
    missingProhibitedPostHocCriteria: policy?.missingProhibitedPostHocCriteria ?? [],
    policyStatus:
      policy?.policyStatus ??
      (selected.coverageShare >= coverageThreshold ? "default_primary_rater_anchor_policy_applied" : "primary_rater_anchor_coverage_threshold_unmet"),
  };
}

export function createPrimaryRaterAnchorSnapshot(id, releaseId, ratings, pairs, options = {}) {
  const anchor = options.anchor ?? selectPrimaryRaterAnchor(ratings, pairs, options);
  const allowedKinds = anchor.allowedKinds ?? options.allowedKinds ?? ["blind_initial"];
  const anchorRatings = ratings.filter((rating) => rating.raterId === anchor.raterId && allowedKinds.includes(rating.kind));
  const itemLabels = Object.fromEntries(
    pairs.map(({ positionId, critiqueId }) => [makeItemId(positionId, critiqueId), aggregateRatings(positionId, critiqueId, anchorRatings, "primary_rater_anchor")]),
  );
  return {
    id,
    releaseId,
    targetLabelVersion: "primary_rater_anchor",
    status: "primary_rater_anchor",
    rubricVersion: "lmca-app-f-2026-10",
    reliabilityWeightModelId: "single-primary-rater-no-reliability-weighting",
    createdAt: new Date().toISOString(),
    primaryRaterAnchor: anchor,
    primaryRaterAnchorPolicy: options.primaryRaterAnchorPolicy ?? null,
    itemLabels,
    denominatorCounts: {
      blindInitialRatings: countKind(anchorRatings, "blind_initial"),
      revisions: countKind(anchorRatings, "revision"),
      selfChecks: countKind(anchorRatings, "self_check"),
      expertChecks: countKind(anchorRatings, "expert_check"),
      modelAssistedChecks: countKind(anchorRatings, "model_assisted_check"),
      adjudicationLabels: countKind(anchorRatings, "adjudication"),
      totalRows: anchorRatings.length,
    },
    aggregationSensitivity: {
      unweightedMedianAvailable: false,
      finalAverageApproximation: false,
      note: "Primary-rater anchor preserves LMCA Table-5-style target semantics; consensus snapshots should be reported separately for quality-sensitive targets.",
    },
  };
}

const REQUIRED_PRIMARY_RATER_ANCHOR_POLICY_FIELDS = ["id", "releaseId", "selectionRule", "coverageThreshold", "predeclaredAt"];
const REQUIRED_PRIMARY_RATER_ANCHOR_PROHIBITED_POSTHOC_CRITERIA = [
  "agreement_with_model_outputs",
  "desired_leaderboard_effect",
  "post_hoc_target_label_switching",
];

export function buildEffectivePrimaryRaterAnchorPolicy(releaseId, submittedPolicies = []) {
  const requiredProhibitedPostHocCriteria = REQUIRED_PRIMARY_RATER_ANCHOR_PROHIBITED_POSTHOC_CRITERIA;
  const submittedPolicy = submittedPolicies.at(-1) ?? null;
  const prohibitedPostHocCriteria = submittedPolicy?.prohibitedPostHocCriteria ?? requiredProhibitedPostHocCriteria;
  const missingProhibitedPostHocCriteria = requiredProhibitedPostHocCriteria.filter((criterion) => !prohibitedPostHocCriteria.includes(criterion));
  const policyContractChecks = submittedPolicy ? submittedPrimaryRaterAnchorPolicyContractChecks(submittedPolicy) : [];
  const policyContractViolations = policyContractChecks.filter((check) => check.status !== "pass");
  const predeclaredAt = submittedPolicy?.predeclaredAt ?? submittedPolicy?.frozenAt ?? null;
  const policySource = submittedPolicy ? "submitted_workflow_primary_rater_anchor_policy" : "default_project_anchor_policy";
  const fixedRaterId = submittedPolicy?.primaryRaterId ?? submittedPolicy?.raterId ?? null;
  const coverageThreshold = Number.isFinite(Number(submittedPolicy?.coverageThreshold)) ? Number(submittedPolicy.coverageThreshold) : 0;
  const frozenBeforeModelEvaluation = submittedPolicy ? Boolean(predeclaredAt) : true;
  const policyStatus =
    submittedPolicy && policyContractViolations.length
      ? "submitted_anchor_policy_contract_review_required"
      : submittedPolicy && !predeclaredAt
        ? "submitted_anchor_policy_missing_predeclaration_time"
        : missingProhibitedPostHocCriteria.length
          ? "submitted_anchor_policy_missing_posthoc_prohibitions"
          : submittedPolicy
            ? "submitted_anchor_policy_predeclared"
            : "default_primary_rater_anchor_policy_applied";
  return {
    id: submittedPolicy?.id ?? `primary-rater-anchor-policy-${releaseId}`,
    releaseId: submittedPolicy?.releaseId ?? releaseId,
    policySource,
    selectionRule: submittedPolicy?.selectionRule ?? "predeclared_max_blind_initial_coverage_tie_break_rater_id",
    fixedRaterId,
    coverageThreshold,
    topicExpertiseThreshold: submittedPolicy?.topicExpertiseThreshold ?? null,
    allowedKinds: submittedPolicy?.allowedKinds ?? ["blind_initial"],
    predeclaredAt: submittedPolicy ? predeclaredAt : "2026-09-30T12:00:00.000Z",
    frozenBeforeModelEvaluation,
    prohibitedPostHocCriteria,
    requiredProhibitedPostHocCriteria,
    missingProhibitedPostHocCriteria,
    policyContractChecks,
    policyContractViolations,
    policyStatus,
  };
}

function submittedPrimaryRaterAnchorPolicyContractChecks(submittedPolicy) {
  const fieldChecks = REQUIRED_PRIMARY_RATER_ANCHOR_POLICY_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: submittedPolicy?.[field] ?? null,
    status: hasRequiredValue(submittedPolicy?.[field]) ? "pass" : "missing_required_field",
  }));
  const prohibitedCriteria = normalizeStringArray(submittedPolicy?.prohibitedPostHocCriteria);
  const prohibitedCriterionChecks = REQUIRED_PRIMARY_RATER_ANCHOR_PROHIBITED_POSTHOC_CRITERIA.map((criterion) => ({
    field: "prohibitedPostHocCriteria",
    expected: criterion,
    observed: prohibitedCriteria,
    status: prohibitedCriteria.includes(criterion) ? "pass" : "missing_required_criterion",
  }));
  return [...fieldChecks, ...prohibitedCriterionChecks];
}

export function buildReleaseGateProfile(releaseId) {
  return {
    id: `gate-${releaseId}`,
    releaseId,
    claimTier: "hidden_benchmark",
    frozenAt: "2026-09-30T12:00:00.000Z",
    sourceCriticalCore: [
      gate("position-critique-units", "Position + critique unit model", "pass", "source_critical_core", "Position, Critique, ItemTextVersion, and Rating records are keyed by position and critique ids."),
      gate("seven-dimensions", "Seven exact LMCA dimensions", "pass", "source_critical_core", "RUBRIC_DIMENSIONS stores centrality, strength, correctness, clarity, dead_weight, single_issue, overall."),
      gate("blind-initial", "Blind initial rating surface", "pass", "source_critical_core", "createBlindRatingView strips source, tags, benchmark status, model scores, and peer ratings."),
      gate("immutable-revisions", "Original ratings preserved after revision", "pass", "source_critical_core", "appendRatingRevision creates a child revision with parentRatingId and does not mutate the original."),
      gate("metric-families", "Weighted pairwise and custom loss kept separate", "pass", "source_critical_core", "Evaluation UI and scoring functions compute separate metric families."),
    ],
    benchmarkQualitySafeguards: [
      gate("split-isolation", "Position-cluster split isolation", "partial", "benchmark_quality", "Schema stores cluster ids and split labels; import-time blocking is ready for backend enforcement."),
      gate("release-manifests", "Public/internal/hidden manifests", "pass", "benchmark_quality", "createExportManifest emits split-aware manifests and excludes hidden benchmark from public/training exports."),
      gate("artifact-balance", "Source/style artifact balance", "partial", "benchmark_quality", "Position and critique source/style fields are modeled and shown in release reports."),
      gate("access-audit", "Hidden benchmark access audit", "pass", "benchmark_quality", "Admin-only benchmark endpoints write append-only exposure logs and feed the hidden benchmark freeze report."),
    ],
    claimGatedDiagnostics: [
      gate("derived-utility", "Full-rubric derived utility diagnostic", "pass", "claim_gated_diagnostic", "defaultFullRubricUtility normalizes dead_weight and declares low-clarity target policy."),
      gate("sycophancy", "Sycophancy and orthodoxy probes", "deferred", "claim_gated_diagnostic", "Not run for the seed demo because no robustness claim is made.", "Required only when a release makes deference/orthodoxy robustness claims."),
      gate("obfuscation", "Obfuscation stress probes", "deferred", "claim_gated_diagnostic", "Seed rubric fixtures include obfuscation handling; generated stress runs are not claimed.", "Required when reporting obfuscated-argument robustness."),
    ],
  };
}

const REQUIRED_RELEASE_GATE_PROFILE_FIELDS = ["id", "releaseId", "releaseVersion", "profileName", "notRunRationalePolicy", "approvedBy", "frozenAt", "timestamp"];
const REQUIRED_RELEASE_GATE_REQUIRED_IF_CLAIMED_RULES = [
  "lmca-comparability-claim-requires-method-core-and-comparability-matrix",
  "hidden-benchmark-claim-requires-split-isolation-access-audit-and-artifact-balance",
  "robustness-claim-requires-matching-diagnostic-or-deferral",
];
const RELEASE_GATE_NOT_RUN_POLICY_FRAGMENTS = ["deferred", "not-run", "not run", "suppress", "claim"];

export function buildEffectiveReleaseGateProfile(releaseId, submittedProfiles = []) {
  const baseProfile = buildReleaseGateProfile(releaseId);
  const submittedProfile = submittedProfiles.at(-1) ?? null;
  if (!submittedProfile) {
    return {
      ...baseProfile,
      profileSource: "default_project_gate_catalog",
      submittedProfileId: null,
      profileCoverage: gateProfileCoverageSummary(baseProfile, null),
    };
  }
  const sourceCriticalCore = mergeSubmittedGateGroup(baseProfile.sourceCriticalCore, submittedProfile, "sourceCriticalCore", "sourceCriticalCoreGates");
  const benchmarkQualitySafeguards = mergeSubmittedGateGroup(
    baseProfile.benchmarkQualitySafeguards,
    submittedProfile,
    "benchmarkQualitySafeguards",
    "benchmarkQualityGates",
  );
  const claimGatedDiagnostics = mergeSubmittedGateGroup(baseProfile.claimGatedDiagnostics, submittedProfile, "claimGatedDiagnostics", "claimGatedDiagnostics");
  const profileContractChecks = submittedReleaseGateProfileContractChecks(submittedProfile);
  const profileContractViolations = profileContractChecks.filter((check) => check.status !== "pass");
  const profile = {
    ...baseProfile,
    id: submittedProfile.id ?? baseProfile.id,
    releaseId: submittedProfile.releaseId ?? releaseId,
    releaseVersion: submittedProfile.releaseVersion ?? submittedProfile.release_version ?? null,
    claimTier: submittedProfile.claimTier ?? baseProfile.claimTier,
    frozenAt: submittedProfile.frozenAt ?? submittedProfile.createdAt ?? baseProfile.frozenAt,
    profileName: submittedProfile.profileName ?? submittedProfile.name ?? null,
    requiredIfClaimedRules: submittedProfile.requiredIfClaimedRules ?? submittedProfile.required_if_claimed_rules ?? [],
    notRunRationalePolicy: submittedProfile.notRunRationalePolicy ?? submittedProfile.not_run_deferred_rationale_policy ?? null,
    approvedBy: submittedProfile.approvedBy ?? submittedProfile.approved_by ?? null,
    timestamp: submittedProfile.timestamp ?? submittedProfile.createdAt ?? submittedProfile.created_at ?? null,
    profileSource: "submitted_workflow_gate_profile",
    submittedProfileId: submittedProfile.id ?? null,
    sourceCriticalCore: sourceCriticalCore.rows,
    benchmarkQualitySafeguards: benchmarkQualitySafeguards.rows,
    claimGatedDiagnostics: claimGatedDiagnostics.rows,
    profileContractChecks,
    profileContractViolations,
  };
  return {
    ...profile,
    profileCoverage: gateProfileCoverageSummary(profile, {
      sourceCriticalCore,
      benchmarkQualitySafeguards,
      claimGatedDiagnostics,
    }, profileContractViolations),
  };
}

function submittedReleaseGateProfileContractChecks(submittedProfile) {
  const requiredFieldChecks = REQUIRED_RELEASE_GATE_PROFILE_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: submittedProfile?.[field] ?? null,
    status: hasRequiredValue(submittedProfile?.[field]) ? "pass" : "missing_required_field",
  }));
  const requiredIfClaimedRules = normalizeStringArray(submittedProfile?.requiredIfClaimedRules ?? submittedProfile?.required_if_claimed_rules);
  const requiredIfClaimedChecks = REQUIRED_RELEASE_GATE_REQUIRED_IF_CLAIMED_RULES.map((rule) => ({
    field: "requiredIfClaimedRules",
    expected: rule,
    observed: requiredIfClaimedRules,
    status: requiredIfClaimedRules.includes(rule) ? "pass" : "missing_required_rule",
  }));
  const normalizedNotRunPolicy = String(submittedProfile?.notRunRationalePolicy ?? submittedProfile?.not_run_deferred_rationale_policy ?? "").toLowerCase();
  const notRunPolicyCheck = {
    field: "notRunRationalePolicy",
    expected: "mentions deferred/not-run/suppressed claim policy",
    observed: submittedProfile?.notRunRationalePolicy ?? submittedProfile?.not_run_deferred_rationale_policy ?? null,
    status: RELEASE_GATE_NOT_RUN_POLICY_FRAGMENTS.some((fragment) => normalizedNotRunPolicy.includes(fragment))
      ? "pass"
      : "missing_claim_deferred_not_run_policy",
  };
  return [...requiredFieldChecks, ...requiredIfClaimedChecks, notRunPolicyCheck];
}

function mergeSubmittedGateGroup(baseRows, submittedProfile, objectKey, listKey) {
  const objectRows = Array.isArray(submittedProfile?.[objectKey]) && submittedProfile[objectKey].every((row) => row && typeof row === "object")
    ? submittedProfile[objectKey]
    : [];
  const declaredIds = new Set([
    ...gateIdsFromValue(submittedProfile?.[objectKey]),
    ...gateIdsFromValue(submittedProfile?.[listKey]),
  ]);
  const submittedRowsById = new Map(objectRows.map((row) => [normalizeGateId(row.id), row]));
  const rows = baseRows.map((row) => {
    const normalizedId = normalizeGateId(row.id);
    const submittedRow = submittedRowsById.get(normalizedId);
    return {
      ...row,
      ...(submittedRow ?? {}),
      id: row.id,
      submittedDeclarationStatus: declaredIds.size
        ? declaredIds.has(normalizedId)
          ? "declared_in_submitted_profile"
          : "missing_from_submitted_profile"
        : "not_declared_in_submitted_profile",
    };
  });
  const baseIds = new Set(baseRows.map((row) => normalizeGateId(row.id)));
  const extraRows = objectRows
    .filter((row) => !baseIds.has(normalizeGateId(row.id)))
    .map((row) => ({
      ...row,
      id: normalizeGateId(row.id),
      submittedDeclarationStatus: "extra_submitted_gate",
    }));
  const missingRequiredIds = declaredIds.size ? baseRows.map((row) => normalizeGateId(row.id)).filter((id) => !declaredIds.has(id)) : baseRows.map((row) => normalizeGateId(row.id));
  const extraDeclaredIds = [...declaredIds].filter((id) => !baseIds.has(id));
  return {
    rows: [...rows, ...extraRows],
    requiredIds: baseRows.map((row) => normalizeGateId(row.id)),
    declaredIds: [...declaredIds],
    missingRequiredIds,
    extraDeclaredIds,
  };
}

function gateIdsFromValue(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map((row) => (row && typeof row === "object" ? row.id : row))
    .map(normalizeGateId)
    .filter(Boolean);
}

function normalizeGateId(id) {
  return typeof id === "string" ? id.trim().toLowerCase().replace(/[_\s]+/g, "-") : "";
}

function gateProfileCoverageSummary(profile, groups, contractViolations = []) {
  if (!groups) {
    return {
      status: "default_gate_catalog_used_no_submitted_profile",
      missingRequiredGateCount: 0,
      contractViolationCount: 0,
      groups: {},
    };
  }
  const summaryGroups = Object.fromEntries(
    Object.entries(groups).map(([key, group]) => [
      key,
      {
        requiredIds: group.requiredIds,
        declaredIds: group.declaredIds,
        missingRequiredIds: group.missingRequiredIds,
        extraDeclaredIds: group.extraDeclaredIds,
        status: group.missingRequiredIds.length ? "submitted_profile_missing_required_gates" : "submitted_profile_covers_required_gates",
      },
    ]),
  );
  const missingRequiredGateCount = Object.values(summaryGroups).reduce((sum, group) => sum + group.missingRequiredIds.length, 0);
  return {
    submittedProfileId: profile.submittedProfileId,
    status: contractViolations.length
      ? "submitted_profile_contract_review_required"
      : missingRequiredGateCount
        ? "submitted_profile_missing_required_gates"
        : "submitted_profile_covers_required_gate_catalog",
    missingRequiredGateCount,
    contractViolationCount: contractViolations.length,
    contractViolations,
    groups: summaryGroups,
  };
}

export function evaluateReleaseGateProfile(profile) {
  const checks = [...profile.sourceCriticalCore, ...profile.benchmarkQualitySafeguards, ...profile.claimGatedDiagnostics];
  return {
    passCount: checks.filter((check) => check.status === "pass").length,
    failCount: checks.filter((check) => check.status === "fail").length,
    partialCount: checks.filter((check) => check.status === "partial").length,
    deferredCount: checks.filter((check) => check.status === "deferred").length,
    blockingFailures: checks.filter((check) => check.status === "fail" && check.tier !== "claim_gated_diagnostic"),
    profileCoverageStatus: profile.profileCoverage?.status ?? "profile_coverage_not_reported",
    missingRequiredProfileGateCount: profile.profileCoverage?.missingRequiredGateCount ?? 0,
    profileContractViolationCount: profile.profileCoverage?.contractViolationCount ?? 0,
  };
}

export function createExportManifest(kind, releaseId, positionList = positions, critiqueList = critiques, labelSnapshot) {
  const hiddenBenchmarkExcluded = kind === "public" || kind === "training";
  const includedSplits = allowedSplitsForExport(kind);
  const includedPositionIds = new Set(positionList.filter((position) => includedSplits.includes(position.split)).map((position) => position.id));
  const includedCritiques = critiqueList.filter((critique) => includedPositionIds.has(critique.positionId));
  return {
    id: `${kind}-manifest-${releaseId}`,
    kind,
    releaseId,
    createdAt: new Date().toISOString(),
    includedSplits,
    excludedSplits: hiddenBenchmarkExcluded ? ["hidden_benchmark", "internal_validation"] : [],
    rightsClearedOnly: kind === "public",
    hiddenBenchmarkExcluded,
    labelSnapshotId: labelSnapshot?.id,
    counts: {
      positions: includedPositionIds.size,
      critiques: includedCritiques.length,
      itemLabels: labelSnapshot ? Object.keys(labelSnapshot.itemLabels).length : 0,
    },
    notes: [
      "Source and admin tags remain excluded from blind rater views.",
      "Blind initial ratings, revisions, checks, and adjudication labels are counted separately.",
      hiddenBenchmarkExcluded ? "Hidden benchmark and protected validation splits are excluded." : "Restricted export requires exposure logging.",
    ],
  };
}

export function applySubmittedItemTextVersions(positionList = positions, critiqueList = critiques, submittedItemTextVersions = []) {
  const normalized = submittedItemTextVersions.map(normalizeSubmittedItemTextVersion).filter(Boolean);
  const versionsByKey = normalized.reduce((acc, item) => {
    const key = `${item.itemType}:${item.itemId}`;
    acc[key] ??= [];
    acc[key].push(item.textVersion);
    return acc;
  }, {});
  const attach = (item, itemType) => {
    const submittedVersions = versionsByKey[`${itemType}:${item.id}`] ?? [];
    if (!submittedVersions.length) return item;
    const submittedIds = new Set(submittedVersions.map((version) => version.id));
    return {
      ...item,
      textVersions: [...(item.textVersions ?? []).filter((version) => !submittedIds.has(version.id)), ...submittedVersions],
    };
  };
  return {
    positionList: positionList.map((position) => attach(position, "position")),
    critiqueList: critiqueList.map((critique) => attach(critique, "critique")),
    submittedItemTextVersionIds: normalized.map((item) => item.textVersion.id),
  };
}

function normalizeSubmittedItemTextVersion(record) {
  const itemType = record?.itemType ?? record?.item_type;
  const itemId = record?.itemId ?? record?.item_id;
  const id = record?.id ?? record?.itemTextVersionId ?? record?.item_text_version_id;
  if (!id || !itemType || !itemId) return null;
  return {
    itemType,
    itemId,
    textVersion: {
      id,
      text: record.canonicalText ?? record.text ?? "",
      canonicalHash: record.canonicalTextHash ?? record.canonicalHash ?? `sha256:${id}:canonical`,
      renderedHash:
        record.raterVisibleRenderedTextHash ??
        record.raterVisibleRenderedHash ??
        record.renderedHash ??
        record.modelVisibleRenderedTextHash ??
        `sha256:${id}:rendered`,
      modelVisibleRenderedHash: record.modelVisibleRenderedTextHash ?? null,
      normalizationStatus: record.normalizationStatus ?? record.textVersionStatus ?? "submitted_workflow_text_version",
      source: "submitted_workflow_item_text_version",
      createdAt: record.createdAt ?? record.timestamp ?? now,
    },
  };
}

export function buildEffectiveRatingContextSnapshots(submittedRatingContextSnapshots = [], baseContextSnapshots = ratingContextSnapshots) {
  const normalized = submittedRatingContextSnapshots.map(normalizeSubmittedRatingContextSnapshot).filter(Boolean);
  const submittedIds = new Set(normalized.map((snapshot) => snapshot.id));
  return [...baseContextSnapshots.filter((snapshot) => !submittedIds.has(snapshot.id)), ...normalized];
}

function normalizeSubmittedRatingContextSnapshot(record) {
  const id = record?.id ?? record?.ratingContextSnapshotId ?? record?.rating_context_snapshot_id;
  const positionId = record?.positionId ?? record?.position_id;
  const targetCritiqueId = record?.targetCritiqueId ?? record?.critiqueId ?? record?.target_critique_id;
  if (!id || !positionId || !targetCritiqueId) return null;
  const visibleCritiqueIds = uniqueStrings(record.visibleCritiqueIds ?? record.siblingCritiqueIdsShown ?? [targetCritiqueId]);
  const orderIndexByCritiqueId =
    record.orderIndexByCritiqueId ?? Object.fromEntries(visibleCritiqueIds.map((critiqueId, index) => [critiqueId, index]));
  const targetOrderIndex = orderIndexByCritiqueId[targetCritiqueId];
  const priorSiblingCritiqueIds =
    record.priorSiblingCritiqueIds ??
    (Number.isInteger(targetOrderIndex)
      ? visibleCritiqueIds.filter((critiqueId) => critiqueId !== targetCritiqueId && orderIndexByCritiqueId[critiqueId] < targetOrderIndex)
      : []);
  const policy = record.policy ?? record.contextPolicy ?? "submitted_context_policy";
  return {
    id,
    positionId,
    targetCritiqueId,
    policy,
    visibleCritiqueIds,
    priorSiblingCritiqueIds,
    laterSiblingCritiqueIdsAbsentAtSubmission: record.laterSiblingCritiqueIdsAbsentAtSubmission ?? record.absentSiblingCritiqueIds ?? [],
    siblingItemTextVersionIds: record.siblingItemTextVersionIds ?? [],
    orderIndexByCritiqueId,
    orderPolicy: record.orderPolicy ?? (visibleCritiqueIds.length > 1 ? "submitted_sibling_order" : "single_target_no_sibling_context"),
    siblingExposurePattern: record.siblingExposurePattern ?? (visibleCritiqueIds.length > 1 ? "submitted_sibling_context" : "none"),
    humanModelParityStatus:
      record.humanModelParityStatus ??
      (visibleCritiqueIds.length > 1 ? "submitted_context_sensitive_model_prompt_matching_required" : "matchable_target_only"),
    snapshotSource: "submitted_workflow_rating_context_snapshot",
    frozenAt: record.frozenAt ?? record.createdAt ?? record.timestamp ?? now,
  };
}

export function buildTrainingExport(
  releaseId,
  labelSnapshot,
  positionList = positions,
  critiqueList = critiques,
  ratings = seedRatings,
  contextSnapshots = ratingContextSnapshots,
  options = {},
) {
  const includedSplits = options.includedSplits ?? ["public_train"];
  const excludedSplits = options.excludedSplits ?? ["public_dev", "internal_validation", "hidden_benchmark", "stress_test"];
  const includedPositions = positionList.filter((position) => includedSplits.includes(position.split));
  const excludedPositions = positionList.filter((position) => excludedSplits.includes(position.split));
  const includedPositionIds = new Set(includedPositions.map((position) => position.id));
  const includedCritiques = critiqueList.filter((critique) => includedPositionIds.has(critique.positionId));
  const includedCritiqueIds = new Set(includedCritiques.map((critique) => critique.id));
  const includedRatings = ratings.filter((rating) => includedPositionIds.has(rating.positionId) && includedCritiqueIds.has(rating.critiqueId));
  const pointwiseExamples = applyPositionBalancedPointwiseWeights(includedCritiques
    .map((critique) => buildPointwiseTrainingExample(critique, positionList, labelSnapshot, includedRatings, contextSnapshots))
    .filter(Boolean));
  const positionToOveralls = Object.fromEntries(
    includedPositions.map((position) => [
      position.id,
      Object.fromEntries(
        includedCritiques
          .filter((critique) => critique.positionId === position.id)
          .map((critique) => [critique.id, labelSnapshot.itemLabels[makeItemId(position.id, critique.id)]?.weightedMeanScores.overall])
          .filter(([, score]) => isValidScore(score)),
      ),
    ]),
  );
  const pairwiseSnapshotEvidence = buildEffectiveTrainingPairwiseComparisonSnapshot(
    releaseId,
    labelSnapshot,
    positionToOveralls,
    includedPositionIds,
    options.pairwiseComparisonSnapshots ?? [],
  );
  const pairwiseComparisonSnapshot = pairwiseSnapshotEvidence.snapshot;
  const labelByItemId = labelSnapshot.itemLabels;
  const pairwisePreferenceExamples = applyPositionBalancedPairwiseWeights(pairwiseComparisonSnapshot.nonTiedEdges.map((edge) => {
    const itemA = labelByItemId[makeItemId(edge.positionId, edge.critiqueA)];
    const itemB = labelByItemId[makeItemId(edge.positionId, edge.critiqueB)];
    const overallA = itemA.weightedMeanScores.overall;
    const overallB = itemB.weightedMeanScores.overall;
    const preferred = overallA > overallB ? edge.critiqueA : edge.critiqueB;
    const pairwiseMargin = round(Math.abs(overallA - overallB));
    return {
      id: `pref-${edge.positionId}-${edge.critiqueA}-${edge.critiqueB}`,
      positionId: edge.positionId,
      critiqueA: edge.critiqueA,
      critiqueB: edge.critiqueB,
      pairwiseComparisonSnapshotId: pairwiseComparisonSnapshot.id,
      preferredCritiqueId: preferred,
      preferenceWeight: pairwiseMargin,
      targetLabelVersion: labelSnapshot.targetLabelVersion,
      labelMetadataByCritique: {
        [edge.critiqueA]: trainingPreferenceLabelMetadata(itemA),
        [edge.critiqueB]: trainingPreferenceLabelMetadata(itemB),
      },
      pairwiseMargin,
      marginBin: edge.marginBin,
      lowMarginFlag: pairwiseMargin < (options.lowMarginThreshold ?? 0.2),
      labelUncertaintyClass:
        itemA.uncertaintyFlag || itemB.uncertaintyFlag
          ? "review_before_training"
          : pairwiseMargin < (options.lowMarginThreshold ?? 0.2)
            ? "low_margin_downweight"
            : "standard_weighted_preference",
    };
  }));
  const scalarRewardTargets = pointwiseExamples.map((example) => ({
    itemId: example.itemId,
    positionId: example.positionId,
    critiqueId: example.critiqueId,
    overallTarget: example.scores.overall,
    centXStrTarget: example.centXStrWeightedMean,
    deadWeightBadnessTarget: example.scores.dead_weight,
    singleIssueDiagnosticTarget: example.scores.single_issue,
    positionBalancedWeight: example.positionBalancedWeight,
    normalizedPositionBalancedWeight: example.normalizedPositionBalancedWeight,
    rewardPolicy: "overall_and_cent_x_strength_separate_dead_weight_badness_not_personal_agreement",
  }));
  const positionBalancedWeighting = buildTrainingExportPositionBalancedWeighting(pointwiseExamples, pairwisePreferenceExamples);
  const includedClusterIds = new Set(includedPositions.map((position) => position.clusterId));
  const protectedClusterIds = new Set(excludedPositions.map((position) => position.clusterId));
  const clusterOverlaps = [...includedClusterIds].filter((clusterId) => protectedClusterIds.has(clusterId));
  return {
    id: `training-export-${releaseId}`,
    releaseId,
    createdAt: new Date().toISOString(),
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    rubricVersion: labelSnapshot.rubricVersion,
    exportKind: "model_improvement_training_export",
    promptTrackExposure: options.promptTrackExposure ?? "project_full_rubric_training",
    optimizedSurrogateObjective: {
      pairwise: options.pairwiseSurrogate ?? "bradley_terry_logistic_margin_weighted",
      pointwise: options.pointwiseSurrogate ?? "dimensionwise_absolute_error_or_regression",
      scalarReward: "configured_downstream_from_overall_and_cent_x_strength_separately",
      tieHandling: "human_ties_excluded_from_pairwise_preferences",
      lowMarginTreatment: "retain_continuous_weight_and_flag_below_0_20",
      calibrationTargetDistribution: "none_in_export_raw_labels_only",
      lmcaEvaluationMetricsSeparate: true,
    },
    protectedSplitPolicy: {
      includedSplits,
      excludedSplits,
      publicDevPolicy: "development_or_evaluation_by_default_not_training",
      hiddenBenchmarkExcluded: !pointwiseExamples.some((example) => example.split === "hidden_benchmark"),
      internalValidationExcluded: !pointwiseExamples.some((example) => example.split === "internal_validation"),
      positionClusterIsolationStatus: clusterOverlaps.length ? "blocked" : "pass",
      overlappingProtectedClusterIds: clusterOverlaps,
    },
    counts: {
      pointwiseExamples: pointwiseExamples.length,
      pairwisePreferenceExamples: pairwisePreferenceExamples.length,
      scalarRewardTargets: scalarRewardTargets.length,
      includedRatings: includedRatings.length,
      includedPositions: includedPositions.length,
      excludedProtectedPositions: excludedPositions.length,
    },
    positionBalancedWeighting,
    ratingContextSnapshots: contextSnapshots.filter((snapshot) => includedPositionIds.has(snapshot.positionId)),
    pairwiseComparisonSnapshot,
    pairwiseComparisonSnapshotSource: pairwiseSnapshotEvidence.source,
    submittedPairwiseComparisonSnapshotId: pairwiseSnapshotEvidence.submittedPairwiseComparisonSnapshotId,
    pairwiseComparisonSnapshotStatus: pairwiseSnapshotEvidence.status,
    ignoredPairwiseComparisonSnapshotIds: pairwiseSnapshotEvidence.ignoredPairwiseComparisonSnapshotIds,
    pairwiseMarginDistribution: pairwiseMarginDistribution(pairwiseComparisonSnapshot),
    pointwiseExamples,
    pairwisePreferenceExamples,
    scalarRewardTargets,
    notes: [
      "Training exports use training-approved splits only by default.",
      "Hidden benchmark and protected validation splits are excluded from model-improvement artifacts.",
      "LMCA evaluation metrics remain frozen report metrics, not optimized training losses.",
      "Label uncertainty, rater coverage, spread, and context-snapshot provenance are preserved for downstream exclusion or downweighting.",
    ],
  };
}

function trainingPreferenceLabelMetadata(label) {
  const lowClarityBranch = Number.isFinite(label?.weightedMeanScores?.clarity) && label.weightedMeanScores.clarity < 0.5;
  return {
    labelStatus: label?.finalLabelStatus ?? null,
    raterCount: label?.raterCount ?? null,
    expertCount: label?.expertCount ?? null,
    spreadPreDiscussion: Number.isFinite(label?.spreadPreDiscussion) ? round(label.spreadPreDiscussion) : null,
    spreadPostDiscussion: Number.isFinite(label?.spreadPostDiscussion) ? round(label.spreadPostDiscussion) : null,
    unresolvedDisagreementClass: label?.uncertaintyFlag ? "review_before_training" : "none_recorded",
    lowClarityBranch,
    lowClarityPolicy: lowClarityBranch ? "non_clarity_subscores_provisional_or_downweighted" : "full_rubric_fields_available",
    largestSingleRaterContributionShare: label?.largestSingleRaterContributionShare ?? null,
  };
}

function applyPositionBalancedPointwiseWeights(examples) {
  const rowsByPosition = countBy(examples, "positionId");
  const scoredPositionCount = Object.keys(rowsByPosition).length;
  return examples.map((example) => {
    const positionExampleCount = rowsByPosition[example.positionId] ?? 1;
    const positionBalancedWeight = 1 / positionExampleCount;
    return {
      ...example,
      positionExampleCount,
      positionBalancedWeight: round(positionBalancedWeight),
      normalizedPositionBalancedWeight: scoredPositionCount ? round(positionBalancedWeight / scoredPositionCount) : 0,
      positionBalancedWeightingPolicy: "average_within_position_before_cross_position_training_weighting",
    };
  });
}

function applyPositionBalancedPairwiseWeights(examples) {
  const rowsByPosition = countBy(examples, "positionId");
  const scoredPairwisePositionCount = Object.keys(rowsByPosition).length;
  return examples.map((example) => {
    const positionPairCount = rowsByPosition[example.positionId] ?? 1;
    const positionBalancedPairWeight = 1 / positionPairCount;
    return {
      ...example,
      positionPairCount,
      positionBalancedPairWeight: round(positionBalancedPairWeight),
      positionBalancedPreferenceWeight: round(example.preferenceWeight * positionBalancedPairWeight),
      normalizedPositionBalancedPreferenceWeight: scoredPairwisePositionCount
        ? round((example.preferenceWeight * positionBalancedPairWeight) / scoredPairwisePositionCount)
        : 0,
      positionBalancedWeightingPolicy: "average_pairwise_edges_within_position_before_cross_position_training_weighting",
    };
  });
}

function buildTrainingExportPositionBalancedWeighting(pointwiseExamples, pairwisePreferenceExamples) {
  const pointwiseRowsByPosition = countBy(pointwiseExamples, "positionId");
  const pairwiseRowsByPosition = countBy(pairwisePreferenceExamples, "positionId");
  const pointwiseWeightSumByPosition = weightSumByPosition(pointwiseExamples, "positionBalancedWeight");
  const pairwiseWeightSumByPosition = weightSumByPosition(pairwisePreferenceExamples, "positionBalancedPairWeight");
  const pointwiseSumsBalanced = Object.values(pointwiseWeightSumByPosition).every((value) => Math.abs(value - 1) <= 0.001);
  const pairwiseSumsBalanced = Object.values(pairwiseWeightSumByPosition).every((value) => Math.abs(value - 1) <= 0.001);
  return {
    policy: "average_or_sample_within_position_before_cross_position_training_weighting",
    pointwiseRowsByPosition,
    pairwiseRowsByPosition,
    pointwiseWeightSumByPosition,
    pairwiseWeightSumByPosition,
    normalizedPointwiseWeightSum: round(pointwiseExamples.reduce((sum, example) => sum + example.normalizedPositionBalancedWeight, 0)),
    normalizedPairwisePreferenceWeightSum: round(
      pairwisePreferenceExamples.reduce((sum, example) => sum + example.normalizedPositionBalancedPreferenceWeight, 0),
    ),
    status:
      pointwiseSumsBalanced && (pairwisePreferenceExamples.length === 0 || pairwiseSumsBalanced)
        ? "position_balanced_training_weights_complete"
        : "position_balanced_training_weights_review_required",
  };
}

function weightSumByPosition(rows, weightField) {
  return rows.reduce((acc, row) => {
    acc[row.positionId] = round((acc[row.positionId] ?? 0) + (Number.isFinite(row[weightField]) ? row[weightField] : 0));
    return acc;
  }, {});
}

function buildEffectiveTrainingPairwiseComparisonSnapshot(
  releaseId,
  labelSnapshot,
  positionToOveralls,
  includedPositionIds,
  submittedPairwiseComparisonSnapshots = [],
) {
  const normalizedSubmitted = submittedPairwiseComparisonSnapshots
    .map((snapshot) => normalizeSubmittedPairwiseComparisonSnapshot(snapshot, labelSnapshot, positionToOveralls))
    .filter(Boolean);
  const submitted = [...normalizedSubmitted]
    .reverse()
    .find((snapshot) => pairwiseSnapshotMatchesTrainingExport(snapshot, labelSnapshot, includedPositionIds, positionToOveralls));
  if (submitted) {
    return {
      snapshot: submitted,
      source: "submitted_workflow_pairwise_comparison_snapshot",
      status: "submitted_pairwise_snapshot_applied",
      submittedPairwiseComparisonSnapshotId: submitted.id,
      ignoredPairwiseComparisonSnapshotIds: normalizedSubmitted.filter((snapshot) => snapshot.id !== submitted.id).map((snapshot) => snapshot.id),
    };
  }
  return {
    snapshot: buildPairwiseComparisonSnapshot(
      `training-pairwise-${releaseId}`,
      labelSnapshot.id,
      labelSnapshot.targetLabelVersion,
      positionToOveralls,
      pairwiseSnapshotOptionsFromLabelSnapshot(labelSnapshot, positionToOveralls),
    ),
    source: "computed_training_pairwise_snapshot",
    status: normalizedSubmitted.length ? "submitted_pairwise_snapshot_not_applicable_computed_used" : "computed_pairwise_snapshot_used",
    submittedPairwiseComparisonSnapshotId: null,
    ignoredPairwiseComparisonSnapshotIds: normalizedSubmitted.map((snapshot) => snapshot.id),
  };
}

function pairwiseSnapshotOptionsFromLabelSnapshot(labelSnapshot, positionToOveralls) {
  const positionTextVersionIdsByPosition = {};
  const critiqueTextVersionIdsByPosition = {};
  const itemTextVersionIdsByItem = {};
  Object.entries(positionToOveralls).forEach(([positionId, critiqueScores]) => {
    Object.keys(critiqueScores).forEach((critiqueId) => {
      const itemId = makeItemId(positionId, critiqueId);
      const label = labelSnapshot.itemLabels?.[itemId] ?? {};
      const positionTextVersionIds = normalizeStringArray(label.positionTextVersionIds) ?? [];
      const critiqueTextVersionIds = normalizeStringArray(label.critiqueTextVersionIds) ?? [];
      if (positionTextVersionIds.length) {
        positionTextVersionIdsByPosition[positionId] = uniqueStrings([
          ...(positionTextVersionIdsByPosition[positionId] ?? []),
          ...positionTextVersionIds,
        ]);
      }
      critiqueTextVersionIdsByPosition[positionId] ??= {};
      if (critiqueTextVersionIds.length) {
        critiqueTextVersionIdsByPosition[positionId][critiqueId] = critiqueTextVersionIds;
      }
      itemTextVersionIdsByItem[itemId] = uniqueStrings([...positionTextVersionIds, ...critiqueTextVersionIds]);
    });
  });
  return {
    tieTolerance: 0,
    targetScoreField: "overall",
    humanTargetScoreSource: `${labelSnapshot.id}:${labelSnapshot.targetLabelVersion}:weightedMeanScores.overall`,
    positionTextVersionIdsByPosition,
    critiqueTextVersionIdsByPosition,
    itemTextVersionIdsByItem,
  };
}

function normalizeSubmittedPairwiseComparisonSnapshot(snapshot, labelSnapshot, positionToOveralls) {
  const id = snapshot?.id ?? snapshot?.pairwiseComparisonSnapshotId ?? snapshot?.pairwise_comparison_snapshot_id;
  if (!id) return null;
  const positionIds = snapshot.positionIds ?? Object.keys(snapshot.critiqueIdsByPosition ?? positionToOveralls);
  const critiqueIdsByPosition =
    snapshot.critiqueIdsByPosition ??
    Object.fromEntries(positionIds.map((positionId) => [positionId, Object.keys(positionToOveralls[positionId] ?? {})]));
  const edges = normalizeSubmittedPairwiseEdges(snapshot, positionIds, positionToOveralls);
  return {
    id,
    labelSnapshotId: snapshot.labelSnapshotId ?? labelSnapshot.id,
    targetLabelVersion: snapshot.targetLabelVersion ?? labelSnapshot.targetLabelVersion,
    targetScoreField: snapshot.targetScoreField ?? "overall",
    humanTargetScoreSource: snapshot.humanTargetScoreSource ?? `${snapshot.labelSnapshotId ?? labelSnapshot.id}:${snapshot.targetLabelVersion ?? labelSnapshot.targetLabelVersion}:weightedMeanScores.overall`,
    tieTolerance: numberOrDefault(snapshot.tieTolerance ?? snapshot.humanTieTolerance, 0),
    humanTieTolerance: numberOrDefault(snapshot.humanTieTolerance ?? snapshot.tieTolerance, 0),
    modelTieTolerance: numberOrDefault(snapshot.modelTieTolerance ?? snapshot.tieTolerance, 0),
    humanTiePolicy: normalizeHumanTiePolicy(snapshot.humanTiePolicy ?? snapshot.tiePolicy),
    modelTiePolicy: normalizeModelTiePolicy(snapshot.modelTiePolicy ?? snapshot.tiePolicy),
    scoreRoundingPolicy: snapshot.scoreRoundingPolicy ?? "submitted_pairwise_snapshot_policy",
    scoreQuantizationPolicy: snapshot.scoreQuantizationPolicy ?? "unit_interval_decimal_scores_no_bucket_quantization",
    positionIds,
    critiqueIdsByPosition,
    positionTextVersionIdsByPosition: snapshot.positionTextVersionIdsByPosition ?? {},
    critiqueTextVersionIdsByPosition: snapshot.critiqueTextVersionIdsByPosition ?? {},
    itemTextVersionIds: snapshot.itemTextVersionIds ?? [],
    itemTextVersionIdsByItem: snapshot.itemTextVersionIdsByItem ?? {},
    nonTiedEdges: edges,
    excludedHumanTieEdges: snapshot.excludedHumanTieEdges ?? snapshot.excludedHumanTieEdgeCount ?? 0,
    excludedHumanTieEdgeRows: snapshot.excludedHumanTieEdgeRows ?? snapshot.exclusions?.humanTieEdges ?? [],
    excludedNoPairPositions: snapshot.excludedNoPairPositions ?? [],
    exclusions: snapshot.exclusions ?? {
      humanTieEdgeCount: snapshot.excludedHumanTieEdges ?? snapshot.excludedHumanTieEdgeCount ?? 0,
      humanTieEdges: snapshot.excludedHumanTieEdgeRows ?? [],
      noPairPositionIds: snapshot.excludedNoPairPositions ?? [],
      missingTextVersionItemIds: [],
    },
    frozenAt: snapshot.frozenAt ?? snapshot.timestamp ?? now,
    snapshotSource: "submitted_workflow_pairwise_comparison_snapshot",
  };
}

function normalizeSubmittedPairwiseEdges(snapshot, positionIds, positionToOveralls) {
  const rawEdges = snapshot.nonTiedEdges ?? snapshot.nonTiedComparisonEdges ?? [];
  return rawEdges
    .map((edge) => {
      const positionId = edge.positionId ?? (Array.isArray(edge) && edge.length > 2 ? edge[0] : positionIds.length === 1 ? positionIds[0] : null);
      const critiqueA = edge.critiqueA ?? edge.leftCritiqueId ?? (Array.isArray(edge) ? edge.at(-2) : null);
      const critiqueB = edge.critiqueB ?? edge.rightCritiqueId ?? (Array.isArray(edge) ? edge.at(-1) : null);
      if (!positionId || !critiqueA || !critiqueB) return null;
      const computedMargin = Math.abs((positionToOveralls[positionId]?.[critiqueA] ?? 0) - (positionToOveralls[positionId]?.[critiqueB] ?? 0));
      const humanMargin = numberOrDefault(edge.humanMargin ?? edge.margin, computedMargin);
      return {
        positionId,
        critiqueA,
        critiqueB,
        humanMargin,
        marginBin: edge.marginBin ?? (humanMargin < 0.15 ? "low" : humanMargin < 0.35 ? "medium" : "high"),
      };
    })
    .filter(Boolean);
}

function pairwiseSnapshotMatchesTrainingExport(snapshot, labelSnapshot, includedPositionIds, positionToOveralls) {
  if (snapshot.labelSnapshotId !== labelSnapshot.id) return false;
  if (snapshot.targetLabelVersion !== labelSnapshot.targetLabelVersion) return false;
  if (!snapshot.positionIds.every((positionId) => includedPositionIds.has(positionId))) return false;
  return snapshot.nonTiedEdges.every(
    (edge) =>
      Number.isFinite(Number(positionToOveralls[edge.positionId]?.[edge.critiqueA])) &&
      Number.isFinite(Number(positionToOveralls[edge.positionId]?.[edge.critiqueB])),
  );
}

export function buildLabelChannelSeparationReport(
  releaseId,
  labelSnapshot,
  trainingExport,
  certification = buildCertificationAudit(),
  rubricQaCoverage = buildRubricQaCoverageReport(releaseId),
) {
  const forbiddenChannels = ["personal_agreement", "preference_persuasion", "persuasion", "user_agreement"];
  const itemLabelRows = Object.entries(labelSnapshot.itemLabels ?? {}).map(([itemId, label]) => {
    const scoreFields = Object.keys(label.weightedMeanScores ?? {}).sort();
    const nonLmcaScoreFields = scoreFields.filter((field) => !RUBRIC_DIMENSIONS.includes(field));
    return {
      itemId,
      labelStatus: label.finalLabelStatus,
      scoreFields,
      labelChannel: "lmca_argumentative_quality",
      nonLmcaScoreFields,
      channelStatus: nonLmcaScoreFields.length ? "non_lmca_score_field_present" : "pass",
    };
  });
  const trainingRows = [
    ...(trainingExport.pointwiseExamples ?? []).map((example) => ({
      rowId: example.itemId,
      surface: "training_pointwise",
      labelChannel: "lmca_argumentative_quality",
      policy: "uses_lmca_score_vector",
      forbiddenChannelPresent: forbiddenChannels.some((channel) => JSON.stringify(example).includes(channel)),
    })),
    ...(trainingExport.pairwisePreferenceExamples ?? []).map((example) => ({
      rowId: example.id,
      surface: "training_pairwise_preference",
      labelChannel: "lmca_argumentative_quality_preference_from_overall_gap",
      policy: "preference_is_pairwise_critique_quality_order_not_personal_preference",
      forbiddenChannelPresent: forbiddenChannels.some((channel) => JSON.stringify(example).includes(channel)),
    })),
    ...(trainingExport.scalarRewardTargets ?? []).map((target) => ({
      rowId: target.itemId,
      surface: "training_scalar_reward",
      labelChannel: "lmca_argumentative_quality_reward_target",
      policy: target.rewardPolicy,
      forbiddenChannelPresent:
        !String(target.rewardPolicy).includes("not_personal_agreement") ||
        forbiddenChannels.some((channel) => channel !== "personal_agreement" && String(target.rewardPolicy).includes(channel)),
    })),
  ];
  const surfaceRows = [
    {
      surface: "rating_ui",
      labelChannel: "lmca_argumentative_quality",
      evidence: "RUBRIC_DIMENSIONS defines the rater-visible score fields.",
      status: RUBRIC_DIMENSIONS.length === 7 ? "pass" : "review_required",
    },
    {
      surface: "label_snapshot",
      labelChannel: "lmca_argumentative_quality",
      evidence: `${itemLabelRows.length} item labels expose only LMCA score dimensions.`,
      status: itemLabelRows.some((row) => row.nonLmcaScoreFields.length) ? "review_required" : "pass",
    },
    {
      surface: "training_export",
      labelChannel: "lmca_argumentative_quality",
      evidence: `${trainingRows.length} training rows audited for forbidden agreement/persuasion channels.`,
      status: trainingRows.some((row) => row.forbiddenChannelPresent) ? "review_required" : "pass",
    },
    {
      surface: "certification",
      labelChannel: "lmca_argumentative_quality_calibration",
      evidence: `${certification.packs.length} packs and ${certification.loadedGoldLibraryItems} gold items remain training exposure.`,
      status: certification.modelJudgeGoldViolations.length || !certification.trainingExposureOnly ? "review_required" : "pass",
    },
    {
      surface: "rubric_qa_exports",
      labelChannel: "lmca_argumentative_quality_public_qa",
      evidence: `${rubricQaCoverage.counts.fixtureCount} QA fixtures are public training/QA only.`,
      status: rubricQaCoverage.counts.protectedExposureViolationCount ? "review_required" : "pass",
    },
  ];
  const violationRows = [
    ...itemLabelRows
      .filter((row) => row.nonLmcaScoreFields.length > 0)
      .map((row) => ({ surface: "label_snapshot", rowId: row.itemId, reason: `non-LMCA score fields: ${row.nonLmcaScoreFields.join(", ")}` })),
    ...trainingRows
      .filter((row) => row.forbiddenChannelPresent)
      .map((row) => ({ surface: row.surface, rowId: row.rowId, reason: `forbidden channel in policy: ${row.policy}` })),
    ...surfaceRows
      .filter((row) => row.status !== "pass")
      .map((row) => ({ surface: row.surface, rowId: row.surface, reason: row.evidence })),
  ];
  return {
    id: `label-channel-separation-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      allowedChannel: "lmca_argumentative_quality",
      forbiddenChannels,
      separationRule:
        "LMCA labels score critique argumentative quality only; personal agreement, persuasion, user preference, and sycophancy/orthodoxy cues remain separate diagnostics or prohibited training channels.",
      trainingRule:
        "Pairwise preferences and scalar rewards derive from LMCA overall and rubric dimensions, not from personal-agreement or persuasion labels.",
    },
    counts: {
      auditedSurfaces: surfaceRows.length,
      itemLabelRows: itemLabelRows.length,
      trainingRows: trainingRows.length,
      violationCount: violationRows.length,
      forbiddenTrainingChannelRows: trainingRows.filter((row) => row.forbiddenChannelPresent).length,
      nonLmcaSnapshotFieldRows: itemLabelRows.filter((row) => row.nonLmcaScoreFields.length > 0).length,
    },
    rubricDimensions: RUBRIC_DIMENSIONS,
    surfaceRows,
    itemLabelRows,
    trainingRows,
    violationRows,
    releaseUseStatus: violationRows.length ? "label_channel_separation_review_required" : "lmca_argumentative_quality_channel_separated",
  };
}

export function summarizeAdjudication(memos = adjudicationMemos) {
  return memos.reduce((acc, memo) => {
    (memo.disagreementTaxonomy ?? []).forEach((taxonomy) => {
      acc[taxonomy] = (acc[taxonomy] ?? 0) + 1;
    });
    return acc;
  }, {});
}

export function buildAdjudicationMemoAuditReport(
  releaseId,
  labelSnapshot,
  ratings = seedRatings,
  positionList = positions,
  critiqueList = critiques,
  memos = adjudicationMemos,
) {
  const positionById = new Map(positionList.map((position) => [position.id, position]));
  const critiqueByItemId = new Map(critiqueList.map((critique) => [makeItemId(critique.positionId, critique.id), critique]));
  const memoRows = memos
    .map((memo) => {
      const itemId = makeItemId(memo.positionId, memo.critiqueId);
      const position = positionById.get(memo.positionId);
      const itemRatings = ratings.filter((rating) => rating.positionId === memo.positionId && rating.critiqueId === memo.critiqueId);
      const plausibleInterpretations = memo.plausibleInterpretations ?? [];
      const critiqueRefutesInterpretations = memo.critiqueRefutesInterpretations ?? [];
      const raterRationales = itemRatings
        .filter((rating) => rating.rationale)
        .map((rating) => ({
          ratingId: rating.id,
          raterId: rating.raterId,
          kind: rating.kind,
          raterTier: rating.raterTier,
          rationale: rating.rationale,
        }));
      return {
        memoId: memo.id,
        memoSource: memo.memoSource ?? "seed_adjudication_memo",
        itemId,
        positionId: memo.positionId,
        critiqueId: memo.critiqueId,
        split: position?.split ?? "unknown",
        releaseCritical: isReleaseCriticalSplit(position?.split),
        targetLabelPresent: Boolean(labelSnapshot.itemLabels[itemId]),
        topicFamily: position?.topicFamily ?? "unknown",
        discussionThreadId: memo.discussionThreadId ?? null,
        contestedInterpretation: memo.contestedInterpretation,
        plausibleInterpretations,
        plausibleInterpretationCount: plausibleInterpretations.length,
        worstPlausibleInterpretationConsidered: memo.worstPlausibleInterpretationConsidered ?? null,
        interpretationPlausibilityNotes: memo.interpretationPlausibilityNotes ?? null,
        multiInterpretationCoverageSummary: memo.multiInterpretationCoverageSummary ?? null,
        critiqueRefutesInterpretations,
        critiqueRefutesInterpretationsRecorded: Array.isArray(memo.critiqueRefutesInterpretations),
        adversarialPlausibilityWeightingDecision: memo.adversarialPlausibilityWeightingDecision ?? null,
        adversarialInterpretationWeightingSummary: memo.adversarialInterpretationWeightingSummary ?? memo.adversarialPlausibilityWeightingDecision ?? null,
        pricedInAssessment: memo.pricedInAssessment ?? null,
        backgroundKnowledgeAssessment: memo.backgroundKnowledgeAssessment ?? memo.backgroundKnowledgeRelevance ?? null,
        bottomLineDependenceSummary: memo.bottomLineDependenceSummary ?? null,
        bottomLineDependence: Boolean(memo.bottomLineDependence),
        minorityRationales: memo.minorityRationales ?? [],
        minorityRationaleCount: (memo.minorityRationales ?? []).length,
        clearlyUnsatisfactoryImprecision: Boolean(memo.clearlyUnsatisfactoryImprecision),
        clearlyUnsatisfactoryImprecisionSummary: memo.clearlyUnsatisfactoryImprecisionSummary ?? null,
        contentFreeDeadWeightSummary: memo.contentFreeDeadWeightSummary ?? null,
        obfuscatedOrMaskedFallacyRisk: Boolean(memo.obfuscatedOrMaskedFallacyRisk),
        obfuscationSummary: memo.obfuscationSummary ?? null,
        strengthCentralityAllocationSummary: memo.strengthCentralityAllocationSummary ?? null,
        midRangeStrengthUncertaintySummary: memo.midRangeStrengthUncertaintySummary ?? null,
        correctnessWeightingSummary: memo.correctnessWeightingSummary ?? null,
        correctnessVerificationStatus: memo.correctnessVerificationStatus ?? null,
        correctnessVerificationSummary: memo.correctnessVerificationSummary ?? null,
        clarityAfterEffortSummary: memo.clarityAfterEffortSummary ?? null,
        stableJudgment: memo.stableJudgment ?? null,
        benchmarkEligibilityDecision: memo.benchmarkEligibilityDecision,
        splitDecision: memo.splitDecision,
        disagreementTaxonomy: memo.disagreementTaxonomy ?? [],
        postDiscussionResolutionStatus: memo.postDiscussionResolutionStatus ?? null,
        unresolvedDisagreementClass: memo.unresolvedDisagreementClass ?? null,
        maxFinalRaterSpread: Number.isFinite(memo.maxFinalRaterSpread) ? memo.maxFinalRaterSpread : null,
        adjudicatorIds: memo.adjudicatorIds ?? [],
        rubricVersionConsidered: memo.rubricVersionConsidered ?? null,
        timestamp: memo.timestamp ?? memo.createdAt ?? null,
        raterRationales,
        critiqueSourceType: critiqueByItemId.get(itemId)?.sourceType ?? "unknown",
        critiqueStyleBand: critiqueByItemId.get(itemId)?.styleBand ?? "unknown",
      };
    })
    .sort((left, right) => Number(right.releaseCritical) - Number(left.releaseCritical) || left.itemId.localeCompare(right.itemId));
  const incompleteAmbiguityRows = memoRows.filter(
    (row) =>
      row.releaseCritical &&
      (!row.plausibleInterpretationCount ||
        !row.worstPlausibleInterpretationConsidered ||
        !row.critiqueRefutesInterpretationsRecorded ||
        !row.adversarialPlausibilityWeightingDecision),
  );
  const bottomLineDependentRows = memoRows.filter((row) => row.bottomLineDependence);
  const imprecisionRows = memoRows.filter((row) => row.clearlyUnsatisfactoryImprecision);
  const obfuscationRows = memoRows.filter((row) => row.obfuscatedOrMaskedFallacyRisk);
  return {
    id: `adjudication-memo-audit-${releaseId}-${labelSnapshot.id}`,
    releaseId,
    labelSnapshotId: labelSnapshot.id,
    targetLabelVersion: labelSnapshot.targetLabelVersion,
    generatedAt: new Date().toISOString(),
    policy: {
      ambiguityRule:
        "Release-critical ambiguity memos must record plausible interpretations, the worst plausible interpretation considered, which interpretations the critique refutes, and an adversarial-plausibility weighting decision.",
      bottomLineRule:
        "When strength or correctness turns on disputed bottom-line premises, release validation preserves minority rationales rather than forcing consensus.",
      imprecisionRule:
        "Clearly unsatisfactory imprecision and obfuscated or masked-fallacy cases are reported separately from ordinary low-score disagreement.",
    },
    counts: {
      memoCount: memoRows.length,
      releaseCriticalMemoCount: memoRows.filter((row) => row.releaseCritical).length,
      ambiguousMemoCount: memoRows.filter((row) => row.plausibleInterpretationCount > 1 || row.contestedInterpretation).length,
      completeAmbiguityMemoCount: memoRows.filter(
        (row) =>
          row.plausibleInterpretationCount &&
          row.worstPlausibleInterpretationConsidered &&
          row.critiqueRefutesInterpretationsRecorded &&
          row.adversarialPlausibilityWeightingDecision,
      ).length,
      incompleteReleaseCriticalAmbiguityMemoCount: incompleteAmbiguityRows.length,
      bottomLineDependentItemCount: bottomLineDependentRows.length,
      minorityRationaleCount: memoRows.reduce((sum, row) => sum + row.minorityRationaleCount, 0),
      clearlyUnsatisfactoryImprecisionItemCount: imprecisionRows.length,
      obfuscatedOrMaskedFallacyItemCount: obfuscationRows.length,
    },
    taxonomyCounts: summarizeAdjudication(memos),
    memoRows,
    incompleteAmbiguityRows,
    bottomLineDependentRows,
    imprecisionRows,
    obfuscationRows,
    releaseUseStatus:
      incompleteAmbiguityRows.length > 0
        ? "adjudication_memo_fields_incomplete"
        : bottomLineDependentRows.length || imprecisionRows.length || obfuscationRows.length
          ? "adjudication_limitations_preserved"
          : "adjudication_memos_complete",
  };
}

function buildAdjudicationFinalizationEvidenceReport(releaseId, finalizations = [], memos = adjudicationMemos) {
  const memoById = new Map(memos.map((memo) => [memo.id, memo]));
  const rows = finalizations.map((finalization) => normalizeAdjudicationFinalizationEvidenceRow(finalization, memoById)).filter(Boolean);
  const reviewRows = rows.filter((row) => row.reviewReasons.length);
  return {
    id: `adjudication-finalization-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      requiredArtifact: "AdjudicationFinalization",
      releaseRule:
        "Release-critical adjudication finalizations must name the governed adjudication, matching memo, finalized status, finalizer, and timestamp before final labels can rely on them.",
      preservedOriginalsRule: "Finalization evidence confirms memo handoff only; preserved original ratings remain enforced by revision and label-snapshot evidence.",
    },
    rows,
    counts: {
      submittedFinalizationCount: rows.length,
      completeFinalizationCount: rows.length - reviewRows.length,
      reviewRequiredCount: reviewRows.length,
      matchedMemoCount: rows.filter((row) => row.memoFound).length,
      finalizedForReleaseCandidateCount: rows.filter((row) => row.finalizationStatus === "finalized_for_release_candidate").length,
    },
    byFinalizationStatus: countBy(rows, "finalizationStatus"),
    reviewRows,
    releaseUseStatus: !rows.length
      ? "no_submitted_adjudication_finalizations"
      : reviewRows.length
        ? "adjudication_finalization_evidence_review_required"
        : "submitted_adjudication_finalization_evidence_complete",
  };
}

function normalizeAdjudicationFinalizationEvidenceRow(finalization, memoById) {
  if (!finalization || typeof finalization !== "object") return null;
  const memoId = finalization.memoId ?? finalization.adjudicationMemoId ?? null;
  const memo = memoById.get(memoId);
  const adjudicatorIds = Array.isArray(memo?.adjudicatorIds) ? memo.adjudicatorIds : [];
  const finalizedBy = finalization.finalizedBy ?? finalization.adjudicatorId ?? finalization.createdBy ?? null;
  const timestamp = finalization.timestamp ?? finalization.finalizedAt ?? finalization.createdAt ?? null;
  const reviewReasons = [
    finalization.id ? null : "id",
    finalization.adjudicationId ? null : "adjudicationId",
    memoId ? null : "memoId",
    memoId && !memo ? "matching_adjudication_memo" : null,
    finalization.finalizationStatus ? null : "finalizationStatus",
    finalization.finalizationStatus && finalization.finalizationStatus !== "finalized_for_release_candidate" ? "finalizationStatus:not_finalized_for_release_candidate" : null,
    finalizedBy ? null : "finalizedBy",
    memo && adjudicatorIds.length && finalizedBy && !adjudicatorIds.includes(finalizedBy) ? "finalizedBy:not_memo_adjudicator" : null,
    timestamp ? null : "timestamp",
  ].filter(Boolean);
  return {
    id: finalization.id ?? null,
    rowSource: "submitted_workflow_adjudication_finalization",
    adjudicationId: finalization.adjudicationId ?? null,
    memoId,
    memoFound: Boolean(memo),
    discussionThreadId: finalization.discussionThreadId ?? memo?.discussionThreadId ?? null,
    itemId: memo?.itemId ?? (memo ? makeItemId(memo.positionId, memo.critiqueId) : null),
    finalizationStatus: finalization.finalizationStatus ?? null,
    finalizedBy,
    memoAdjudicatorIds: adjudicatorIds,
    finalizedByMemoAdjudicator: Boolean(memo && finalizedBy && (!adjudicatorIds.length || adjudicatorIds.includes(finalizedBy))),
    timestamp,
    reviewReasons,
    status: reviewReasons.length ? "adjudication_finalization_evidence_review_required" : "adjudication_finalization_evidence_complete",
  };
}

function buildDiscussionAdjudicationWorkflowEvidenceReport(releaseId, options = {}) {
  const threadRows = (options.discussionThreads ?? []).map(normalizeDiscussionThreadWorkflowRow).filter(Boolean);
  const discussionRows = (options.discussions ?? []).map((discussion) => normalizeDiscussionOpenWorkflowRow(discussion, threadRows)).filter(Boolean);
  const commentRows = (options.discussionComments ?? []).map(normalizeDiscussionCommentWorkflowRow).filter(Boolean);
  const revisionProposalRows = (options.discussionRevisionProposals ?? []).map(normalizeDiscussionRevisionProposalWorkflowRow).filter(Boolean);
  const postLockSessionRows = (options.postLockDiscussionSessions ?? []).map(normalizePostLockDiscussionSessionLinkRow).filter(Boolean);
  const adjudicationRows = (options.adjudications ?? []).map(normalizeAdjudicationWorkflowRow).filter(Boolean);
  const adjudicationReviewSessionRows = (options.adjudicationReviewSessions ?? []).map(normalizeAdjudicationReviewSessionLinkRow).filter(Boolean);
  const memoRows = (options.adjudicationMemos ?? []).map(normalizeAdjudicationMemoLinkRow).filter(Boolean);
  const finalizationRows = (options.adjudicationFinalizations ?? []).map(normalizeAdjudicationFinalizationLinkRow).filter(Boolean);
  const coverageRows = threadRows.map((thread) =>
    discussionAdjudicationThreadCoverageRow(thread, {
      discussionRows,
      commentRows,
      revisionProposalRows,
      postLockSessionRows,
      adjudicationRows,
      adjudicationReviewSessionRows,
      memoRows,
      finalizationRows,
    }),
  );
  const reviewSections = [
    ...discussionRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "discussion", artifactId: row.id, reason }))),
    ...threadRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "discussion_thread", artifactId: row.id, reason }))),
    ...commentRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "discussion_comment", artifactId: row.id, reason }))),
    ...revisionProposalRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "discussion_revision_proposal", artifactId: row.id, reason }))),
    ...adjudicationRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "adjudication", artifactId: row.id, reason }))),
    ...coverageRows.flatMap((row) =>
      row.reviewReasons.map((reason) => ({ artifactType: "discussion_adjudication_thread_coverage", artifactId: row.discussionThreadId, reason })),
    ),
  ];
  const submittedThreadCount = threadRows.length;
  const completeThreadCount = coverageRows.filter((row) => row.status === "discussion_adjudication_workflow_complete").length;
  const releaseUseStatus = reviewSections.length
    ? "discussion_adjudication_workflow_review_required"
    : submittedThreadCount
      ? "submitted_discussion_adjudication_workflow_complete"
      : "discussion_adjudication_workflow_not_submitted";
  return {
    id: `discussion-adjudication-workflow-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    evidenceRules: {
      postLockDiscussionRule:
        "Submitted discussion threads must link to post-lock sessions with locked initial ratings, object-level comments, revision proposals, and transcript artifacts.",
      adjudicationRule:
        "Submitted discussion threads must link to adjudication records, adjudication review sessions, memos, and finalized release-candidate finalizations before supporting release claims.",
      preservationRule: "Revision proposals must preserve original ratings append-only rather than replacing initial blind ratings.",
    },
    discussionRows,
    discussionThreadRows: threadRows,
    discussionCommentRows: commentRows,
    discussionRevisionProposalRows: revisionProposalRows,
    postLockDiscussionSessionRows: postLockSessionRows,
    adjudicationRows,
    adjudicationReviewSessionRows,
    adjudicationMemoRows: memoRows,
    adjudicationFinalizationRows: finalizationRows,
    coverageRows,
    counts: {
      submittedDiscussionCount: discussionRows.length,
      submittedDiscussionThreadCount: threadRows.length,
      submittedDiscussionCommentCount: commentRows.length,
      submittedDiscussionRevisionProposalCount: revisionProposalRows.length,
      submittedPostLockDiscussionSessionCount: postLockSessionRows.length,
      submittedAdjudicationCount: adjudicationRows.length,
      submittedAdjudicationReviewSessionCount: adjudicationReviewSessionRows.length,
      submittedAdjudicationMemoCount: memoRows.filter((row) => row.rowSource === "submitted_workflow_adjudication_memo").length,
      submittedAdjudicationFinalizationCount: finalizationRows.length,
      completeDiscussionThreadCount: completeThreadCount,
      reviewSectionCount: reviewSections.length,
    },
    reviewSections,
    releaseUseStatus,
  };
}

function normalizeDiscussionOpenWorkflowRow(discussion, threadRows = []) {
  const id = discussion?.id;
  if (!id) return null;
  const itemKeys = workflowItemKeys(discussion);
  const linkedThread = linkedDiscussionThreadForResource(discussion, threadRows);
  const disagreementTaxonomy = normalizeStringArray(discussion.disagreementTaxonomy ?? discussion.disagreementTaxonomyCodes);
  const reviewReasons = [
    itemKeys.length ? null : "itemKeys",
    disagreementTaxonomy.length ? null : "disagreementTaxonomy",
    linkedThread ? null : "linkedDiscussionThread",
  ].filter(Boolean);
  return {
    id,
    rowSource: "submitted_workflow_discussion",
    itemKeys,
    linkedDiscussionThreadId: linkedThread?.id ?? null,
    disagreementTaxonomy,
    policyActionKind: discussion.policyActionKind ?? null,
    policyDecisionId: discussion.policyDecisionId ?? null,
    policyDecisionConsumptionId: discussion.policyDecisionConsumptionId ?? null,
    reviewReasons,
    status: reviewReasons.length ? "discussion_open_review_required" : "discussion_open_complete",
  };
}

