function releaseArtifactEvidenceRow(artifactKind, submitted, checks, passStatus) {
  const reviewChecks = checks.filter((check) => check.status !== "matches" && check.status !== "not_submitted_optional");
  return {
    artifactKind,
    submittedArtifactId: submitted?.id ?? null,
    submittedAt: submitted?.createdAt ?? submitted?.timestamp ?? null,
    checks,
    reviewChecks,
    status: !submitted ? "no_submitted_artifact" : reviewChecks.length ? `${artifactKind}_review_required` : passStatus,
  };
}

function requiredManifestCheck(field, expected, submitted) {
  if (submitted === undefined || submitted === null || submitted === "") {
    return { field, expected, submitted: submitted ?? null, status: "missing_required_field" };
  }
  return { field, expected, submitted, status: manifestValuesMatch(expected, submitted) ? "matches" : "mismatch" };
}

function requiredStructuredManifestCheck(field, expected, submitted) {
  if (!submitted || typeof submitted !== "object" || Array.isArray(submitted)) {
    return { field, expected, submitted: submitted ?? null, status: "missing_required_field" };
  }
  return { field, expected, submitted, status: stableJsonKey(expected) === stableJsonKey(submitted) ? "matches" : "mismatch" };
}

function optionalManifestCheck(field, expected, submitted) {
  if (submitted === undefined || submitted === null || submitted === "") {
    return { field, expected, submitted: submitted ?? null, status: "not_submitted_optional" };
  }
  return { field, expected, submitted, status: manifestValuesMatch(expected, submitted) ? "matches" : "mismatch" };
}

function requiredNonEmptyCheck(field, submitted) {
  const ok = Array.isArray(submitted) ? submitted.length > 0 : submitted !== undefined && submitted !== null && submitted !== "";
  return { field, expected: "non_empty", submitted: submitted ?? null, status: ok ? "matches" : "missing_required_field" };
}

function requiredSetMembershipCheck(field, expectedAnyOf, submitted) {
  if (submitted === undefined || submitted === null || submitted === "") {
    return { field, expectedAnyOf, submitted: submitted ?? null, status: "missing_required_field" };
  }
  return { field, expectedAnyOf, submitted, status: expectedAnyOf.includes(submitted) ? "matches" : "mismatch" };
}

function optionalSetMembershipCheck(field, expectedAnyOf, submitted) {
  if (submitted === undefined || submitted === null || submitted === "") {
    return { field, expectedAnyOf, submitted: submitted ?? null, status: "not_submitted_optional" };
  }
  return { field, expectedAnyOf, submitted, status: expectedAnyOf.includes(submitted) ? "matches" : "mismatch" };
}

function requiredArrayIncludesCheck(field, expectedIncludes, submitted) {
  const submittedArray = Array.isArray(submitted) ? submitted : [];
  const missing = expectedIncludes.filter((value) => !submittedArray.includes(value));
  return { field, expectedIncludes, submitted: submittedArray, missing, status: missing.length ? "mismatch" : "matches" };
}

function requiredMinimumCheck(field, minimum, submitted) {
  if (submitted === undefined || submitted === null || submitted === "") {
    return { field, minimum, submitted: submitted ?? null, status: "missing_required_field" };
  }
  return { field, minimum, submitted, status: Number(submitted) >= minimum ? "matches" : "below_minimum" };
}

function requiredPolicyIncludesCheck(field, submitted, fragments) {
  if (submitted === undefined || submitted === null || submitted === "") {
    return { field, expectedIncludes: fragments, submitted: submitted ?? null, status: "missing_required_field" };
  }
  const normalized = String(submitted).toLowerCase();
  const missing = fragments.filter((fragment) => !normalized.includes(String(fragment).toLowerCase()));
  return { field, expectedIncludes: fragments, submitted, missing, status: missing.length ? "mismatch" : "matches" };
}

function requiredPolicyIncludesAnyCheck(field, submitted, fragments) {
  if (submitted === undefined || submitted === null || submitted === "") {
    return { field, expectedIncludesAny: fragments, submitted: submitted ?? null, status: "missing_required_field" };
  }
  const normalized = String(submitted).toLowerCase();
  const ok = fragments.some((fragment) => normalized.includes(String(fragment).toLowerCase()));
  return { field, expectedIncludesAny: fragments, submitted, status: ok ? "matches" : "mismatch" };
}

function manifestValuesMatch(expected, submitted) {
  if (typeof expected === "number" || typeof submitted === "number") return Number(expected) === Number(submitted);
  return expected === submitted;
}

function denominatorValue(summary = {}, field) {
  if (!summary || typeof summary !== "object") return undefined;
  const aliases = {
    blindInitialRatings: ["blindInitialRatings", "blindInitial", "blind_initial"],
    revisions: ["revisions", "revisionCount", "revised"],
    totalRows: ["totalRows", "total", "ratingRows"],
  };
  return aliases[field]?.map((key) => summary[key]).find((value) => value !== undefined) ?? summary[field];
}

function latestSubmittedExportManifest(records = [], releaseId, kind = "public") {
  return [...records].reverse().find((record) => (!record?.releaseId || record.releaseId === releaseId) && (!record?.kind || record.kind === kind)) ?? null;
}

function latestSubmittedWorkflowArtifactByField(records = [], field, value, releaseId) {
  return (
    [...records]
      .reverse()
      .find((record) => record?.[field] === value && (!record?.releaseId || record.releaseId === releaseId)) ?? null
  );
}

function protectedSplitList(record) {
  if (!record || typeof record !== "object") return [];
  if (record.protectedSplitsExcluded === true || record.protectedSplitExclusionPolicy === true) {
    return ["internal_validation", "hidden_benchmark"];
  }
  return (
    record.excludedProtectedSplits ??
    record.protectedSplitsExcluded ??
    record.protectedSplitExclusions ??
    record.protectedSplitPolicy?.excludedSplits ??
    record.protectedSplitPolicy?.excludedProtectedSplits ??
    []
  );
}

export function buildLmcaComparisonReport({ releaseId, corpusManifest, metricEligibility, validationDesign, labelSnapshot }) {
  const releaseRaterTotal = countTotal(corpusManifest.raterDistributionIgnoringRevisions);
  const lmcaRaterTotal = countTotal(LMCA_BASELINES.raterDistributionIgnoringRevisions);
  const releaseLargestRaterShare = largestShare(corpusManifest.raterDistributionIgnoringRevisions);
  const lmcaLargestRaterShare = largestShare(LMCA_BASELINES.raterDistributionIgnoringRevisions);
  const modelScoreAnchorComparison = buildLmcaModelScoreAnchorComparison();
  return {
    id: `lmca-comparison-${releaseId}`,
    releaseId,
    comparisonScope: "compressed_october_seed_vs_lmca_source_baselines",
    sourceScaleComparison: [
      comparisonRow("rated_critiques", corpusManifest.counts.critiques, LMCA_BASELINES.corpusScale.ratedCritiques),
      comparisonRow("ratings_ignoring_revisions", corpusManifest.counts.ratingsIgnoringRevisions, LMCA_BASELINES.corpusScale.ratingsIgnoringRevisions),
      comparisonRow("model_written_critiques", corpusManifest.counts.modelWrittenCritiques, LMCA_BASELINES.corpusScale.modelWrittenCritiques),
      comparisonRow("positions_with_at_least_one_critique", corpusManifest.counts.positions, LMCA_BASELINES.corpusScale.positionsWithAtLeastOneCritique),
      comparisonRow(
        "positions_with_at_least_two_critiques",
        corpusManifest.counts.positionsWithAtLeastTwoCritiques,
        LMCA_BASELINES.corpusScale.positionsWithAtLeastTwoCritiques,
      ),
    ],
    positionSourceComparison: Object.entries(LMCA_BASELINES.positionSourceCounts).map(([sourceCategory, lmcaCount]) => {
      const releaseCount = corpusManifest.positionSourceCategory[sourceCategory] ?? 0;
      return {
        sourceCategory,
        releaseCount,
        lmcaCount,
        releaseShare: share(releaseCount, corpusManifest.counts.positions),
        lmcaShare: share(lmcaCount, LMCA_BASELINES.corpusScale.positionsWithAtLeastOneCritique),
        status: releaseCount > 0 ? "covered_in_seed" : "missing_from_seed",
      };
    }),
    knownOtherDatasetSubsources: LMCA_BASELINES.knownOtherDatasetSubsources,
    topicFamilyComparison: LMCA_BASELINES.topicFamilies.map((topicFamily) => ({
      topicFamily,
      releaseCount: corpusManifest.topicFamily[topicFamily] ?? 0,
      status: corpusManifest.topicFamily[topicFamily] ? "covered_in_seed" : "missing_from_seed",
    })),
    raterCompositionComparison: {
      releaseDistributionIgnoringRevisions: corpusManifest.raterDistributionIgnoringRevisions,
      lmcaDistributionIgnoringRevisions: LMCA_BASELINES.raterDistributionIgnoringRevisions,
      releaseTotal: releaseRaterTotal,
      lmcaTotal: lmcaRaterTotal,
      releaseLargestRaterShare,
      lmcaLargestRaterShare,
      status: releaseRaterTotal >= LMCA_BASELINES.corpusScale.ratingsIgnoringRevisions && releaseLargestRaterShare <= lmcaLargestRaterShare ? "rater_composition_comparable" : "seed_rater_composition_not_comparable",
      note: "Rater-composition claims compare independent rows ignoring revisions; revisions, checks, and adjudication labels are tracked separately.",
    },
    modelDenominatorComparison: [
      comparisonRow("weighted_pairwise_positions", metricEligibility.pairwiseEligiblePositions.length, LMCA_BASELINES.modelEvaluationDenominators.weightedPairwisePositions),
      comparisonRow("weighted_pairwise_critique_pairs", metricEligibility.pairwiseEligiblePairCount, LMCA_BASELINES.modelEvaluationDenominators.weightedPairwiseCritiquePairs),
      comparisonRow("custom_metric_dialogues", metricEligibility.customLossEligibleItems.length, LMCA_BASELINES.modelEvaluationDenominators.customMetricDialogues),
    ],
    modelScoreAnchorComparison,
    targetLabelComparison: {
      currentTargetLabelVersion: labelSnapshot.targetLabelVersion,
      requiredForTable5StyleTarget: "primary_rater_anchor",
      lmcaTable5Target: "Emery Cooper ratings",
      status: labelSnapshot.targetLabelVersion === "primary_rater_anchor" ? "target_identical_candidate" : "lmca_style_not_target_identical",
      rows: [
        {
          comparison: "lmca_table_5_weighted_pairwise",
          lmcaTarget: "Emery Cooper ratings",
          releaseTarget: labelSnapshot.targetLabelVersion,
          cleanClaimAllowed: labelSnapshot.targetLabelVersion === "primary_rater_anchor",
        },
        {
          comparison: "volunteer_consensus_or_adjudicated",
          lmcaTarget: "not Table 5 target-identical",
          releaseTarget: labelSnapshot.targetLabelVersion,
          cleanClaimAllowed: true,
        },
      ],
    },
    validationHumanCeilingComparison: {
      currentValidationStatus: validationDesign.status,
      appendixCScaleMet: validationDesign.status === "appendix_c_scale",
      numericBaselines: LMCA_BASELINES.appendixCNumericBaselines,
      status: validationDesign.status === "appendix_c_scale" ? "appendix_c_comparable" : "numeric_baselines_declared_but_seed_validation_thin",
    },
    overclaimGuardrail:
      "This comparison is descriptive unless the relevant scale, source composition, rater composition, target-label, validation, denominator, and prompt-track gates pass independently.",
  };
}

function buildLmcaModelScoreAnchorComparison() {
  const weightedPairwiseDenominator = {
    positionsOrArguments: LMCA_BASELINES.modelEvaluationDenominators.weightedPairwisePositions,
    critiquePairs: LMCA_BASELINES.modelEvaluationDenominators.weightedPairwiseCritiquePairs,
  };
  const customMetricDenominator = {
    dialogues: LMCA_BASELINES.modelEvaluationDenominators.customMetricDialogues,
  };
  const uncertaintyIntervalPolicy = {
    intervalType: "source_reported_95_percent_confidence_interval",
    nominalLevel: 0.95,
    intervalNotation: "point_estimate_plus_minus_ci95",
  };
  const promptSnapshotPolicy = {
    sourceReferenceAnchorPolicy:
      "Treat LMCA Table 5/Table 7 scores as source-reference anchors unless target labels, prompt family/scope, protected-split policy, topic/source composition, and resolved model snapshots are comparable.",
    resolvedSnapshotRequiredForDirectReproduction: true,
  };
  const weightedPairwiseTable5 = LMCA_BASELINES.modelScoreAnchors.weightedPairwiseTable5.map((anchor) => ({
    ...anchor,
    table: "LMCA Table 5",
    metricFamily: "weighted_pairwise",
    lowerIsBetter: true,
    denominator: weightedPairwiseDenominator,
    targetLabelRegime: "Emery Cooper ratings",
    uncertaintyIntervalPolicy,
    promptSnapshotPolicy,
  }));
  const customMetricTable7 = LMCA_BASELINES.modelScoreAnchors.customMetricTable7.map((anchor) => ({
    ...anchor,
    table: "LMCA Table 7",
    metricFamily: "custom_weighted_loss",
    lowerIsBetter: true,
    denominator: customMetricDenominator,
    targetLabelRegime: "LMCA custom-metric human-rating target",
    uncertaintyIntervalPolicy,
    promptSnapshotPolicy,
  }));
  const anchorRows = [...weightedPairwiseTable5, ...customMetricTable7];
  return {
    lowerIsBetter: true,
    denominators: {
      weightedPairwiseTable5: weightedPairwiseDenominator,
      customMetricTable7: customMetricDenominator,
    },
    targetLabelRegimes: {
      weightedPairwiseTable5: "Emery Cooper ratings",
      customMetricTable7: "LMCA custom-metric human-rating target",
    },
    uncertaintyIntervalPolicy,
    promptSnapshotPolicy,
    weightedPairwiseTable5,
    customMetricTable7,
    anchorRows,
    anchorCount: anchorRows.length,
    status: "anchors_declared_seed_run_not_numeric_comparable",
    note: "Anchor scores are source baselines for release reports; the seed run differs in scale, target labels, prompt tracks, and protected split policy.",
  };
}

export function buildComparabilityClaimMatrix({ corpusManifest, metricEligibility, validationDesign, labelSnapshot, submittedClaims = [] }) {
  const computedClaims = [
    claim("method_preserving", "passes", "Position-critique units, seven-dimensional ratings, blind initial surface, immutable revisions, and the two LMCA scoring families are implemented."),
    claim(
      "corpus_scale_comparable",
      corpusManifest.counts.positions >= LMCA_BASELINES.corpusScale.positionsWithAtLeastOneCritique ? "passes" : "fails",
      `${corpusManifest.counts.positions} positions loaded versus LMCA's ${LMCA_BASELINES.corpusScale.positionsWithAtLeastOneCritique} positions with at least one rated critique.`,
    ),
    claim(
      "source_topic_rater_comparable",
      coversAllBaselineTopics(corpusManifest.topicFamily) ? "passes" : "partial",
      "Source, topic, split, and rater-composition tables are generated; the seed corpus does not yet cover every LMCA topic family.",
    ),
    claim(
      "exact_position_source_count_comparable",
      corpusManifest.counts.positions >= LMCA_BASELINES.corpusScale.positionsWithAtLeastOneCritique ? "passes" : "fails",
      `${corpusManifest.counts.positions} positions loaded; exact LMCA-style source-count claims require the target corpus scale and linked source manifest evidence.`,
    ),
    claim(
      "topic_family_comparable",
      coversAllBaselineTopics(corpusManifest.topicFamily) ? "passes" : "partial",
      "Topic-family coverage is reported separately from the generic source/topic/rater comparability rollup.",
    ),
    claim(
      "rater_contribution_comparable",
      "partial",
      "Rater contribution distributions are reported, but LMCA-identical rater composition claims require matching contribution and expertise evidence.",
    ),
    claim(
      "adapted_source_language_task_format_comparable",
      "partial",
      "Adapted-source, language, and task-format status must remain explicit when a release includes translated or reformatted artifacts.",
    ),
    claim(
      "metric_denominator_comparable",
      metricEligibility.pairwiseEligiblePairCount >= LMCA_BASELINES.modelEvaluationDenominators.weightedPairwiseCritiquePairs ? "passes" : "fails",
      `${metricEligibility.pairwiseEligiblePairCount} pairwise-eligible critique pairs versus LMCA Table 5's ${LMCA_BASELINES.modelEvaluationDenominators.weightedPairwiseCritiquePairs}.`,
    ),
    claim(
      "target_label_comparable",
      labelSnapshot.targetLabelVersion === "primary_rater_anchor" ? "passes" : "fails",
      `Current target label version is ${labelSnapshot.targetLabelVersion}; LMCA Table 5-style target-identical claims require a frozen primary-rater anchor.`,
    ),
    claim(
      "validation_design_comparable",
      validationDesign.status === "appendix_c_scale" ? "passes" : "fails",
      `Validation status is ${validationDesign.status}; Appendix-C-scale requires ${OCTOBER_RELEASE_TARGETS.validationCritiques} critiques, ${OCTOBER_RELEASE_TARGETS.validationPositions} positions, and ${OCTOBER_RELEASE_TARGETS.coreAllItemsRaters} core all-items raters.`,
    ),
    claim("validation_ceiling_comparable", validationDesign.status === "appendix_c_scale" ? "passes" : "fails", "Human-ceiling numeric baselines are stored, but the seed validation run is thinner than Appendix C."),
    claim("model_score_anchor_comparable", "partial", "LMCA Table 5 and Table 7 anchor scores are stored for reports; seed model outputs are not a comparable leaderboard run."),
    claim("prompt_family_source_scope_comparable", "partial", "Prompt family and source-scope parity are tracked separately from model-score anchor status."),
    claim("model_snapshot_comparable", "partial", "Model snapshot and parameter provenance are required before model-score comparisons can be treated as target-stable."),
    claim("protected_split_leakage_comparable", "partial", "Protected-split leakage status is tracked independently from ordinary release-scale and validation-design claims."),
    claim("replication_like", "fails", "The current seed release is method-preserving scaffolding, not an LMCA-scale or target-identical replication."),
  ];
  return applySubmittedComparabilityClaims(computedClaims, submittedClaims);
}

function robustnessClaimsFromSubmittedComparabilityClaims(submittedClaims = []) {
  return uniqueStrings(
    submittedClaims.flatMap((claim) => (Array.isArray(claim?.robustnessClaims) ? claim.robustnessClaims : [])),
  );
}

function applySubmittedComparabilityClaims(computedClaims, submittedClaims = []) {
  const submittedClaim = submittedClaims.at(-1) ?? null;
  if (!submittedClaim) {
    return computedClaims.map((claimRow) => ({
      ...claimRow,
      statusSource: "computed_release_evidence",
      computedStatus: claimRow.status,
    }));
  }
  const submittedClaimContractChecks = submittedComparabilityClaimContractChecks(submittedClaim);
  const submittedClaimContractViolations = submittedClaimContractChecks.filter((check) => check.status !== "pass");
  const submittedByTier = submittedComparabilityStatuses(submittedClaim);
  const submittedClaimMetadata = {
    submittedClaimId: submittedClaim.id ?? null,
    submittedReleaseGateProfileId: submittedClaim.releaseGateProfileId ?? null,
    submittedPrimaryRaterAnchorPolicyId: submittedClaim.primaryRaterAnchorPolicyId ?? null,
    submittedLinkedReleaseIds: Array.isArray(submittedClaim.linkedReleaseIds) ? submittedClaim.linkedReleaseIds : [],
    submittedEvidenceLinks: Array.isArray(submittedClaim.evidenceLinks) ? submittedClaim.evidenceLinks : [],
    submittedApprovedBy: submittedClaim.approvedBy ?? null,
    submittedTimestamp: submittedClaim.timestamp ?? null,
    submittedClaimContractChecks,
    submittedClaimContractViolations,
    submittedClaimContractViolationCount: submittedClaimContractViolations.length,
  };
  if (submittedClaimContractViolations.length) {
    return computedClaims.map((claimRow) => ({
      ...claimRow,
      statusSource: "computed_release_evidence_submitted_claim_contract_review_required",
      computedStatus: claimRow.status,
      ...submittedClaimMetadata,
    }));
  }
  return computedClaims.map((claimRow) => {
    const submitted = submittedByTier[claimRow.tier] ?? null;
    if (!submitted) {
      return {
        ...claimRow,
        statusSource: "computed_release_evidence_no_submitted_tier",
        computedStatus: claimRow.status,
        ...submittedClaimMetadata,
      };
    }
    const normalizedSubmittedStatus = normalizeComparabilityStatus(submitted.status);
    const effectiveStatus = stricterComparabilityStatus(claimRow.status, normalizedSubmittedStatus);
    return {
      ...claimRow,
      status: effectiveStatus,
      evidence: submitted.evidence ?? claimRow.evidence,
      computedStatus: claimRow.status,
      computedEvidence: claimRow.evidence,
      submittedStatus: submitted.status,
      normalizedSubmittedStatus,
      submittedEvidence: submitted.evidence ?? null,
      ...submittedClaimMetadata,
      submittedClaimWording: submittedClaim.claimWording ?? null,
      statusSource:
        effectiveStatus === normalizedSubmittedStatus
          ? "submitted_comparability_claim"
          : "computed_guardrail_with_submitted_claim",
    };
  });
}

const REQUIRED_COMPARABILITY_CLAIM_FIELDS = [
  "id",
  "releaseId",
  "releaseGateProfileId",
  "claimWording",
  "methodPreservingStatus",
  "corpusScaleStatus",
  "exactPositionSourceCountStatus",
  "topicFamilyStatus",
  "raterContributionStatus",
  "adaptedSourceLanguageTaskFormatStatus",
  "metricDenominatorStatus",
  "targetLabelRaterStatus",
  "primaryRaterAnchorPolicyId",
  "validationDesignStatus",
  "validationNumericCeilingStatus",
  "modelScoreAnchorStatus",
  "promptFamilySourceScopeStatus",
  "modelSnapshotStatus",
  "protectedSplitLeakageStatus",
  "limitationsText",
  "approvedBy",
  "timestamp",
];
const REQUIRED_COMPARABILITY_CLAIM_ARRAY_FIELDS = ["linkedReleaseIds", "evidenceLinks"];
const COMPARABILITY_CLAIM_STATUS_FIELDS = [
  "methodPreservingStatus",
  "corpusScaleStatus",
  "exactPositionSourceCountStatus",
  "topicFamilyStatus",
  "raterContributionStatus",
  "adaptedSourceLanguageTaskFormatStatus",
  "metricDenominatorStatus",
  "targetLabelRaterStatus",
  "validationDesignStatus",
  "validationNumericCeilingStatus",
  "modelScoreAnchorStatus",
  "promptFamilySourceScopeStatus",
  "modelSnapshotStatus",
  "protectedSplitLeakageStatus",
];
const ALLOWED_COMPARABILITY_CLAIM_STATUSES = ["passes", "partial", "fails", "not_applicable"];

function submittedComparabilityClaimContractChecks(submittedClaim) {
  const fieldChecks = REQUIRED_COMPARABILITY_CLAIM_FIELDS.map((field) => ({
    field,
    expected: "present",
    observed: submittedClaim?.[field] ?? null,
    status: hasRequiredValue(submittedClaim?.[field]) ? "pass" : "missing_required_field",
  }));
  const arrayChecks = REQUIRED_COMPARABILITY_CLAIM_ARRAY_FIELDS.map((field) => ({
    field,
    expected: "non_empty_array",
    observed: submittedClaim?.[field] ?? null,
    status: Array.isArray(submittedClaim?.[field]) && submittedClaim[field].length ? "pass" : "missing_required_array_values",
  }));
  const statusChecks = COMPARABILITY_CLAIM_STATUS_FIELDS.map((field) => ({
    field,
    expected: ALLOWED_COMPARABILITY_CLAIM_STATUSES,
    observed: submittedClaim?.[field] ?? null,
    status: ALLOWED_COMPARABILITY_CLAIM_STATUSES.includes(submittedClaim?.[field]) ? "pass" : "invalid_claim_status",
  }));
  return [...fieldChecks, ...arrayChecks, ...statusChecks];
}

function submittedComparabilityStatuses(claim) {
  const statuses = {};
  const directFieldMap = {
    methodPreservingStatus: "method_preserving",
    corpusScaleStatus: "corpus_scale_comparable",
    sourceTopicRaterStatus: "source_topic_rater_comparable",
    exactPositionSourceCountStatus: "exact_position_source_count_comparable",
    topicFamilyStatus: "topic_family_comparable",
    raterContributionStatus: "rater_contribution_comparable",
    adaptedSourceLanguageTaskFormatStatus: "adapted_source_language_task_format_comparable",
    metricDenominatorStatus: "metric_denominator_comparable",
    targetLabelRaterStatus: "target_label_comparable",
    targetLabelStatus: "target_label_comparable",
    validationDesignStatus: "validation_design_comparable",
    validationNumericCeilingStatus: "validation_ceiling_comparable",
    validationCeilingStatus: "validation_ceiling_comparable",
    modelScoreAnchorStatus: "model_score_anchor_comparable",
    promptFamilySourceScopeStatus: "prompt_family_source_scope_comparable",
    modelSnapshotStatus: "model_snapshot_comparable",
    protectedSplitLeakageStatus: "protected_split_leakage_comparable",
    promptModelScoreAnchorStatus: "model_score_anchor_comparable",
    replicationLikeStatus: "replication_like",
  };
  Object.entries(directFieldMap).forEach(([field, tier]) => {
    if (claim[field] !== undefined && statuses[tier] === undefined) {
      statuses[tier] = {
        status: claim[field],
        evidence: claim[`${field.replace(/Status$/, "")}Evidence`] ?? claim.limitationsText ?? claim.claimWording ?? null,
      };
    }
  });
  Object.entries(claim.claimStatuses ?? {}).forEach(([tier, status]) => {
    statuses[normalizeComparabilityTier(tier)] = {
      status,
      evidence: claim.evidenceByTier?.[tier] ?? claim.evidenceByTier?.[normalizeComparabilityTier(tier)] ?? claim.limitationsText ?? claim.claimWording ?? null,
    };
  });
  (claim.tierStatuses ?? claim.tiers ?? []).forEach((row) => {
    if (!row || typeof row !== "object") return;
    const tier = normalizeComparabilityTier(row.tier ?? row.id);
    if (!tier) return;
    statuses[tier] = {
      status: row.status ?? row.claimStatus,
      evidence: row.evidence ?? row.limitationsText ?? claim.limitationsText ?? claim.claimWording ?? null,
    };
  });
  return statuses;
}

function normalizeComparabilityTier(tier) {
  return typeof tier === "string" ? tier.trim().toLowerCase().replace(/[-\s]+/g, "_") : "";
}

function normalizeComparabilityStatus(status) {
  const value = typeof status === "string" ? status.trim().toLowerCase().replace(/[-\s]+/g, "_") : "";
  if (!value) return "fails";
  if (value === "passes" || value === "pass" || value.startsWith("passes_")) return "passes";
  if (value === "partial" || value.startsWith("partial_") || value.includes("_partial_")) return "partial";
  if (value === "not_applicable" || value === "not_applicable_here" || value === "na") return "not_applicable";
  if (value === "fails" || value === "fail" || value.startsWith("fails_") || value.startsWith("fail_")) return "fails";
  return value.includes("required") || value.includes("until") || value.includes("missing") ? "fails" : "partial";
}

function stricterComparabilityStatus(computedStatus, submittedStatus) {
  const rank = { fails: 0, partial: 1, not_applicable: 1, passes: 2 };
  const computedRank = rank[normalizeComparabilityStatus(computedStatus)] ?? 0;
  const submittedRank = rank[normalizeComparabilityStatus(submittedStatus)] ?? 0;
  return computedRank <= submittedRank ? normalizeComparabilityStatus(computedStatus) : normalizeComparabilityStatus(submittedStatus);
}

export function buildPromptTrackSeparationReport(
  releaseId,
  evaluationRuns = [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  generationRuns = critiqueGenerationRuns,
) {
  const evaluationRows = evaluationRuns.map((run) => promptTrackRowFromRun("model_evaluation", run));
  const generationRows = generationRuns.flatMap((run) => {
    const generationRow = promptTrackRowFromRun("critique_generation", run);
    const judge = run.modelJudgeScreening;
    const judgeArtifact = judge?.promptArtifact ?? promptArtifactRef(judge?.promptTemplateId ?? "candidate-judge-v2");
    const judgeRow = {
      ...promptTrackRowFromArtifact("model_judge_screening", {
        id: `${run.id}::model-judge`,
        requestedModelAlias: judge?.requestedModelAlias,
        resolvedModelSnapshot: judge?.resolvedModelSnapshot,
        promptFamily: judgeArtifact.promptFamily,
        promptScope: judgeArtifact.promptScope,
        promptArtifact: judgeArtifact,
        renderedPromptChecksum: judge?.renderedPromptChecksum ?? judgeArtifact.renderedPromptChecksum,
        promptPolicyComparabilityStatus: judge?.promptPolicyComparabilityStatus ?? judgeArtifact.promptPolicyComparabilityStatus,
        protectedPromptExampleCheck: judgeArtifact.protectedSplitExclusionCheck,
        itemRoleTerminology: judgeArtifact.itemRoleTerminology,
        outputFormatPolicy: judgeArtifact.outputFormatPolicy,
      }),
      parentGenerationRunId: run.id,
      diagnosticOnly: judge?.diagnosticOnly ?? true,
      scoresVisibleToInitialRaters: judge?.scoresVisibleToInitialRaters ?? null,
    };
    return [generationRow, judgeRow];
  });
  const rows = [...evaluationRows, ...generationRows].sort((left, right) => left.trackKind.localeCompare(right.trackKind) || left.runId.localeCompare(right.runId));
  const protectedExampleViolations = rows.filter((row) => !row.hiddenBenchmarkExamplesExcluded || !row.protectedValidationExamplesExcluded);
  const appendixGBaselineRows = rows.filter((row) => row.promptScope === "appendix_g_overall_only_exact");
  const projectExtensionRows = rows.filter((row) => row.promptPolicyComparabilityStatus !== "source_comparable_overall_only_prompt_track");
  const exampleRows = rows.flatMap((row) => row.promptExampleProvenance.map((example) => ({ ...example, runId: row.runId, promptArtifactId: row.promptArtifactId })));
  const exampleRowsMissingRequiredIds = exampleRows.filter(
    (row) =>
      !row.itemId ||
      !row.positionClusterId ||
      !row.split ||
      row.hiddenBenchmarkExcluded !== true ||
      row.protectedValidationExcluded !== true,
  );
  return {
    id: `prompt-track-separation-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      appendixGRule: "Appendix-G exact overall-only prompts are a source-comparable simple-baseline track and must not be merged with project full-rubric prompts.",
      projectExtensionRule:
        "Full-rubric, critique-generation, model-judge, elicitation, few-shot, optimized, and tool-assisted tracks are project extensions or diagnostics unless explicitly reported as prompt-sensitivity variants.",
      protectedExampleRule:
        "Few-shot and worked examples must record item ids, position-cluster ids, split membership, and hidden-benchmark/protected-validation exclusion checks; no-example tracks must say so explicitly.",
    },
    counts: {
      promptTrackRows: rows.length,
      evaluationPromptTrackRows: evaluationRows.length,
      generationPromptTrackRows: generationRows.length,
      appendixGExactRows: appendixGBaselineRows.length,
      projectExtensionRows: projectExtensionRows.length,
      protectedExampleViolationCount: protectedExampleViolations.length,
      promptExampleRows: exampleRows.length,
      promptExampleRowsMissingRequiredIds: exampleRowsMissingRequiredIds.length,
    },
    byTrackKind: countBy(rows, "trackKind"),
    byPromptScope: countBy(rows, "promptScope"),
    byPromptPolicyComparabilityStatus: countBy(rows, "promptPolicyComparabilityStatus"),
    rows,
    appendixGBaselineRows,
    projectExtensionRows,
    protectedExampleViolations,
    exampleRows,
    exampleRowsMissingRequiredIds,
    releaseUseStatus:
      protectedExampleViolations.length || exampleRowsMissingRequiredIds.length
        ? "prompt_track_protected_example_review_required"
        : appendixGBaselineRows.length && projectExtensionRows.length
          ? "appendix_g_baseline_separated_from_project_prompt_tracks"
          : appendixGBaselineRows.length
            ? "appendix_g_baseline_prompt_track_only"
            : "project_prompt_tracks_disclosed_without_appendix_g_baseline",
  };
}

export function buildPromptParserProvenanceReport(
  releaseId,
  evaluationRuns = [fullRubricEvaluationRun, overallOnlyEvaluationRun],
  generationRuns = critiqueGenerationRuns,
  { promptTemplates = [], parserConfigs = [], modelEvaluationPredictions = [] } = {},
) {
  const submittedPromptTemplates = promptTemplates.map(normalizeSubmittedPromptTemplate).filter(Boolean);
  const submittedParserConfigs = parserConfigs.map(normalizeSubmittedParserConfig).filter(Boolean);
  const submittedPromptById = new Map(submittedPromptTemplates.map((template) => [template.id, template]));
  const submittedParserById = new Map(submittedParserConfigs.map((config) => [config.id, config]));
  const references = promptParserReferences(evaluationRuns, generationRuns, modelEvaluationPredictions);
  const promptReferenceRows = references
    .filter((reference) => reference.promptTemplateId)
    .map((reference) => promptReferenceEvidenceRow(reference, submittedPromptById));
  const parserReferenceRows = references
    .filter((reference) => reference.parserConfigId)
    .map((reference) => parserReferenceEvidenceRow(reference, submittedParserById));
  const submittedPromptReviewRows = submittedPromptTemplates.filter((template) => template.reviewReasons.length > 0);
  const submittedParserReviewRows = submittedParserConfigs.filter((config) => config.reviewReasons.length > 0);
  const missingPromptRows = promptReferenceRows.filter((row) => row.status === "missing_prompt_template_reference");
  const missingParserRows = parserReferenceRows.filter((row) => row.status === "missing_parser_config_reference");
  const reviewRequired =
    missingPromptRows.length ||
    missingParserRows.length ||
    submittedPromptReviewRows.length ||
    submittedParserReviewRows.length;
  return {
    id: `prompt-parser-provenance-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    policy: {
      promptTemplateRule:
        "Submitted PromptTemplate records must preserve prompt family/track, source-scope class, rendered checksum or hash, output schema, role, and protected-split example exclusion before they count as active prompt provenance.",
      parserConfigRule:
        "Submitted ParserConfig records must preserve accepted schema, parser version or implementation id, retry/repair policy, invalid-score and missing-field handling, and protected-split retry constraints before they count as active parser provenance.",
      referenceRule:
        "Evaluation, prediction, generation, and model-judge rows must reference either a built-in immutable prompt/parser artifact or a submitted workflow record.",
    },
    counts: {
      promptReferenceCount: promptReferenceRows.length,
      parserReferenceCount: parserReferenceRows.length,
      submittedPromptTemplateCount: submittedPromptTemplates.length,
      submittedParserConfigCount: submittedParserConfigs.length,
      missingPromptReferenceCount: missingPromptRows.length,
      missingParserReferenceCount: missingParserRows.length,
      submittedPromptReviewCount: submittedPromptReviewRows.length,
      submittedParserReviewCount: submittedParserReviewRows.length,
    },
    promptReferenceRows,
    parserReferenceRows,
    submittedPromptTemplates,
    submittedParserConfigs,
    reviewRows: {
      missingPromptRows,
      missingParserRows,
      submittedPromptReviewRows,
      submittedParserReviewRows,
    },
    releaseUseStatus: reviewRequired
      ? "prompt_parser_provenance_review_required"
      : submittedPromptTemplates.length || submittedParserConfigs.length
        ? "submitted_prompt_parser_provenance_complete"
        : "seed_prompt_parser_provenance_complete",
  };
}

function promptParserReferences(evaluationRuns, generationRuns, modelEvaluationPredictions = []) {
  return [
    ...evaluationRuns.flatMap((run) => [
      {
        sourceType: "evaluation_run",
        sourceId: run.id,
        promptTemplateId: run.promptArtifact?.id ?? run.promptTemplateId,
        parserConfigId: run.parserConfigId,
      },
      ...(run.predictions ?? []).map((prediction) => ({
        sourceType: "model_evaluation_prediction",
        sourceId: prediction.id,
        evaluationRunId: run.id,
        promptTemplateId: prediction.promptTemplateId,
        parserConfigId: prediction.parserConfigId,
      })),
    ]),
    ...generationRuns.flatMap((run) => [
      {
        sourceType: "critique_generation_run",
        sourceId: run.id,
        promptTemplateId: run.promptArtifact?.id ?? run.promptTemplateId,
        parserConfigId: run.parserConfigId ?? null,
      },
      {
        sourceType: "model_judge_screening",
        sourceId: run.id,
        promptTemplateId: run.modelJudgeScreening?.promptArtifact?.id ?? run.modelJudgeScreening?.promptTemplateId,
        parserConfigId: run.modelJudgeScreening?.parserConfigId,
      },
    ]),
    ...modelEvaluationPredictions.map((prediction) => ({
      sourceType: "submitted_model_evaluation_prediction",
      sourceId: prediction.id,
      evaluationRunId: prediction.evaluationRunId,
      promptTemplateId: prediction.promptTemplateId,
      parserConfigId: prediction.parserConfigId,
    })),
  ];
}

function normalizeSubmittedPromptTemplate(template) {
  const id = template?.id ?? template?.promptTemplateId ?? template?.prompt_template_id;
  if (!id) return null;
  const protectedSplitExclusionPolicy = template.protectedSplitExclusionPolicy ?? template.protectedPromptExampleCheck?.status ?? null;
  const toolAvailabilityPolicy = template.toolAvailabilityPolicy ?? null;
  const reviewReasons = [
    requiredPromptFieldReason("promptFamily", template.promptFamily),
    requiredPromptFieldReason("promptTrack", template.promptTrack ?? template.promptSourceScopeClass),
    requiredPromptFieldReason("promptSourceScopeClass", template.promptSourceScopeClass ?? template.promptScope),
    requiredPromptFieldReason("renderedPromptChecksum", template.renderedPromptChecksum ?? template.promptTextHash ?? template.bodyHash),
    requiredPromptFieldReason("promptRole", template.promptRole ?? template.role),
    requiredPromptFieldReason("requestedOutputSchema", template.requestedOutputSchema ?? template.outputFormatPolicy ?? template.acceptedSchema),
    protectedSplitExclusionPolicy &&
    (String(protectedSplitExclusionPolicy).includes("hidden") || String(protectedSplitExclusionPolicy).includes("protected"))
      ? null
      : "protectedSplitExclusionPolicy",
    policyMentions(template.itemDataDelimiterPolicy, ["delimiter"]) ? null : "itemDataDelimiterPolicy",
    policyMentions(template.instructionHierarchyText, ["data", "not instruction"]) ? null : "instructionHierarchyText",
    policyMentionsAny(toolAvailabilityPolicy, ["no_tools", "disabled", "diagnostic"]) ? null : "toolAvailabilityPolicy",
    policyMentions(template.promptInjectionArtifactFlagPolicy, ["flag"]) ? null : "promptInjectionArtifactFlagPolicy",
  ].filter(Boolean);
  return {
    id,
    templateSource: "submitted_workflow_prompt_template",
    promptFamily: template.promptFamily ?? null,
    promptTrack: template.promptTrack ?? null,
    promptSourceScopeClass: template.promptSourceScopeClass ?? template.promptScope ?? null,
    promptVersion: template.promptVersion ?? template.version ?? null,
    renderedPromptChecksum: template.renderedPromptChecksum ?? null,
    promptTextHash: template.promptTextHash ?? template.bodyHash ?? null,
    promptRole: template.promptRole ?? template.role ?? null,
    requestedOutputSchema: template.requestedOutputSchema ?? template.outputFormatPolicy ?? template.acceptedSchema ?? null,
    protectedSplitExclusionPolicy,
    itemDataDelimiterPolicy: template.itemDataDelimiterPolicy ?? null,
    instructionHierarchyText: template.instructionHierarchyText ?? null,
    toolAvailabilityPolicy,
    promptInjectionArtifactFlagPolicy: template.promptInjectionArtifactFlagPolicy ?? null,
    reviewReasons,
    status: reviewReasons.length ? "submitted_prompt_template_review_required" : "submitted_prompt_template_complete",
  };
}

function normalizeSubmittedParserConfig(config) {
  const id = config?.id ?? config?.parserConfigId ?? config?.parser_config_id;
  if (!id) return null;
  const reviewReasons = [
    requiredPromptFieldReason("acceptedSchema", config.acceptedSchema),
    requiredPromptFieldReason("parserVersion", config.parserVersion ?? config.parserImplementationId),
    requiredPromptFieldReason("retryPolicy", config.retryPolicy),
    requiredPromptFieldReason("repairPolicy", config.repairPolicy),
    requiredPromptFieldReason("invalidScoreHandling", config.invalidScoreHandling),
    requiredPromptFieldReason("missingFieldHandling", config.missingFieldHandling),
    requiredPromptFieldReason("protectedSplitRetryConstraints", config.protectedSplitRetryConstraints),
    policyMentions(config.itemInternalInstructionHandling, ["reject", "item"]) ? null : "itemInternalInstructionHandling",
    policyMentions(config.retryPromptInstructionPolicy, ["not", "item"]) ? null : "retryPromptInstructionPolicy",
    policyMentions(config.retryProtectedAnswerLeakagePolicy, ["no", "protected"]) ? null : "retryProtectedAnswerLeakagePolicy",
    policyMentions(config.outputWrapperHandling, ["reject", "wrapper"]) ? null : "outputWrapperHandling",
    policyMentions(config.protectedSplitRetryConstraints, ["no", "protected"]) ? null : "protectedSplitRetryConstraints:protected",
  ].filter(Boolean);
  return {
    id,
    configSource: "submitted_workflow_parser_config",
    acceptedSchema: config.acceptedSchema ?? null,
    parserVersion: config.parserVersion ?? config.parserImplementationId ?? null,
    scoreFieldRequirements: config.scoreFieldRequirements ?? [],
    retryPolicy: config.retryPolicy ?? null,
    repairPolicy: config.repairPolicy ?? null,
    invalidScoreHandling: config.invalidScoreHandling ?? null,
    outOfRangeHandling: config.outOfRangeHandling ?? null,
    missingFieldHandling: config.missingFieldHandling ?? null,
    protectedSplitRetryConstraints: config.protectedSplitRetryConstraints ?? null,
    itemInternalInstructionHandling: config.itemInternalInstructionHandling ?? null,
    retryPromptInstructionPolicy: config.retryPromptInstructionPolicy ?? null,
    retryProtectedAnswerLeakagePolicy: config.retryProtectedAnswerLeakagePolicy ?? null,
    outputWrapperHandling: config.outputWrapperHandling ?? null,
    reviewReasons,
    status: reviewReasons.length ? "submitted_parser_config_review_required" : "submitted_parser_config_complete",
  };
}

function promptReferenceEvidenceRow(reference, submittedPromptById) {
  const seedArtifact = promptArtifacts[reference.promptTemplateId];
  const submittedTemplate = submittedPromptById.get(reference.promptTemplateId);
  return {
    ...reference,
    referenceKind: "prompt_template",
    referenceSource: seedArtifact ? "seed_prompt_artifact" : submittedTemplate ? "submitted_workflow_prompt_template" : "missing",
    submittedStatus: submittedTemplate?.status ?? null,
    status: seedArtifact
      ? "seed_prompt_artifact_reference"
      : submittedTemplate?.status === "submitted_prompt_template_complete"
        ? "submitted_prompt_template_reference"
        : submittedTemplate
          ? "submitted_prompt_template_review_required"
          : "missing_prompt_template_reference",
  };
}

function parserReferenceEvidenceRow(reference, submittedParserById) {
  const seedParser = seedParserConfigIds().has(reference.parserConfigId);
  const submittedConfig = submittedParserById.get(reference.parserConfigId);
  return {
    ...reference,
    referenceKind: "parser_config",
    referenceSource: seedParser ? "seed_parser_config" : submittedConfig ? "submitted_workflow_parser_config" : "missing",
    submittedStatus: submittedConfig?.status ?? null,
    status: seedParser
      ? "seed_parser_config_reference"
      : submittedConfig?.status === "submitted_parser_config_complete"
        ? "submitted_parser_config_reference"
        : submittedConfig
          ? "submitted_parser_config_review_required"
          : "missing_parser_config_reference",
  };
}

function seedParserConfigIds() {
  return new Set(["json-seven-dim-v1", "json-overall-v1", "json-generation-judge-v1"]);
}

function requiredPromptFieldReason(field, value) {
  if (value === undefined || value === null || value === "" || (Array.isArray(value) && value.length === 0)) return field;
  return null;
}

function hasPlainObject(value) {
  return Boolean(value) && typeof value === "object" && !Array.isArray(value) && Object.keys(value).length > 0;
}

