export function buildUXSimplificationEvidenceReport(releaseId, options = {}) {
  const submittedPolicyRows = (options.uxSimplificationPolicies ?? []).map((policy) => normalizeUXSimplificationPolicy(policy, "submitted_workflow_ux_simplification_policy")).filter(Boolean);
  const seedPolicy = normalizeUXSimplificationPolicy(defaultUXSimplificationPolicy(releaseId), "seed_rlhf88_policy");
  const activePolicy = submittedPolicyRows.at(-1) ?? seedPolicy;
  const submittedReviewRows = (options.uxSimplificationReviews ?? [])
    .map((review) => normalizeUXSimplificationReview(review, activePolicy.id, "submitted_workflow_ux_simplification_review"))
    .filter(Boolean);
  const submittedScreenStateRows = (options.screenStatePayloads ?? [])
    .map((payload) => normalizeScreenStatePayload(payload, "submitted_workflow_screen_state_payload"))
    .filter(Boolean);
  const submittedFeatureParityRows = (options.screenFeatureParityChecks ?? [])
    .map((check) => normalizeUXScreenFeatureParityCheck(check, activePolicy.id, "submitted_workflow_screen_feature_parity_check"))
    .filter(Boolean);
  const submittedCopyPreviewRows = (options.simplifiedCopyPreviews ?? [])
    .map((preview) => normalizeUXSimplifiedCopyPreview(preview, "submitted_workflow_simplified_copy_preview"))
    .filter(Boolean);
  const submittedTraceabilityRows = (options.rubricCopyTraceabilityMaps ?? [])
    .map((map) => normalizeRubricCopyTraceabilityMap(map, "submitted_workflow_rubric_copy_traceability_map"))
    .filter(Boolean);
  const hasSubmittedEvidence =
    submittedPolicyRows.length ||
    submittedReviewRows.length ||
    submittedScreenStateRows.length ||
    submittedFeatureParityRows.length ||
    submittedCopyPreviewRows.length ||
    submittedTraceabilityRows.length;
  const seedReviewRows = [normalizeUXSimplificationReview(defaultUXSimplificationReview(releaseId, seedPolicy.id), seedPolicy.id, "seed_rlhf88_review")];
  const seedScreenStateRows = defaultScreenStatePayloads(releaseId, seedPolicy.id).map((payload) => normalizeScreenStatePayload(payload, "seed_server_derived_screen_state"));
  const seedFeatureParityRows = defaultScreenFeatureParityChecks(releaseId, seedPolicy.id)
    .map((check) => normalizeUXScreenFeatureParityCheck(check, seedPolicy.id, "seed_screen_feature_parity_check"))
    .filter(Boolean);
  const seedCopyPreviewRows = defaultSimplifiedCopyPreviews(releaseId)
    .map((preview) => normalizeUXSimplifiedCopyPreview(preview, "seed_simplified_copy_preview"))
    .filter(Boolean);
  const seedTraceabilityRows = [normalizeRubricCopyTraceabilityMap(defaultRubricCopyTraceabilityMap(releaseId), "seed_rubric_copy_traceability_map")];
  const reviewRowsForGate = hasSubmittedEvidence ? submittedReviewRows : seedReviewRows;
  const screenStateRowsForGate = hasSubmittedEvidence ? submittedScreenStateRows : seedScreenStateRows;
  const featureParityRowsForGate = hasSubmittedEvidence ? submittedFeatureParityRows : seedFeatureParityRows;
  const copyPreviewRowsForGate = hasSubmittedEvidence ? submittedCopyPreviewRows : seedCopyPreviewRows;
  const traceabilityRowsForGate = hasSubmittedEvidence ? submittedTraceabilityRows : seedTraceabilityRows;
  const surfaceRows = UX_SIMPLIFICATION_SURFACES.map((surface) =>
    uxSimplificationSurfaceEvidenceRow(
      surface,
      activePolicy,
      reviewRowsForGate,
      screenStateRowsForGate,
      featureParityRowsForGate,
      copyPreviewRowsForGate,
      traceabilityRowsForGate,
    ),
  );
  const reviewSections = [
    ...submittedPolicyRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "ux_simplification_policy", artifactId: row.id, reason }))),
    ...submittedReviewRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "ux_simplification_review", artifactId: row.id, reason }))),
    ...submittedScreenStateRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "screen_state_payload", artifactId: row.id, reason }))),
    ...submittedFeatureParityRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "screen_feature_parity_check", artifactId: row.id, reason }))),
    ...submittedCopyPreviewRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "simplified_copy_preview", artifactId: row.id, reason }))),
    ...submittedTraceabilityRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "rubric_copy_traceability_map", artifactId: row.id, reason }))),
    ...surfaceRows.filter((row) => row.status !== "ux_surface_simplification_gate_passed").map((row) => ({ artifactType: "ux_surface", artifactId: row.surface, reason: row.status })),
  ];
  const submittedEvidenceComplete =
    submittedPolicyRows.length > 0 &&
    submittedReviewRows.length > 0 &&
    submittedScreenStateRows.length > 0 &&
    submittedFeatureParityRows.length > 0 &&
    submittedCopyPreviewRows.length > 0 &&
    submittedTraceabilityRows.length > 0 &&
    reviewSections.length === 0 &&
    activePolicy.policySource === "submitted_workflow_ux_simplification_policy";
  return {
    id: `ux-simplification-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    requiredSurfaces: UX_SIMPLIFICATION_SURFACES,
    releaseCriticalRubricCopyScreens: RUBRIC_COPY_TRACEABILITY_RELEASE_CRITICAL_SCREENS,
    requiredRubricCopyEntries: RUBRIC_COPY_TRACEABILITY_REQUIRED_COPY_ENTRIES,
    requiredRubricClauseIds: RUBRIC_COPY_TRACEABILITY_REQUIRED_CLAUSES,
    requiredNoFeatureLossChecklist: UX_NO_FEATURE_LOSS_KEYS,
    requiredHiddenFieldClasses: UX_HIDDEN_FIELD_CLASSES,
    policy: {
      taskFirstRule:
        "Enabled user-facing screens must show task-first plain-language copy while preserving exact LMCA rubric semantics and one-click Appendix-F anchors.",
      noFeatureLossRule:
        "Simplified screens must retain every applicable score field, safe-decline/source-recognition path, issue report, verification/adjudication control, data-governance action, protected-label warning, audit/provenance capture, and release-governance action.",
      screenStateRule:
        "Rater/adjudicator/release-review/admin screens must render from sanitized server-derived ScreenStatePayload allowlists, not client-side inference from raw rows.",
    },
    activePolicy,
    policyRows: [seedPolicy, ...submittedPolicyRows],
    reviewRows: [...seedReviewRows, ...submittedReviewRows],
    screenStateRows: [...seedScreenStateRows, ...submittedScreenStateRows],
    screenFeatureParityCheckRows: [...seedFeatureParityRows, ...submittedFeatureParityRows],
    simplifiedCopyPreviewRows: [...seedCopyPreviewRows, ...submittedCopyPreviewRows],
    rubricCopyTraceabilityMapRows: [...seedTraceabilityRows, ...submittedTraceabilityRows],
    surfaceRows,
    counts: {
      submittedPolicyCount: submittedPolicyRows.length,
      submittedReviewCount: submittedReviewRows.length,
      submittedScreenStateCount: submittedScreenStateRows.length,
      submittedFeatureParityCheckCount: submittedFeatureParityRows.length,
      submittedSimplifiedCopyPreviewCount: submittedCopyPreviewRows.length,
      submittedRubricCopyTraceabilityMapCount: submittedTraceabilityRows.length,
      passingSurfaceCount: surfaceRows.filter((row) => row.status === "ux_surface_simplification_gate_passed").length,
      reviewSectionCount: reviewSections.length,
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "ux_simplification_review_required"
      : submittedEvidenceComplete
        ? "submitted_ux_simplification_evidence_complete"
        : "seed_ux_simplification_policy_complete",
  };
}

function normalizeUXSimplificationPolicy(policy, policySource) {
  const id = policy?.id ?? policy?.policyId;
  if (!id) return null;
  const enabledSurfaces = normalizeStringArray(policy.enabledSurfaces ?? policy.surfaces);
  const coveredRoles = normalizeStringArray(policy.coveredRoles);
  const coveredLaneClasses = normalizeStringArray(policy.coveredLaneClasses);
  const coveredSplitClasses = normalizeStringArray(policy.coveredSplitClasses);
  const localeSet = normalizeStringArray(policy.localeSet ?? policy.locales);
  const requiredAlwaysVisibleControls = normalizeStringArray(policy.requiredAlwaysVisibleControls);
  const requiredOneClickAccessibleControls = normalizeStringArray(policy.requiredOneClickAccessibleControls);
  const noFeatureLossChecklist = normalizeStringArray(policy.noFeatureLossChecklist ?? policy.featureReachabilityChecklist);
  const associatedCopyBundleIds = normalizeStringArray(policy.associatedCopyBundleIds ?? policy.copyBundleIds);
  const associatedCopyBundleHashes = normalizeStringArray(policy.associatedCopyBundleHashes ?? policy.copyBundleHashes);
  const missingSurfaces = UX_SIMPLIFICATION_SURFACES.filter((surface) => !enabledSurfaces.includes(surface));
  const missingNoFeatureLossKeys = UX_NO_FEATURE_LOSS_KEYS.filter((key) => !noFeatureLossChecklist.includes(key));
  const missingAlwaysVisibleControls = UX_REQUIRED_ALWAYS_VISIBLE_CONTROLS.filter((control) => !requiredAlwaysVisibleControls.includes(control));
  const missingOneClickAccessibleControls = UX_REQUIRED_ONE_CLICK_ACCESSIBLE_CONTROLS.filter((control) => !requiredOneClickAccessibleControls.includes(control));
  const reviewReasons = [
    requiredPromptFieldReason("policyVersion", policy.policyVersion ?? policy.version),
    missingSurfaces.length ? `enabledSurfaces:${missingSurfaces.join(",")}` : null,
    requiredPromptFieldReason("coveredRoles", coveredRoles),
    requiredPromptFieldReason("coveredLaneClasses", coveredLaneClasses),
    requiredPromptFieldReason("coveredSplitClasses", coveredSplitClasses),
    requiredPromptFieldReason("localeSet", localeSet),
    missingNoFeatureLossKeys.length ? `noFeatureLossChecklist:${missingNoFeatureLossKeys.join(",")}` : null,
    policy.taskFirstCopyRequired === true ? null : "taskFirstCopyRequired",
    policy.progressiveDisclosureRequired === true ? null : "progressiveDisclosureRequired",
    policy.glossarySupportRequired === true ? null : "glossarySupportRequired",
    policy.serverDerivedScreenStateRequired === true ? null : "serverDerivedScreenStateRequired",
    policy.exactRubricSemanticsPreserved === true ? null : "exactRubricSemanticsPreserved",
    hasPlainObject(policy.taskFirstLayoutRules) ? null : "taskFirstLayoutRules",
    hasPlainObject(policy.plainLanguageCopyRules) ? null : "plainLanguageCopyRules",
    hasPlainObject(policy.glossaryTooltipPolicy) ? null : "glossaryTooltipPolicy",
    hasPlainObject(policy.progressiveDisclosureMapRequirements) ? null : "progressiveDisclosureMapRequirements",
    missingAlwaysVisibleControls.length ? `requiredAlwaysVisibleControls:${missingAlwaysVisibleControls.join(",")}` : null,
    missingOneClickAccessibleControls.length ? `requiredOneClickAccessibleControls:${missingOneClickAccessibleControls.join(",")}` : null,
    String(policy.appendixFAnchorAccess ?? "").includes("one_click") ? null : "appendixFAnchorAccess",
    policyMentions(policy.protectedSplitVariantPolicy, ["block", "quarantine"]) ? null : "protectedSplitVariantPolicy",
    policyMentions(policy.hiddenMetadataLeakagePolicy, ["forbid", "hidden"]) ? null : "hiddenMetadataLeakagePolicy",
    hasPlainObject(policy.exactRubricTermPreservationRules) ? null : "exactRubricTermPreservationRules",
    hasPlainObject(policy.prohibitedSimplifications) ? null : "prohibitedSimplifications",
    hasPlainObject(policy.protectedSplitEligibility) ? null : "protectedSplitEligibility",
    requiredPromptFieldReason("associatedCopyBundleIds", associatedCopyBundleIds),
    requiredPromptFieldReason("associatedCopyBundleHashes", associatedCopyBundleHashes),
    requiredPromptFieldReason("createdBy", policy.createdBy),
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
    requiredPromptFieldReason("timestamp", policy.timestamp),
  ].filter(Boolean);
  return {
    id,
    policySource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    enabledSurfaces,
    coveredRoles,
    coveredLaneClasses,
    coveredSplitClasses,
    localeSet,
    noFeatureLossChecklist,
    associatedCopyBundleIds,
    associatedCopyBundleHashes,
    missingSurfaces,
    missingNoFeatureLossKeys,
    missingAlwaysVisibleControls,
    missingOneClickAccessibleControls,
    taskFirstCopyRequired: policy.taskFirstCopyRequired === true,
    progressiveDisclosureRequired: policy.progressiveDisclosureRequired === true,
    glossarySupportRequired: policy.glossarySupportRequired === true,
    serverDerivedScreenStateRequired: policy.serverDerivedScreenStateRequired === true,
    exactRubricSemanticsPreserved: policy.exactRubricSemanticsPreserved === true,
    taskFirstLayoutRules: policy.taskFirstLayoutRules ?? null,
    plainLanguageCopyRules: policy.plainLanguageCopyRules ?? null,
    glossaryTooltipPolicy: policy.glossaryTooltipPolicy ?? null,
    progressiveDisclosureMapRequirements: policy.progressiveDisclosureMapRequirements ?? null,
    requiredAlwaysVisibleControls,
    requiredOneClickAccessibleControls,
    appendixFAnchorAccess: policy.appendixFAnchorAccess ?? null,
    protectedSplitVariantPolicy: policy.protectedSplitVariantPolicy ?? null,
    hiddenMetadataLeakagePolicy: policy.hiddenMetadataLeakagePolicy ?? null,
    exactRubricTermPreservationRules: policy.exactRubricTermPreservationRules ?? null,
    prohibitedSimplifications: policy.prohibitedSimplifications ?? null,
    protectedSplitEligibility: policy.protectedSplitEligibility ?? null,
    createdBy: policy.createdBy ?? null,
    frozenAt: policy.frozenAt ?? null,
    timestamp: policy.timestamp ?? null,
    reviewReasons,
    status: reviewReasons.length
      ? "ux_simplification_policy_review_required"
      : policySource === "submitted_workflow_ux_simplification_policy"
        ? "submitted_ux_simplification_policy_complete"
        : "seed_ux_simplification_policy_complete",
  };
}

function normalizeUXSimplificationReview(review, activePolicyId, reviewSource) {
  const id = review?.id ?? review?.reviewId;
  if (!id) return null;
  const reviewedSurfaces = normalizeStringArray(review.reviewedSurfaces ?? review.surfaces);
  const screenStateIds = normalizeStringArray(review.screenStateIds);
  const screenSetIds = normalizeStringArray(review.screenSetIds);
  const workflowProfileIds = normalizeStringArray(review.workflowProfileIds);
  const reviewedLocaleSet = normalizeStringArray(review.reviewedLocaleSet ?? review.locales);
  const noFeatureLossChecklist = normalizeStringArray(review.noFeatureLossChecklist ?? review.featureReachabilityChecklist);
  const accessibilityReadabilityLinkage = hasPlainObject(review.accessibilityReadabilityLinkage)
    ? review.accessibilityReadabilityLinkage
    : null;
  const missingSurfaces = UX_SIMPLIFICATION_SURFACES.filter((surface) => !reviewedSurfaces.includes(surface));
  const missingNoFeatureLossKeys = UX_NO_FEATURE_LOSS_KEYS.filter((key) => !noFeatureLossChecklist.includes(key));
  const reviewReasons = [
    review.policyId === activePolicyId ? null : "policyId",
    screenStateIds.length || screenSetIds.length ? null : "screenStateIds_or_screenSetIds",
    requiredPromptFieldReason("workflowProfileIds", workflowProfileIds),
    requiredPromptFieldReason("reviewedLocaleSet", reviewedLocaleSet),
    review.reviewStatus === "passed" ? null : "reviewStatus",
    missingSurfaces.length ? `reviewedSurfaces:${missingSurfaces.join(",")}` : null,
    missingNoFeatureLossKeys.length ? `noFeatureLossChecklist:${missingNoFeatureLossKeys.join(",")}` : null,
    hasPlainObject(review.featureParityChecklistResults) ? null : "featureParityChecklistResults",
    hasPlainObject(review.requiredControlDiscoverabilityResults) ? null : "requiredControlDiscoverabilityResults",
    review.rubricSemanticsPreservationResult?.status === "passed" ? null : "rubricSemanticsPreservationResult",
    review.blindingProtectedLabelLeakageResult?.status === "passed" ? null : "blindingProtectedLabelLeakageResult",
    accessibilityReadabilityLinkage ? null : "accessibilityReadabilityLinkage",
    accessibilityReadabilityLinkage?.accessibilityConformanceReportId ? null : "accessibilityReadabilityLinkage.accessibilityConformanceReportId",
    accessibilityReadabilityLinkage?.readabilityStatus === "passed" ? null : "accessibilityReadabilityLinkage.readabilityStatus",
    requiredPromptFieldReason("userComprehensionOrExpertReviewNotes", review.userComprehensionOrExpertReviewNotes),
    hasPlainObject(review.blockersAndMitigations) ? null : "blockersAndMitigations",
    review.promotionDecision === "promote" ? null : "promotionDecision",
    requiredPromptFieldReason("reviewer", review.reviewer),
    requiredPromptFieldReason("timestamp", review.timestamp),
    review.exactRubricSemanticsPreserved === true ? null : "exactRubricSemanticsPreserved",
    review.appendixFAnchorAccessVerified === true ? null : "appendixFAnchorAccessVerified",
    review.serverDerivedScreenStateVerified === true ? null : "serverDerivedScreenStateVerified",
    review.protectedLeakageReviewPassed === true ? null : "protectedLeakageReviewPassed",
  ].filter(Boolean);
  return {
    id,
    reviewSource,
    policyId: review.policyId ?? null,
    screenStateIds,
    screenSetIds,
    workflowProfileIds,
    reviewedSurfaces,
    reviewedLocaleSet,
    reviewStatus: review.reviewStatus ?? null,
    reviewerRole: review.reviewerRole ?? null,
    noFeatureLossChecklist,
    missingSurfaces,
    missingNoFeatureLossKeys,
    featureParityChecklistResults: review.featureParityChecklistResults ?? null,
    requiredControlDiscoverabilityResults: review.requiredControlDiscoverabilityResults ?? null,
    rubricSemanticsPreservationResult: review.rubricSemanticsPreservationResult ?? null,
    blindingProtectedLabelLeakageResult: review.blindingProtectedLabelLeakageResult ?? null,
    accessibilityReadabilityLinkage,
    userComprehensionOrExpertReviewNotes: review.userComprehensionOrExpertReviewNotes ?? null,
    blockersAndMitigations: review.blockersAndMitigations ?? null,
    promotionDecision: review.promotionDecision ?? null,
    reviewer: review.reviewer ?? null,
    timestamp: review.timestamp ?? null,
    exactRubricSemanticsPreserved: review.exactRubricSemanticsPreserved === true,
    appendixFAnchorAccessVerified: review.appendixFAnchorAccessVerified === true,
    serverDerivedScreenStateVerified: review.serverDerivedScreenStateVerified === true,
    protectedLeakageReviewPassed: review.protectedLeakageReviewPassed === true,
    reviewReasons,
    status: reviewReasons.length
      ? "ux_simplification_review_incomplete"
      : reviewSource === "submitted_workflow_ux_simplification_review"
        ? "submitted_ux_simplification_review_passed"
        : "seed_ux_simplification_review_passed",
  };
}

function normalizeScreenStatePayload(payload, payloadSourceLabel) {
  const id = payload?.id ?? payload?.screenStateId;
  if (!id) return null;
  const surface = payload.surface ?? payload.screenSurface ?? null;
  const visibleFieldAllowlist = normalizeStringArray(payload.visibleFieldAllowlist);
  const enabledActionAllowlist = normalizeStringArray(payload.enabledActionAllowlist);
  const requiredControlKeys = normalizeStringArray(payload.requiredControlKeys ?? payload.applicableControlKeys);
  const optionalPanelKeys = normalizeStringArray(payload.optionalPanelKeys);
  const hiddenFieldClasses = normalizeStringArray(payload.hiddenFieldClasses);
  const requiredControls = UX_SCREEN_CONTROL_REQUIREMENTS[surface] ?? [];
  const availableControls = new Set([...enabledActionAllowlist, ...requiredControlKeys]);
  const missingControls = requiredControls.filter((control) => !availableControls.has(control));
  const missingHiddenFieldClasses = UX_HIDDEN_FIELD_CLASSES.filter((fieldClass) => !hiddenFieldClasses.includes(fieldClass));
  const forbiddenVisibleFields = visibleFieldAllowlist.filter((field) => visibleFieldIsForbidden(field));
  const policyVersionProvenance = payload.policyVersionProvenance && typeof payload.policyVersionProvenance === "object" ? payload.policyVersionProvenance : {};
  const requiredOptionalControlMap = hasPlainObject(payload.requiredOptionalControlMap) ? payload.requiredOptionalControlMap : null;
  const protectedGoldBenchmarkDisclosureState = hasPlainObject(payload.protectedGoldBenchmarkDisclosureState)
    ? payload.protectedGoldBenchmarkDisclosureState
    : null;
  const requiredOptionalControlMapControls = normalizeStringArray(requiredOptionalControlMap?.requiredControls);
  const optionalPanelMapKeys = normalizeStringArray(requiredOptionalControlMap?.optionalPanels);
  const missingRequiredOptionalControlMapControls = requiredControls.filter((control) => !requiredOptionalControlMapControls.includes(control));
  const disclosureStateReasons = [
    protectedGoldBenchmarkDisclosureState?.benchmarkMembership === "not_disclosed" ? null : "protectedGoldBenchmarkDisclosureState.benchmarkMembership",
    protectedGoldBenchmarkDisclosureState?.goldAnswer === "not_disclosed" ? null : "protectedGoldBenchmarkDisclosureState.goldAnswer",
    protectedGoldBenchmarkDisclosureState?.protectedSplitStatus === "not_disclosed" ? null : "protectedGoldBenchmarkDisclosureState.protectedSplitStatus",
  ].filter(Boolean);
  const requiredPolicyProvenanceFields = [
    "uxSimplificationPolicyId",
    "visibilityPolicyId",
    "workflowProfileId",
    "assistPolicyId",
    "uiExperimentPolicyId",
    "rubricLintConfigId",
  ];
  const missingPolicyVersionProvenanceFields = requiredPolicyProvenanceFields.filter((field) => !policyVersionProvenance[field]);
  const reviewReasons = [
    UX_SIMPLIFICATION_SURFACES.includes(surface) ? null : "surface",
    requiredPromptFieldReason("role", payload.role ?? payload.actorRole),
    payload.payloadSource === "server_derived" ? null : "payloadSource",
    requiredPromptFieldReason("schemaVersion", payload.schemaVersion),
    requiredPromptFieldReason("outputSchemaVersion", payload.outputSchemaVersion),
    requiredPromptFieldReason("taskStatement", payload.taskStatement),
    requiredPromptFieldReason("primaryNextAction", payload.primaryNextAction),
    requiredPromptFieldReason("submissionConsequenceSummary", payload.submissionConsequenceSummary),
    requiredPromptFieldReason("progressiveDisclosureState", payload.progressiveDisclosureState),
    requiredPromptFieldReason("createdAt", payload.createdAt),
    visibleFieldAllowlist.length ? null : "visibleFieldAllowlist",
    enabledActionAllowlist.length ? null : "enabledActionAllowlist",
    requiredControlKeys.length ? null : "requiredControlKeys",
    optionalPanelKeys.length ? null : "optionalPanelKeys",
    requiredOptionalControlMap ? null : "requiredOptionalControlMap",
    requiredOptionalControlMap && !requiredOptionalControlMapControls.length ? "requiredOptionalControlMap.requiredControls" : null,
    requiredOptionalControlMap && !optionalPanelMapKeys.length ? "requiredOptionalControlMap.optionalPanels" : null,
    missingRequiredOptionalControlMapControls.length ? `requiredOptionalControlMap.requiredControls:${missingRequiredOptionalControlMapControls.join(",")}` : null,
    protectedGoldBenchmarkDisclosureState ? null : "protectedGoldBenchmarkDisclosureState",
    ...disclosureStateReasons,
    missingControls.length ? `enabledActionAllowlist:${missingControls.join(",")}` : null,
    missingHiddenFieldClasses.length ? `hiddenFieldClasses:${missingHiddenFieldClasses.join(",")}` : null,
    forbiddenVisibleFields.length ? `visibleFieldAllowlist_hidden:${forbiddenVisibleFields.join(",")}` : null,
    payload.rejectedUnknownKeys === true || payload.extraKeyRejection === true ? null : "rejectedUnknownKeys",
    payload.sanitized === true ? null : "sanitized",
    ...missingPolicyVersionProvenanceFields.map((field) => `policyVersionProvenance.${field}`),
  ].filter(Boolean);
  return {
    id,
    payloadSourceLabel,
    payloadSource: payload.payloadSource ?? null,
    surface,
    role: payload.role ?? payload.actorRole ?? null,
    schemaVersion: payload.schemaVersion ?? null,
    outputSchemaVersion: payload.outputSchemaVersion ?? null,
    taskStatement: payload.taskStatement ?? null,
    primaryNextAction: payload.primaryNextAction ?? null,
    submissionConsequenceSummary: payload.submissionConsequenceSummary ?? null,
    progressiveDisclosureState: payload.progressiveDisclosureState ?? null,
    createdAt: payload.createdAt ?? null,
    policyId: payload.policyId ?? policyVersionProvenance.uxSimplificationPolicyId ?? null,
    policyVersionProvenance,
    visibleFieldAllowlist,
    enabledActionAllowlist,
    requiredControlKeys,
    optionalPanelKeys,
    requiredOptionalControlMap,
    requiredOptionalControlMapControls,
    optionalPanelMapKeys,
    missingRequiredOptionalControlMapControls,
    protectedGoldBenchmarkDisclosureState,
    disclosureStateReasons,
    hiddenFieldClasses,
    missingControls,
    missingHiddenFieldClasses,
    missingPolicyVersionProvenanceFields,
    forbiddenVisibleFields,
    rejectedUnknownKeys: payload.rejectedUnknownKeys === true || payload.extraKeyRejection === true,
    sanitized: payload.sanitized === true,
    reviewReasons,
    status: reviewReasons.length
      ? "screen_state_payload_review_required"
      : payloadSourceLabel === "submitted_workflow_screen_state_payload"
        ? "submitted_screen_state_payload_sanitized"
        : "seed_screen_state_payload_sanitized",
  };
}

function normalizeUXScreenFeatureParityCheck(check, activePolicyId, rowSource) {
  const id = check?.id ?? check?.checkId;
  if (!id) return null;
  const screenId = check.screenId ?? check.surface ?? null;
  const requiredControls = UX_SCREEN_CONTROL_REQUIREMENTS[screenId] ?? [];
  const requiredControlResults = hasPlainObject(check.requiredControlResults) ? check.requiredControlResults : null;
  const featureParityChecklistResults = hasPlainObject(check.featureParityChecklistResults) ? check.featureParityChecklistResults : null;
  const missingRequiredControls = requiredControls.filter((control) => !requiredControlResults?.[control]);
  const unreachableRequiredControls = requiredControls.filter((control) => requiredControlResults?.[control] && !String(requiredControlResults[control]).includes("reachable"));
  const reviewReasons = [
    UX_SIMPLIFICATION_SURFACES.includes(screenId) ? null : "screenId",
    check.uxSimplificationPolicyId === activePolicyId ? null : "uxSimplificationPolicyId",
    requiredPromptFieldReason("workflowProfileId", check.workflowProfileId),
    requiredControlResults ? null : "requiredControlResults",
    featureParityChecklistResults ? null : "featureParityChecklistResults",
    check.noFeatureLoss === true ? null : "noFeatureLoss",
    featureParityChecklistResults?.no_feature_loss === "passed" ? null : "featureParityChecklistResults.no_feature_loss",
    featureParityChecklistResults?.required_controls_reachable === "passed" ? null : "featureParityChecklistResults.required_controls_reachable",
    requiredPromptFieldReason("checkedBy", check.checkedBy),
    requiredPromptFieldReason("checkedAt", check.checkedAt),
    ...missingRequiredControls.map((control) => `requiredControlResults.${control}`),
    ...unreachableRequiredControls.map((control) => `requiredControlResults.${control}.reachable`),
  ].filter(Boolean);
  return {
    ...check,
    id,
    rowSource,
    screenId,
    requiredControlResults,
    featureParityChecklistResults,
    missingRequiredControls,
    unreachableRequiredControls,
    reviewReasons,
    status: reviewReasons.length ? "screen_feature_parity_check_review_required" : "screen_feature_parity_check_complete",
  };
}

function normalizeUXSimplifiedCopyPreview(preview, rowSource) {
  const id = preview?.id ?? preview?.previewId;
  if (!id) return null;
  const screenId = preview.screenId ?? preview.surface ?? null;
  const glossaryTooltipIds = normalizeStringArray(preview.glossaryTooltipIds);
  const missingGlossaryTerms = UX_SIMPLIFIED_COPY_REQUIRED_GLOSSARY_TERMS.filter((term) => !glossaryTooltipIds.includes(term));
  const protectedSplitVariantDisposition = preview.protectedSplitVariantDisposition ?? null;
  const reviewReasons = [
    UX_SIMPLIFICATION_SURFACES.includes(screenId) ? null : "screenId",
    requiredPromptFieldReason("copyBundleId", preview.copyBundleId),
    missingGlossaryTerms.length ? `glossaryTooltipIds:${missingGlossaryTerms.join(",")}` : null,
    preview.exactRubricTermPreservation === true ? null : "exactRubricTermPreservation",
    preview.hiddenFieldLeakageCheck === "passed" ? null : "hiddenFieldLeakageCheck",
    requiredPromptFieldReason("uiExperimentPolicyId", preview.uiExperimentPolicyId),
    requiredPromptFieldReason("raterInstructionRenderVersionId", preview.raterInstructionRenderVersionId),
    requiredPromptFieldReason("releaseConfigManifestId", preview.releaseConfigManifestId),
    UX_COPY_VARIANT_PROTECTED_SPLIT_DISPOSITIONS.has(protectedSplitVariantDisposition) ? null : "protectedSplitVariantDisposition",
    protectedSplitVariantDisposition === "quarantined_sensitivity_snapshot" && !preview.uiSensitivitySnapshotId
      ? "uiSensitivitySnapshotId"
      : null,
    requiredPromptFieldReason("reviewerId", preview.reviewerId),
    requiredPromptFieldReason("reviewedAt", preview.reviewedAt),
  ].filter(Boolean);
  return {
    ...preview,
    id,
    rowSource,
    screenId,
    glossaryTooltipIds,
    protectedSplitVariantDisposition,
    uiExperimentPolicyId: preview.uiExperimentPolicyId ?? null,
    raterInstructionRenderVersionId: preview.raterInstructionRenderVersionId ?? null,
    releaseConfigManifestId: preview.releaseConfigManifestId ?? null,
    uiSensitivitySnapshotId: preview.uiSensitivitySnapshotId ?? null,
    missingGlossaryTerms,
    reviewReasons,
    status: reviewReasons.length ? "simplified_copy_preview_review_required" : "simplified_copy_preview_complete",
  };
}

function normalizeRubricCopyTraceabilityMap(map, rowSource) {
  const id = map?.id ?? map?.rubricCopyTraceabilityMapId;
  if (!id) return null;
  const coveredScreenIds = normalizeStringArray(map.coveredScreenIds ?? map.screenIds);
  const simplifiedCopyEntryIds = normalizeStringArray(map.simplifiedCopyEntryIds ?? map.copyEntryIds);
  const mappedRubricClauseIds = normalizeStringArray(map.mappedRubricClauseIds ?? map.rubricClauseIds);
  const semanticDriftTestIds = normalizeStringArray(map.semanticDriftTestIds);
  const clauseMap = hasPlainObject(map.clauseMap) ? map.clauseMap : null;
  const missingScreens = RUBRIC_COPY_TRACEABILITY_RELEASE_CRITICAL_SCREENS.filter((screenId) => !coveredScreenIds.includes(screenId));
  const missingCopyEntries = RUBRIC_COPY_TRACEABILITY_REQUIRED_COPY_ENTRIES.filter((entryId) => !simplifiedCopyEntryIds.includes(entryId));
  const missingClauseIds = RUBRIC_COPY_TRACEABILITY_REQUIRED_CLAUSES.filter((clauseId) => !mappedRubricClauseIds.includes(clauseId));
  const missingClauseMapEntries = RUBRIC_COPY_TRACEABILITY_REQUIRED_COPY_ENTRIES.filter((entryId) => !clauseMap?.[entryId]);
  const invalidClauseMapEntries = Object.entries(clauseMap ?? {})
    .filter(([entryId, clauseId]) =>
      RUBRIC_COPY_TRACEABILITY_REQUIRED_COPY_ENTRIES.includes(entryId) && !RUBRIC_COPY_TRACEABILITY_REQUIRED_CLAUSES.includes(clauseId),
    )
    .map(([entryId]) => entryId);
  const reviewReasons = [
    requiredPromptFieldReason("releaseId", map.releaseId),
    requiredPromptFieldReason("mapVersion", map.mapVersion ?? map.version),
    requiredPromptFieldReason("rubricVersion", map.rubricVersion),
    requiredPromptFieldReason("copyBundleId", map.copyBundleId),
    missingScreens.length ? `coveredScreenIds:${missingScreens.join(",")}` : null,
    missingCopyEntries.length ? `simplifiedCopyEntryIds:${missingCopyEntries.join(",")}` : null,
    missingClauseIds.length ? `mappedRubricClauseIds:${missingClauseIds.join(",")}` : null,
    clauseMap ? null : "clauseMap",
    missingClauseMapEntries.length ? `clauseMap:${missingClauseMapEntries.join(",")}` : null,
    invalidClauseMapEntries.length ? `clauseMap.invalid:${invalidClauseMapEntries.join(",")}` : null,
    semanticDriftTestIds.length ? null : "semanticDriftTestIds",
    map.semanticDriftTestStatus === "passed" ? null : "semanticDriftTestStatus",
    map.semanticDriftFailureBlocker === true ? null : "semanticDriftFailureBlocker",
    map.exactRubricClauseMapping === true ? null : "exactRubricClauseMapping",
    policyMentions(map.appendixFAnchorAccess, ["one_click"]) ? null : "appendixFAnchorAccess",
    map.hiddenFieldLeakageCheck === "passed" ? null : "hiddenFieldLeakageCheck",
    map.releaseCriticalUseStatus === "frozen_for_release_critical_screens" ? null : "releaseCriticalUseStatus",
    requiredPromptFieldReason("releaseConfigManifestId", map.releaseConfigManifestId),
    requiredPromptFieldReason("reviewerId", map.reviewerId),
    requiredPromptFieldReason("reviewedAt", map.reviewedAt),
    requiredPromptFieldReason("frozenAt", map.frozenAt),
  ].filter(Boolean);
  return {
    ...map,
    id,
    rowSource,
    releaseId: map.releaseId ?? null,
    mapVersion: map.mapVersion ?? map.version ?? null,
    rubricVersion: map.rubricVersion ?? null,
    copyBundleId: map.copyBundleId ?? null,
    coveredScreenIds,
    simplifiedCopyEntryIds,
    mappedRubricClauseIds,
    clauseMap: clauseMap ?? null,
    semanticDriftTestIds,
    semanticDriftTestStatus: map.semanticDriftTestStatus ?? null,
    missingScreens,
    missingCopyEntries,
    missingClauseIds,
    missingClauseMapEntries,
    invalidClauseMapEntries,
    reviewReasons,
    status: reviewReasons.length ? "rubric_copy_traceability_review_required" : "rubric_copy_traceability_complete",
  };
}

function uxSimplificationSurfaceEvidenceRow(surface, activePolicy, reviewRows, screenStateRows, featureParityRows, copyPreviewRows, traceabilityRows) {
  const policyCoversSurface = activePolicy.enabledSurfaces.includes(surface) && activePolicy.reviewReasons.length === 0;
  const reviewCoversSurface = reviewRows.some((row) => row.reviewedSurfaces.includes(surface) && row.reviewReasons.length === 0);
  const screenStateCoversSurface = screenStateRows.some((row) => row.surface === surface && row.reviewReasons.length === 0);
  const featureParityCoversSurface = featureParityRows.some((row) => row.screenId === surface && row.reviewReasons.length === 0);
  const simplifiedCopyCoversSurface = copyPreviewRows.some((row) => row.screenId === surface && row.reviewReasons.length === 0);
  const rubricCopyTraceabilityRequired = RUBRIC_COPY_TRACEABILITY_RELEASE_CRITICAL_SCREENS.includes(surface);
  const rubricCopyTraceabilityCoversSurface =
    !rubricCopyTraceabilityRequired ||
    traceabilityRows.some((row) => row.coveredScreenIds.includes(surface) && row.reviewReasons.length === 0);
  const status =
    policyCoversSurface &&
    reviewCoversSurface &&
    screenStateCoversSurface &&
    featureParityCoversSurface &&
    simplifiedCopyCoversSurface &&
    rubricCopyTraceabilityCoversSurface
      ? "ux_surface_simplification_gate_passed"
      : !policyCoversSurface
        ? "ux_surface_missing_policy"
        : !reviewCoversSurface
          ? "ux_surface_missing_review"
          : !screenStateCoversSurface
            ? "ux_surface_missing_screen_state"
            : !featureParityCoversSurface
            ? "ux_surface_missing_feature_parity_check"
              : !simplifiedCopyCoversSurface
                ? "ux_surface_missing_simplified_copy_preview"
                : "ux_surface_missing_rubric_copy_traceability_map";
  return {
    surface,
    policyId: activePolicy.id,
    policyCoversSurface,
    reviewCoversSurface,
    screenStateCoversSurface,
    featureParityCoversSurface,
    simplifiedCopyCoversSurface,
    rubricCopyTraceabilityRequired,
    rubricCopyTraceabilityCoversSurface,
    requiredControls: UX_SCREEN_CONTROL_REQUIREMENTS[surface] ?? [],
    status,
  };
}

function normalizeStringArray(value) {
  if (Array.isArray(value)) return value.filter((item) => typeof item === "string" && item).map((item) => item.trim());
  if (typeof value === "string" && value) return value.split(",").map((item) => item.trim()).filter(Boolean);
  return [];
}

function uniqueRowsById(rows) {
  return [...new Map(rows.filter((row) => row?.id).map((row) => [row.id, row])).values()];
}

function policyMentions(value, fragments) {
  const normalized = String(value ?? "").toLowerCase();
  return fragments.every((fragment) => normalized.includes(fragment));
}

function policyMentionsAny(value, fragments) {
  const normalized = String(value ?? "").toLowerCase();
  return fragments.some((fragment) => normalized.includes(fragment));
}

function visibleFieldIsForbidden(field) {
  const normalized = String(field).replace(/[^a-z0-9]/gi, "").toLowerCase();
  return UX_FORBIDDEN_VISIBLE_FIELD_FRAGMENTS.some((fragment) => normalized.includes(fragment));
}

