function defaultAccessibilityConformanceReport(releaseId) {
  return {
    id: `accessibility-conformance-${releaseId}`,
    workflowProfileIds: [`rating-workflow-profile-${releaseId}`],
    screenIds: ACCESSIBILITY_REQUIRED_SURFACES,
    raterInstructionRenderVersionIds: [`rater-instruction-render-${releaseId}`],
    uiExperimentPolicyId: `ui-experiment-policy-${releaseId}`,
    uxSimplificationPolicyId: `ux-simplification-policy-${releaseId}`,
    testedLocaleSet: ["en-US"],
    checksPassed: ACCESSIBILITY_REQUIRED_CHECKS,
    readabilityReviewStatus: "passed",
    simplificationReadabilityInteractionNotes: "Plain-language summaries preserve Appendix-F anchors and required controls.",
    failures: [],
    mitigations: [],
    nonStaffPromotionBlocker: false,
    reviewer: "seed-accessibility-reviewer",
    timestamp: "2026-10-01T00:00:00.000Z",
  };
}

export function buildPolicyBundleEvidenceReport(releaseId, options = {}) {
  const submittedVisibilityRows = (options.visibilityPolicies ?? []).map((policy) => normalizeVisibilityPolicy(policy, "submitted_workflow_visibility_policy")).filter(Boolean);
  const submittedProfileRows = (options.ratingWorkflowProfiles ?? []).map((profile) => normalizeRatingWorkflowProfile(profile, "submitted_workflow_rating_profile")).filter(Boolean);
  const submittedScoreExplanationRows = (options.scoreExplanationPolicies ?? [])
    .map((policy) => normalizeScoreExplanationPolicy(policy, "submitted_workflow_score_explanation_policy"))
    .filter(Boolean);
  const submittedEscalationRows = (options.ratingEscalationPolicies ?? [])
    .map((policy) => normalizeRatingEscalationPolicy(policy, "submitted_workflow_rating_escalation_policy"))
    .filter(Boolean);
  const submittedUiPolicyRows = (options.uiExperimentPolicies ?? []).map((policy) => normalizeUIExperimentPolicy(policy, "submitted_workflow_ui_experiment_policy")).filter(Boolean);
  const submittedAssistRows = (options.preSubmitAssistPolicies ?? []).map((policy) => normalizePreSubmitAssistPolicy(policy, "submitted_workflow_pre_submit_assist_policy")).filter(Boolean);
  const submittedAccessibilityRows = (options.accessibilityConformanceReports ?? [])
    .map((report) => normalizeAccessibilityConformanceReport(report, "submitted_workflow_accessibility_report"))
    .filter(Boolean);
  const seedVisibilityRows = [normalizeVisibilityPolicy(defaultVisibilityPolicy(releaseId), "seed_visibility_policy")];
  const seedProfileRows = [normalizeRatingWorkflowProfile(defaultRatingWorkflowProfile(releaseId), "seed_rating_workflow_profile")];
  const seedScoreExplanationRows = [normalizeScoreExplanationPolicy(defaultScoreExplanationPolicy(releaseId), "seed_score_explanation_policy")];
  const seedEscalationRows = [normalizeRatingEscalationPolicy(defaultRatingEscalationPolicy(releaseId), "seed_rating_escalation_policy")];
  const seedUiPolicyRows = [normalizeUIExperimentPolicy(defaultUIExperimentPolicy(releaseId), "seed_ui_experiment_policy")];
  const seedAssistRows = [normalizePreSubmitAssistPolicy(defaultPreSubmitAssistPolicy(releaseId), "seed_pre_submit_assist_policy")];
  const seedAccessibilityRows = [normalizeAccessibilityConformanceReport(defaultAccessibilityConformanceReport(releaseId), "seed_accessibility_conformance_report")];
  const gateGroups = [
    ["visibility_policy", submittedVisibilityRows.length ? submittedVisibilityRows : seedVisibilityRows],
    ["rating_workflow_profile", submittedProfileRows.length ? submittedProfileRows : seedProfileRows],
    ["score_explanation_policy", submittedScoreExplanationRows.length ? submittedScoreExplanationRows : seedScoreExplanationRows],
    ["rating_escalation_policy", submittedEscalationRows.length ? submittedEscalationRows : seedEscalationRows],
    ["ui_experiment_policy", submittedUiPolicyRows.length ? submittedUiPolicyRows : seedUiPolicyRows],
    ["pre_submit_assist_policy", submittedAssistRows.length ? submittedAssistRows : seedAssistRows],
    ["accessibility_conformance_report", submittedAccessibilityRows.length ? submittedAccessibilityRows : seedAccessibilityRows],
  ];
  const reviewSections = [
    ...submittedVisibilityRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "visibility_policy", artifactId: row.id, reason }))),
    ...submittedProfileRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "rating_workflow_profile", artifactId: row.id, reason }))),
    ...submittedScoreExplanationRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "score_explanation_policy", artifactId: row.id, reason }))),
    ...submittedEscalationRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "rating_escalation_policy", artifactId: row.id, reason }))),
    ...submittedUiPolicyRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "ui_experiment_policy", artifactId: row.id, reason }))),
    ...submittedAssistRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "pre_submit_assist_policy", artifactId: row.id, reason }))),
    ...submittedAccessibilityRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "accessibility_conformance_report", artifactId: row.id, reason }))),
    ...gateGroups
      .filter(([, rows]) => !rows.some((row) => row.reviewReasons.length === 0))
      .map(([artifactType]) => ({ artifactType, artifactId: artifactType, reason: "missing_complete_policy_artifact" })),
  ];
  const submittedEvidenceComplete =
    submittedVisibilityRows.length > 0 &&
    submittedProfileRows.length > 0 &&
    submittedScoreExplanationRows.length > 0 &&
    submittedEscalationRows.length > 0 &&
    submittedUiPolicyRows.length > 0 &&
    submittedAssistRows.length > 0 &&
    submittedAccessibilityRows.length > 0 &&
    reviewSections.length === 0;
  return {
    id: `policy-bundle-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    requiredFieldClasses: POLICY_BUNDLE_FIELD_CLASSES,
    requiredWorkflowTaskModes: RATING_WORKFLOW_TASK_MODES,
    protectedUiLaneClasses: PROTECTED_UI_LANE_CLASSES,
    blockedExperimentClasses: UI_EXPERIMENT_BLOCKED_CLASSES,
    prohibitedAssistInputs: PRE_SUBMIT_PROHIBITED_INPUTS,
    accessibilityRequiredSurfaces: ACCESSIBILITY_REQUIRED_SURFACES,
    accessibilityRequiredChecks: ACCESSIBILITY_REQUIRED_CHECKS,
    visibilityPolicyRows: [...seedVisibilityRows, ...submittedVisibilityRows],
    ratingWorkflowProfileRows: [...seedProfileRows, ...submittedProfileRows],
    scoreExplanationPolicyRows: [...seedScoreExplanationRows, ...submittedScoreExplanationRows],
    ratingEscalationPolicyRows: [...seedEscalationRows, ...submittedEscalationRows],
    uiExperimentPolicyRows: [...seedUiPolicyRows, ...submittedUiPolicyRows],
    preSubmitAssistPolicyRows: [...seedAssistRows, ...submittedAssistRows],
    accessibilityConformanceRows: [...seedAccessibilityRows, ...submittedAccessibilityRows],
    counts: {
      submittedVisibilityPolicyCount: submittedVisibilityRows.length,
      submittedRatingWorkflowProfileCount: submittedProfileRows.length,
      submittedScoreExplanationPolicyCount: submittedScoreExplanationRows.length,
      submittedRatingEscalationPolicyCount: submittedEscalationRows.length,
      submittedUiExperimentPolicyCount: submittedUiPolicyRows.length,
      submittedPreSubmitAssistPolicyCount: submittedAssistRows.length,
      submittedAccessibilityConformanceReportCount: submittedAccessibilityRows.length,
      completePolicyGroupCount: gateGroups.filter(([, rows]) => rows.some((row) => row.reviewReasons.length === 0)).length,
      reviewSectionCount: reviewSections.length,
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "policy_bundle_review_required"
      : submittedEvidenceComplete
        ? "submitted_policy_bundle_evidence_complete"
        : "seed_policy_bundle_evidence_complete",
  };
}

function normalizeVisibilityPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.visibilityPolicyId;
  if (!id) return null;
  const fieldClasses = normalizeStringArray(policy.fieldClasses);
  const missingFieldClasses = POLICY_BUNDLE_FIELD_CLASSES.filter((fieldClass) => !fieldClasses.includes(fieldClass));
  const reviewReasons = [
    requiredPromptFieldReason("policyVersion", policy.policyVersion ?? policy.version),
    normalizeStringArray(policy.roleClasses).length ? null : "roleClasses",
    normalizeStringArray(policy.workflowStates).length ? null : "workflowStates",
    missingFieldClasses.length ? `fieldClasses:${missingFieldClasses.join(",")}` : null,
    normalizeStringArray(policy.allowedReadActions).length ? null : "allowedReadActions",
    normalizeStringArray(policy.allowedWriteActions).length ? null : "allowedWriteActions",
    policyMentions(policy.sourceTagVisibilityRules, ["hide", "source"]) ? null : "sourceTagVisibilityRules",
    policyMentions(policy.benchmarkGoldModelPeerVisibilityRules, ["hide", "model", "peer"]) ? null : "benchmarkGoldModelPeerVisibilityRules",
    policy.backendEnforced === true ? null : "backendEnforced",
    policy.exposureLogRequired === true ? null : "exposureLogRequired",
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    fieldClasses,
    missingFieldClasses,
    roleClasses: normalizeStringArray(policy.roleClasses),
    workflowStates: normalizeStringArray(policy.workflowStates),
    allowedReadActions: normalizeStringArray(policy.allowedReadActions),
    allowedWriteActions: normalizeStringArray(policy.allowedWriteActions),
    backendEnforced: policy.backendEnforced === true,
    exposureLogRequired: policy.exposureLogRequired === true,
    reviewReasons,
    status: reviewReasons.length ? "visibility_policy_review_required" : "visibility_policy_complete",
  };
}

function normalizeRatingWorkflowProfile(profile, rowSource) {
  const id = profile?.id ?? profile?.workflowProfileId;
  if (!id) return null;
  const taskModesCovered = normalizeStringArray(profile.taskModesCovered ?? profile.assignmentTypesCovered);
  const requiredScoreFields = normalizeStringArray(profile.requiredScoreFields);
  const requiredConfidenceValues = normalizeStringArray(profile.requiredConfidenceValues);
  const optionalRationaleFields = normalizeStringArray(profile.optionalRationaleFields);
  const triggerRequiredRationaleFields = normalizeStringArray(profile.triggerRequiredRationaleFields);
  const requiredIssuePanels = normalizeStringArray(profile.requiredIssuePanels);
  const optionalIssuePanels = normalizeStringArray(profile.optionalIssuePanels);
  const disabledControls = normalizeStringArray(profile.disabledControls);
  const missingTaskModes = RATING_WORKFLOW_TASK_MODES.filter((mode) => !taskModesCovered.includes(mode));
  const missingScoreFields = RUBRIC_DIMENSIONS.filter((field) => !requiredScoreFields.includes(field));
  const missingConfidenceValues = SCORE_CONFIDENCE_LEVELS.filter((value) => !requiredConfidenceValues.includes(value));
  const missingOptionalRationaleFields = RATING_WORKFLOW_OPTIONAL_RATIONALE_FIELDS.filter((field) => !optionalRationaleFields.includes(field));
  const ordinaryOptionalTriggerFields = optionalRationaleFields.filter((field) => RATING_WORKFLOW_TRIGGER_REQUIRED_RATIONALE_FIELDS.includes(field));
  const missingTriggerRequiredRationaleFields = RATING_WORKFLOW_TRIGGER_REQUIRED_RATIONALE_FIELDS.filter((field) => !triggerRequiredRationaleFields.includes(field));
  const missingRequiredIssuePanels = RATING_WORKFLOW_REQUIRED_ISSUE_PANELS.filter((panel) => !requiredIssuePanels.includes(panel));
  const advancedPanelsRequiredForOrdinary = RATING_WORKFLOW_OPTIONAL_ISSUE_PANELS.filter((panel) => requiredIssuePanels.includes(panel));
  const missingOptionalIssuePanels = RATING_WORKFLOW_OPTIONAL_ISSUE_PANELS.filter((panel) => !optionalIssuePanels.includes(panel));
  const missingDisabledControls = RATING_WORKFLOW_DISABLED_CONTROLS.filter((control) => !disabledControls.includes(control));
  const reviewReasons = [
    requiredPromptFieldReason("profileVersion", profile.profileVersion ?? profile.version),
    missingTaskModes.length ? `taskModesCovered:${missingTaskModes.join(",")}` : null,
    missingScoreFields.length ? `requiredScoreFields:${missingScoreFields.join(",")}` : null,
    profile.requiredConfidenceJudgment === true ? null : "requiredConfidenceJudgment",
    missingConfidenceValues.length ? `requiredConfidenceValues:${missingConfidenceValues.join(",")}` : null,
    requiredPromptFieldReason("scoreExplanationPolicyId", profile.scoreExplanationPolicyId),
    missingOptionalRationaleFields.length ? `optionalRationaleFields:${missingOptionalRationaleFields.join(",")}` : null,
    ordinaryOptionalTriggerFields.length ? `optionalRationaleFields:unexpected_trigger_required:${ordinaryOptionalTriggerFields.join(",")}` : null,
    missingTriggerRequiredRationaleFields.length ? `triggerRequiredRationaleFields:${missingTriggerRequiredRationaleFields.join(",")}` : null,
    missingRequiredIssuePanels.length ? `requiredIssuePanels:${missingRequiredIssuePanels.join(",")}` : null,
    advancedPanelsRequiredForOrdinary.length ? `requiredIssuePanels:advanced_not_optional:${advancedPanelsRequiredForOrdinary.join(",")}` : null,
    missingOptionalIssuePanels.length ? `optionalIssuePanels:${missingOptionalIssuePanels.join(",")}` : null,
    missingDisabledControls.length ? `disabledControls:${missingDisabledControls.join(",")}` : null,
    profile.evidenceSpanRequirednessPolicy === RATING_WORKFLOW_EVIDENCE_SPAN_REQUIREDNESS_POLICY
      ? null
      : `evidenceSpanRequirednessPolicy:${RATING_WORKFLOW_EVIDENCE_SPAN_REQUIREDNESS_POLICY}`,
    profile.verificationWorkspaceRequirednessPolicy === RATING_WORKFLOW_VERIFICATION_WORKSPACE_REQUIREDNESS_POLICY
      ? null
      : `verificationWorkspaceRequirednessPolicy:${RATING_WORKFLOW_VERIFICATION_WORKSPACE_REQUIREDNESS_POLICY}`,
    profile.interpretationTargetMapRequirednessPolicy === RATING_WORKFLOW_INTERPRETATION_TARGET_MAP_REQUIREDNESS_POLICY
      ? null
      : `interpretationTargetMapRequirednessPolicy:${RATING_WORKFLOW_INTERPRETATION_TARGET_MAP_REQUIREDNESS_POLICY}`,
    profile.safeDeclineAvailable === true ? null : "safeDeclineAvailable",
    requiredPromptFieldReason("preSubmitLintPolicy", profile.preSubmitLintPolicy),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    profileVersion: profile.profileVersion ?? profile.version ?? null,
    taskModesCovered,
    missingTaskModes,
    requiredScoreFields,
    missingScoreFields,
    requiredConfidenceJudgment: profile.requiredConfidenceJudgment === true,
    requiredConfidenceValues,
    missingConfidenceValues,
    scoreExplanationPolicyId: profile.scoreExplanationPolicyId ?? null,
    optionalRationaleFields,
    missingOptionalRationaleFields,
    triggerRequiredRationaleFields,
    missingTriggerRequiredRationaleFields,
    requiredIssuePanels,
    missingRequiredIssuePanels,
    optionalIssuePanels,
    missingOptionalIssuePanels,
    disabledControls,
    missingDisabledControls,
    evidenceSpanRequirednessPolicy: profile.evidenceSpanRequirednessPolicy ?? null,
    verificationWorkspaceRequirednessPolicy: profile.verificationWorkspaceRequirednessPolicy ?? null,
    interpretationTargetMapRequirednessPolicy: profile.interpretationTargetMapRequirednessPolicy ?? null,
    safeDeclineAvailable: profile.safeDeclineAvailable === true,
    preSubmitLintPolicy: profile.preSubmitLintPolicy ?? null,
    reviewReasons,
    status: reviewReasons.length ? "rating_workflow_profile_review_required" : "rating_workflow_profile_complete",
  };
}

function normalizeScoreExplanationPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.scoreExplanationPolicyId;
  if (!id) return null;
  const ordinaryRequiredFields = normalizeStringArray(policy.ordinaryRequiredFields);
  const optionalFields = normalizeStringArray(policy.optionalFields);
  const triggerList = normalizeStringArray(policy.triggerList ?? policy.triggers);
  const coveredWorkflowSplitClasses = normalizeStringArray(policy.coveredWorkflowSplitClasses);
  const inconsistencyRules = normalizeStringArray(policy.inconsistencyRules);
  const missingTriggers = SCORE_EXPLANATION_TRIGGER_RULES.filter((trigger) => !triggerList.includes(trigger));
  const unexpectedTriggers = triggerList.filter((trigger) => !SCORE_EXPLANATION_TRIGGER_RULES.includes(trigger));
  const missingInconsistencyRules = SCORE_EXPLANATION_INCONSISTENCY_RULES.filter((rule) => !inconsistencyRules.includes(rule));
  const unexpectedInconsistencyRules = inconsistencyRules.filter((rule) => !SCORE_EXPLANATION_INCONSISTENCY_RULES.includes(rule));
  const missingRequiredFields = SCORE_EXPLANATION_ORDINARY_REQUIRED_FIELDS.filter((field) => !ordinaryRequiredFields.includes(field));
  const unexpectedOrdinaryRequiredFields = ordinaryRequiredFields.filter((field) => !SCORE_EXPLANATION_ORDINARY_REQUIRED_FIELDS.includes(field));
  const missingOptionalFields = SCORE_EXPLANATION_OPTIONAL_FIELDS.filter((field) => !optionalFields.includes(field));
  const unexpectedOptionalFields = optionalFields.filter((field) => !SCORE_EXPLANATION_OPTIONAL_FIELDS.includes(field));
  const reviewReasons = [
    requiredPromptFieldReason("policyVersion", policy.policyVersion ?? policy.version),
    coveredWorkflowSplitClasses.length ? null : "coveredWorkflowSplitClasses",
    missingRequiredFields.length ? `ordinaryRequiredFields:${missingRequiredFields.join(",")}` : null,
    unexpectedOrdinaryRequiredFields.length ? `ordinaryRequiredFields:unexpected:${unexpectedOrdinaryRequiredFields.join(",")}` : null,
    missingOptionalFields.length ? `optionalFields:${missingOptionalFields.join(",")}` : null,
    unexpectedOptionalFields.length ? `optionalFields:unexpected:${unexpectedOptionalFields.join(",")}` : null,
    missingTriggers.length ? `triggerList:${missingTriggers.join(",")}` : null,
    unexpectedTriggers.length ? `triggerList:unexpected:${unexpectedTriggers.join(",")}` : null,
    policy.extremeScoreThresholdLow === SCORE_EXPLANATION_EXTREME_THRESHOLD_LOW
      ? null
      : `extremeScoreThresholdLow:${SCORE_EXPLANATION_EXTREME_THRESHOLD_LOW}`,
    policy.extremeScoreThresholdHigh === SCORE_EXPLANATION_EXTREME_THRESHOLD_HIGH
      ? null
      : `extremeScoreThresholdHigh:${SCORE_EXPLANATION_EXTREME_THRESHOLD_HIGH}`,
    missingInconsistencyRules.length ? `inconsistencyRules:${missingInconsistencyRules.join(",")}` : null,
    unexpectedInconsistencyRules.length ? `inconsistencyRules:unexpected:${unexpectedInconsistencyRules.join(",")}` : null,
    policy.overallVsCentralityStrengthGapThreshold === SCORE_EXPLANATION_OVERALL_PRODUCT_GAP_THRESHOLD
      ? null
      : `overallVsCentralityStrengthGapThreshold:${SCORE_EXPLANATION_OVERALL_PRODUCT_GAP_THRESHOLD}`,
    policy.targetUnclearTrigger === true ? null : "targetUnclearTrigger",
    policy.highStakesWorkflowTrigger === true ? null : "highStakesWorkflowTrigger",
    policy.postDiscussionRevisionTrigger === true ? null : "postDiscussionRevisionTrigger",
    policy.exposureFamiliarityConflictUncertaintyTrigger === true ? null : "exposureFamiliarityConflictUncertaintyTrigger",
    policyMentions(policy.protectedStatusBlindPromptCopy, ["workflow", "policy"]) ? null : "protectedStatusBlindPromptCopy",
    policyMentions(policy.sentenceGuidance, ["one"]) && policyMentions(policy.sentenceGuidance, ["two"]) ? null : "sentenceGuidance",
    policyMentions(policy.qaRoutingPolicy, ["qa", "route"]) ? null : "qaRoutingPolicy",
    requiredPromptFieldReason("protectedSplitCompatibilityClass", policy.protectedSplitCompatibilityClass),
    policy.protectedSplitCompatible === true ? null : "protectedSplitCompatible",
    requiredPromptFieldReason("createdBy", policy.createdBy ?? policy.created_by),
    requiredPromptFieldReason("timestamp", policy.timestamp),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    coveredWorkflowSplitClasses,
    ordinaryRequiredFields,
    optionalFields,
    missingOptionalFields,
    unexpectedOptionalFields,
    triggerList,
    inconsistencyRules,
    missingTriggers,
    unexpectedTriggers,
    missingInconsistencyRules,
    unexpectedInconsistencyRules,
    extremeScoreThresholdLow: policy.extremeScoreThresholdLow ?? null,
    extremeScoreThresholdHigh: policy.extremeScoreThresholdHigh ?? null,
    overallVsCentralityStrengthGapThreshold: policy.overallVsCentralityStrengthGapThreshold ?? null,
    protectedStatusBlindPromptCopy: policy.protectedStatusBlindPromptCopy ?? null,
    sentenceGuidance: policy.sentenceGuidance ?? null,
    qaRoutingPolicy: policy.qaRoutingPolicy ?? null,
    protectedSplitCompatibilityClass: policy.protectedSplitCompatibilityClass ?? null,
    protectedSplitCompatible: policy.protectedSplitCompatible === true,
    createdBy: policy.createdBy ?? policy.created_by ?? null,
    timestamp: policy.timestamp ?? null,
    reviewReasons,
    status: reviewReasons.length ? "score_explanation_policy_review_required" : "score_explanation_policy_complete",
  };
}

function normalizeRatingEscalationPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.ratingEscalationPolicyId;
  if (!id) return null;
  const triggerList = normalizeStringArray(policy.triggerList ?? policy.triggers);
  const missingTriggers = RATING_ESCALATION_TRIGGER_RULES.filter((trigger) => !triggerList.includes(trigger));
  const unexpectedTriggers = triggerList.filter((trigger) => !RATING_ESCALATION_TRIGGER_RULES.includes(trigger));
  const serviceLevelByTrigger =
    policy.serviceLevelByTrigger && typeof policy.serviceLevelByTrigger === "object" && !Array.isArray(policy.serviceLevelByTrigger)
      ? policy.serviceLevelByTrigger
      : {};
  const missingServiceLevelTriggers = RATING_ESCALATION_TRIGGER_RULES.filter(
    (trigger) => typeof serviceLevelByTrigger[trigger] !== "string" || !serviceLevelByTrigger[trigger].trim(),
  );
  const unexpectedServiceLevelTriggers = Object.keys(serviceLevelByTrigger).filter((trigger) => !RATING_ESCALATION_TRIGGER_RULES.includes(trigger));
  const reviewReasons = [
    requiredPromptFieldReason("policyVersion", policy.policyVersion ?? policy.version),
    missingTriggers.length ? `triggerList:${missingTriggers.join(",")}` : null,
    unexpectedTriggers.length ? `triggerList:unexpected:${unexpectedTriggers.join(",")}` : null,
    policy.lowClarityThreshold === RATING_ESCALATION_LOW_CLARITY_THRESHOLD
      ? null
      : `lowClarityThreshold:${RATING_ESCALATION_LOW_CLARITY_THRESHOLD}`,
    policy.lowClarityAdjudicationCount === RATING_ESCALATION_LOW_CLARITY_ADJUDICATION_COUNT
      ? null
      : `lowClarityAdjudicationCount:${RATING_ESCALATION_LOW_CLARITY_ADJUDICATION_COUNT}`,
    policy.initialOverallSpreadThreshold === RATING_ESCALATION_OVERALL_SPREAD_THRESHOLD
      ? null
      : `initialOverallSpreadThreshold:${RATING_ESCALATION_OVERALL_SPREAD_THRESHOLD}`,
    policy.centralityStrengthProductSpreadThreshold === RATING_ESCALATION_PRODUCT_SPREAD_THRESHOLD
      ? null
      : `centralityStrengthProductSpreadThreshold:${RATING_ESCALATION_PRODUCT_SPREAD_THRESHOLD}`,
    policy.correctnessSpreadThreshold === RATING_ESCALATION_CORRECTNESS_SPREAD_THRESHOLD
      ? null
      : `correctnessSpreadThreshold:${RATING_ESCALATION_CORRECTNESS_SPREAD_THRESHOLD}`,
    policy.postDiscussionMaxSpreadTarget === RATING_ESCALATION_POST_DISCUSSION_MAX_SPREAD_TARGET
      ? null
      : `postDiscussionMaxSpreadTarget:${RATING_ESCALATION_POST_DISCUSSION_MAX_SPREAD_TARGET}`,
    missingServiceLevelTriggers.length ? `serviceLevelByTrigger:${missingServiceLevelTriggers.join(",")}` : null,
    unexpectedServiceLevelTriggers.length ? `serviceLevelByTrigger:unexpected:${unexpectedServiceLevelTriggers.join(",")}` : null,
    policyMentions(policy.protectedStatusBlindRoutingCopy, ["workflow", "policy"]) ? null : "protectedStatusBlindRoutingCopy",
    policyMentions(policy.lmcaSourceBoundary, ["project", "default"]) ? null : "lmcaSourceBoundary",
    requiredPromptFieldReason("createdBy", policy.createdBy ?? policy.created_by),
    requiredPromptFieldReason("timestamp", policy.timestamp),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    triggerList,
    missingTriggers,
    unexpectedTriggers,
    lowClarityThreshold: policy.lowClarityThreshold ?? null,
    lowClarityAdjudicationCount: policy.lowClarityAdjudicationCount ?? null,
    initialOverallSpreadThreshold: policy.initialOverallSpreadThreshold ?? null,
    centralityStrengthProductSpreadThreshold: policy.centralityStrengthProductSpreadThreshold ?? null,
    correctnessSpreadThreshold: policy.correctnessSpreadThreshold ?? null,
    postDiscussionMaxSpreadTarget: policy.postDiscussionMaxSpreadTarget ?? null,
    serviceLevelByTrigger,
    missingServiceLevelTriggers,
    unexpectedServiceLevelTriggers,
    protectedStatusBlindRoutingCopy: policy.protectedStatusBlindRoutingCopy ?? null,
    lmcaSourceBoundary: policy.lmcaSourceBoundary ?? null,
    createdBy: policy.createdBy ?? policy.created_by ?? null,
    timestamp: policy.timestamp ?? null,
    reviewReasons,
    status: reviewReasons.length ? "rating_escalation_policy_review_required" : "rating_escalation_policy_complete",
  };
}

function normalizeUIExperimentPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.uiExperimentPolicyId;
  if (!id) return null;
  const coveredSplitLaneClasses = normalizeStringArray(policy.coveredSplitLaneClasses);
  const blockedExperimentClasses = normalizeStringArray(policy.blockedExperimentClasses);
  const missingLaneClasses = PROTECTED_UI_LANE_CLASSES.filter((lane) => !coveredSplitLaneClasses.includes(lane));
  const missingBlockedClasses = UI_EXPERIMENT_BLOCKED_CLASSES.filter((experimentClass) => !blockedExperimentClasses.includes(experimentClass));
  const reviewReasons = [
    requiredPromptFieldReason("policyVersion", policy.policyVersion ?? policy.version),
    missingLaneClasses.length ? `coveredSplitLaneClasses:${missingLaneClasses.join(",")}` : null,
    missingBlockedClasses.length ? `blockedExperimentClasses:${missingBlockedClasses.join(",")}` : null,
    policy.unregisteredMaterialChangesBlocked === true ? null : "unregisteredMaterialChangesBlocked",
    policy.sensitivitySnapshotRequired === true ? null : "sensitivitySnapshotRequired",
    policyMentions(policy.uxSimplificationCompatibilityRule, ["ux", "simplification"]) ? null : "uxSimplificationCompatibilityRule",
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    coveredSplitLaneClasses,
    blockedExperimentClasses,
    missingLaneClasses,
    missingBlockedClasses,
    unregisteredMaterialChangesBlocked: policy.unregisteredMaterialChangesBlocked === true,
    sensitivitySnapshotRequired: policy.sensitivitySnapshotRequired === true,
    reviewReasons,
    status: reviewReasons.length ? "ui_experiment_policy_review_required" : "ui_experiment_policy_complete",
  };
}

function normalizePreSubmitAssistPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.preSubmitAssistPolicyId;
  if (!id) return null;
  const permittedAssistTypes = normalizeStringArray(policy.permittedAssistTypes);
  const prohibitedInputs = normalizeStringArray(policy.prohibitedInputs);
  const missingProhibitedInputs = PRE_SUBMIT_PROHIBITED_INPUTS.filter((input) => !prohibitedInputs.includes(input));
  const reviewReasons = [
    requiredPromptFieldReason("policyVersion", policy.policyVersion ?? policy.version),
    requiredPromptFieldReason("rubricVersion", policy.rubricVersion),
    requiredPromptFieldReason("workflowProfileId", policy.workflowProfileId),
    permittedAssistTypes.length ? null : "permittedAssistTypes",
    missingProhibitedInputs.length ? `prohibitedInputs:${missingProhibitedInputs.join(",")}` : null,
    policy.deterministic === true ? null : "deterministic",
    policy.labelBlind === true ? null : "labelBlind",
    policy.nonDirective === true ? null : "nonDirective",
    policy.targetScoreSuggestionsProhibited === true ? null : "targetScoreSuggestionsProhibited",
    policy.protectedSplitEligible === true ? null : "protectedSplitEligible",
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    rubricVersion: policy.rubricVersion ?? null,
    workflowProfileId: policy.workflowProfileId ?? null,
    permittedAssistTypes,
    prohibitedInputs,
    missingProhibitedInputs,
    deterministic: policy.deterministic === true,
    labelBlind: policy.labelBlind === true,
    nonDirective: policy.nonDirective === true,
    targetScoreSuggestionsProhibited: policy.targetScoreSuggestionsProhibited === true,
    protectedSplitEligible: policy.protectedSplitEligible === true,
    reviewReasons,
    status: reviewReasons.length ? "pre_submit_assist_policy_review_required" : "pre_submit_assist_policy_complete",
  };
}

function normalizeAccessibilityConformanceReport(report, rowSource) {
  const id = report?.id ?? report?.accessibilityConformanceReportId;
  if (!id) return null;
  const screenIds = normalizeStringArray(report.screenIds ?? report.coveredSurfaces);
  const checksPassed = normalizeStringArray(report.checksPassed);
  const missingSurfaces = ACCESSIBILITY_REQUIRED_SURFACES.filter((surface) => !screenIds.includes(surface));
  const missingChecks = ACCESSIBILITY_REQUIRED_CHECKS.filter((check) => !checksPassed.includes(check));
  const failures = Array.isArray(report.failures) ? report.failures : [];
  const reviewReasons = [
    normalizeStringArray(report.workflowProfileIds).length ? null : "workflowProfileIds",
    normalizeStringArray(report.raterInstructionRenderVersionIds).length ? null : "raterInstructionRenderVersionIds",
    requiredPromptFieldReason("uiExperimentPolicyId", report.uiExperimentPolicyId),
    requiredPromptFieldReason("uxSimplificationPolicyId", report.uxSimplificationPolicyId),
    normalizeStringArray(report.testedLocaleSet).length ? null : "testedLocaleSet",
    missingSurfaces.length ? `screenIds:${missingSurfaces.join(",")}` : null,
    missingChecks.length ? `checksPassed:${missingChecks.join(",")}` : null,
    report.readabilityReviewStatus === "passed" ? null : "readabilityReviewStatus",
    failures.length ? "failures" : null,
    report.nonStaffPromotionBlocker === false ? null : "nonStaffPromotionBlocker",
  ].filter(Boolean);
  return {
    id,
    rowSource,
    screenIds,
    missingSurfaces,
    checksPassed,
    missingChecks,
    testedLocaleSet: normalizeStringArray(report.testedLocaleSet),
    readabilityReviewStatus: report.readabilityReviewStatus ?? null,
    failures,
    mitigations: Array.isArray(report.mitigations) ? report.mitigations : [],
    nonStaffPromotionBlocker: report.nonStaffPromotionBlocker === true,
    reviewReasons,
    status: reviewReasons.length ? "accessibility_conformance_review_required" : "accessibility_conformance_complete",
  };
}

