export function buildReleaseConfigManifestEvidenceReport(releaseId, options = {}) {
  const submittedProfileRows = (options.governedBundleCanonicalizationProfiles ?? [])
    .map((profile) => normalizeGovernedBundleCanonicalizationProfile(profile, "submitted_workflow_canonicalization_profile"))
    .filter(Boolean);
  const seedProfile = normalizeGovernedBundleCanonicalizationProfile(defaultGovernedBundleCanonicalizationProfile(releaseId), "seed_canonicalization_profile");
  const activeProfile = submittedProfileRows.find((row) => row.reviewReasons.length === 0) ?? seedProfile;
	  const submittedBundleRows = (options.governedBundleRecords ?? [])
	    .map((bundle) => normalizeGovernedBundleRecord(bundle, activeProfile.id, "submitted_workflow_governed_bundle"))
	    .filter(Boolean);
	  const seedBundleRows = defaultGovernedBundleRecords(releaseId, seedProfile.id).map((bundle) =>
	    normalizeGovernedBundleRecord(bundle, seedProfile.id, "seed_governed_bundle"),
	  );
	  const bundleRowsForGate = submittedBundleRows.length ? submittedBundleRows : seedBundleRows;
	  const submittedBundleVerificationRows = (options.governedBundleVerifications ?? [])
	    .map((verification) => normalizeGovernedBundleVerification(verification, bundleRowsForGate, "submitted_workflow_governed_bundle_verification"))
	    .filter(Boolean);
	  const seedBundleVerificationRows = defaultGovernedBundleVerifications(releaseId, defaultGovernedBundleRecords(releaseId, seedProfile.id)).map((verification) =>
	    normalizeGovernedBundleVerification(verification, seedBundleRows, "seed_governed_bundle_verification"),
	  );
	  const bundleVerificationRowsForGate = submittedBundleVerificationRows.length ? submittedBundleVerificationRows : seedBundleVerificationRows;
	  const submittedManifestRows = (options.releaseConfigManifests ?? [])
	    .map((manifest) => normalizeReleaseConfigManifest(manifest, bundleRowsForGate, bundleVerificationRowsForGate, "submitted_workflow_release_config_manifest"))
	    .filter(Boolean);
	  const seedManifest = normalizeReleaseConfigManifest(defaultReleaseConfigManifest(releaseId, seedBundleRows), seedBundleRows, seedBundleVerificationRows, "seed_release_config_manifest");
	  const manifestRowsForGate = submittedManifestRows.length ? submittedManifestRows : [seedManifest];
	  const submittedVerificationRows = (options.releaseConfigManifestVerifications ?? [])
	    .map((verification) => normalizeReleaseConfigManifestVerification(verification, "submitted_workflow_release_config_manifest_verification"))
	    .filter(Boolean);
	  const bundleFamilyRows = REQUIRED_GOVERNED_BUNDLE_FAMILIES.map((family) => governedBundleFamilyEvidenceRow(family, bundleRowsForGate, bundleVerificationRowsForGate));
  const activeManifest = manifestRowsForGate.find((row) => row.reviewReasons.length === 0) ?? null;
  const manifestVerificationRow = activeManifest
    ? submittedVerificationRows.find((row) => row.manifestId === activeManifest.id && row.reviewReasons.length === 0) ?? null
    : null;
  const reviewSections = [
	    ...submittedProfileRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "governed_bundle_canonicalization_profile", artifactId: row.id, reason }))),
	    ...submittedBundleRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "governed_bundle", artifactId: row.id, reason }))),
	    ...submittedBundleVerificationRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "governed_bundle_verification", artifactId: row.id, reason }))),
	    ...submittedManifestRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "release_config_manifest", artifactId: row.id, reason }))),
    ...submittedVerificationRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "release_config_manifest_verification", artifactId: row.id, reason }))),
    ...bundleFamilyRows.filter((row) => row.status !== "governed_bundle_family_complete").map((row) => ({
      artifactType: "governed_bundle_family",
      artifactId: row.bundleFamily,
      reason: row.status,
    })),
    activeManifest ? null : { artifactType: "release_config_manifest", artifactId: "release_config_manifest", reason: "missing_complete_release_config_manifest" },
    submittedManifestRows.length && !manifestVerificationRow
      ? { artifactType: "release_config_manifest_verification", artifactId: activeManifest?.id ?? "release_config_manifest", reason: "missing_complete_manifest_verification" }
      : null,
  ].filter(Boolean);
  const submittedEvidenceComplete =
	    submittedProfileRows.length > 0 &&
	    submittedBundleRows.length > 0 &&
	    submittedBundleVerificationRows.length > 0 &&
	    submittedManifestRows.length > 0 &&
	    submittedVerificationRows.length > 0 &&
    reviewSections.length === 0;
  return {
    id: `release-config-manifest-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    requiredManifestBindings: REQUIRED_RELEASE_CONFIG_BINDINGS,
    requiredGovernedBundleFamilies: REQUIRED_GOVERNED_BUNDLE_FAMILIES,
	    canonicalizationProfiles: [seedProfile, ...submittedProfileRows],
	    governedBundleRows: [...seedBundleRows, ...submittedBundleRows],
	    governedBundleVerificationRows: [...seedBundleVerificationRows, ...submittedBundleVerificationRows],
	    releaseConfigManifestRows: [seedManifest, ...submittedManifestRows],
    releaseConfigManifestVerificationRows: submittedVerificationRows,
    bundleFamilyRows,
    activeManifestId: activeManifest?.id ?? null,
    activeManifestHash: activeManifest?.canonicalManifestHash ?? null,
    counts: {
	      submittedCanonicalizationProfileCount: submittedProfileRows.length,
	      submittedGovernedBundleCount: submittedBundleRows.length,
	      submittedGovernedBundleVerificationCount: submittedBundleVerificationRows.length,
	      submittedReleaseConfigManifestCount: submittedManifestRows.length,
      submittedVerificationCount: submittedVerificationRows.length,
      passingBundleFamilyCount: bundleFamilyRows.filter((row) => row.status === "governed_bundle_family_complete").length,
      reviewSectionCount: reviewSections.length,
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "release_config_manifest_review_required"
      : submittedEvidenceComplete
        ? "submitted_release_config_manifest_evidence_complete"
        : "seed_release_config_manifest_evidence_complete",
  };
}

function normalizeGovernedBundleCanonicalizationProfile(profile, rowSource) {
  const id = profile?.id ?? profile?.canonicalizationProfileId;
  if (!id) return null;
  const reviewReasons = [
    requiredPromptFieldReason("version", profile.version),
    String(profile.hashAlgorithm ?? "").toLowerCase() === "sha256" ? null : "hashAlgorithm",
    requiredPromptFieldReason("materializationQueryRules", profile.materializationQueryRules),
    requiredPromptFieldReason("includedFieldPolicy", profile.includedFieldPolicy),
	    requiredPromptFieldReason("rowOrderingPolicy", profile.rowOrderingPolicy),
	    requiredPromptFieldReason("arrayOrderingPolicy", profile.arrayOrderingPolicy),
	    requiredPromptFieldReason("nullEmptyHandling", profile.nullEmptyHandling),
	    requiredPromptFieldReason("unicodeNormalization", profile.unicodeNormalization),
	    requiredPromptFieldReason("timestampNumberEncoding", profile.timestampNumberEncoding),
	    normalizeStringArray(profile.environmentScopeFields).length ? null : "environmentScopeFields",
	    normalizeStringArray(profile.nonsemanticMetadataExclusionRules).length ? null : "nonsemanticMetadataExclusionRules",
	    normalizeStringArray(profile.testVectorIds).length ? null : "testVectorIds",
	    requiredPromptFieldReason("createdBy", profile.createdBy),
	    requiredPromptFieldReason("activatedAt", profile.activatedAt),
	  ].filter(Boolean);
  return {
    id,
    rowSource,
    name: profile.name ?? null,
    version: profile.version ?? null,
    hashAlgorithm: profile.hashAlgorithm ?? null,
    materializationQueryRules: profile.materializationQueryRules ?? null,
    includedFieldPolicy: profile.includedFieldPolicy ?? null,
    rowOrderingPolicy: profile.rowOrderingPolicy ?? null,
    arrayOrderingPolicy: profile.arrayOrderingPolicy ?? null,
	    nullEmptyHandling: profile.nullEmptyHandling ?? null,
	    unicodeNormalization: profile.unicodeNormalization ?? null,
	    timestampNumberEncoding: profile.timestampNumberEncoding ?? null,
	    environmentScopeFields: normalizeStringArray(profile.environmentScopeFields),
	    nonsemanticMetadataExclusionRules: normalizeStringArray(profile.nonsemanticMetadataExclusionRules),
	    testVectorIds: normalizeStringArray(profile.testVectorIds),
	    createdBy: profile.createdBy ?? null,
	    activatedAt: profile.activatedAt ?? null,
	    reviewReasons,
    status: reviewReasons.length ? "canonicalization_profile_review_required" : "canonicalization_profile_complete",
  };
}

function normalizeGovernedBundleRecord(bundle, activeProfileId, rowSource) {
  const id = bundle?.id ?? bundle?.governedBundleId;
  if (!id) return null;
  const bundleFamily = bundle.bundleFamily ?? null;
  const reviewReasons = [
    REQUIRED_GOVERNED_BUNDLE_FAMILIES.includes(bundleFamily) ? null : "bundleFamily",
    requiredPromptFieldReason("semanticVersion", bundle.semanticVersion),
	    bundle.canonicalizationProfileId === activeProfileId ? null : "canonicalizationProfileId",
	    String(bundle.canonicalContentHash ?? "").startsWith("sha256:") ? null : "canonicalContentHash",
	    Number.isFinite(bundle.materializedRowCount) && bundle.materializedRowCount > 0 ? null : "materializedRowCount",
	    requiredPromptFieldReason("bundleContentSchemaVersion", bundle.bundleContentSchemaVersion),
	    requiredPromptFieldReason("canonicalizationTestVectorId", bundle.canonicalizationTestVectorId),
	    bundle.semanticMutationPolicy === "new_version_required" ? null : "semanticMutationPolicy",
	    bundle.manifestActivationPolicy === "verified_before_manifest_activation" ? null : "manifestActivationPolicy",
	    bundle.appendOnlyActivationStatus === "activated" ? null : "appendOnlyActivationStatus",
	    requiredPromptFieldReason("activatedBy", bundle.activatedBy),
	    requiredPromptFieldReason("activatedAt", bundle.activatedAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    bundleFamily,
    semanticVersion: bundle.semanticVersion ?? null,
	    canonicalizationProfileId: bundle.canonicalizationProfileId ?? null,
	    canonicalContentHash: bundle.canonicalContentHash ?? null,
	    materializedRowCount: bundle.materializedRowCount ?? null,
	    bundleContentSchemaVersion: bundle.bundleContentSchemaVersion ?? null,
	    canonicalizationTestVectorId: bundle.canonicalizationTestVectorId ?? null,
	    semanticMutationPolicy: bundle.semanticMutationPolicy ?? null,
	    manifestActivationPolicy: bundle.manifestActivationPolicy ?? null,
	    appendOnlyActivationStatus: bundle.appendOnlyActivationStatus ?? null,
	    parentBundleId: bundle.parentBundleId ?? null,
	    supersededBy: bundle.supersededBy ?? null,
	    mutationAttemptAuditId: bundle.mutationAttemptAuditId ?? null,
	    activatedBy: bundle.activatedBy ?? null,
    activatedAt: bundle.activatedAt ?? null,
    reviewReasons,
	    status: reviewReasons.length ? "governed_bundle_review_required" : "governed_bundle_complete",
	  };
}

function normalizeGovernedBundleVerification(verification, bundleRows, rowSource) {
  const id = verification?.id ?? verification?.verificationId;
  if (!id) return null;
  const governedBundleId = verification.governedBundleId ?? verification.bundleId ?? null;
  const bundleRow = bundleRows.find((row) => row.id === governedBundleId) ?? null;
  const reviewReasons = [
    bundleRow && bundleRow.reviewReasons.length === 0 ? null : "governedBundleId",
    verification.bundleFamily === bundleRow?.bundleFamily ? null : "bundleFamily",
    verification.semanticVersion === bundleRow?.semanticVersion ? null : "semanticVersion",
    verification.canonicalizationProfileId === bundleRow?.canonicalizationProfileId ? null : "canonicalizationProfileId",
    verification.verificationStatus === "passed" ? null : "verificationStatus",
    verification.expectedHash === bundleRow?.canonicalContentHash ? null : "expectedHash",
    verification.observedHash === verification.expectedHash ? null : "observedHash",
    verification.materializedRowCount === bundleRow?.materializedRowCount ? null : "materializedRowCount",
    verification.manifestActivationBlockedOnMismatch === true ? null : "manifestActivationBlockedOnMismatch",
    requiredPromptFieldReason("verifiedAt", verification.verifiedAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    governedBundleId,
    bundleFamily: verification.bundleFamily ?? null,
    semanticVersion: verification.semanticVersion ?? null,
    canonicalizationProfileId: verification.canonicalizationProfileId ?? null,
    verificationStatus: verification.verificationStatus ?? null,
    expectedHash: verification.expectedHash ?? null,
    observedHash: verification.observedHash ?? null,
    materializedRowCount: verification.materializedRowCount ?? null,
    manifestActivationBlockedOnMismatch: verification.manifestActivationBlockedOnMismatch === true,
    verifiedAt: verification.verifiedAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "governed_bundle_verification_review_required" : "governed_bundle_verification_passed",
  };
}

function normalizeReleaseConfigManifest(manifest, bundleRows, bundleVerificationRows, rowSource) {
  const id = manifest?.id ?? manifest?.releaseConfigManifestId;
  if (!id) return null;
  const bindingFamilies = normalizeStringArray(manifest.bindingFamilies);
  const governedBundleIds = normalizeStringArray(manifest.governedBundleIds);
  const completeBundleIds = new Set(bundleRows.filter((row) => row.reviewReasons.length === 0).map((row) => row.id));
  const verifiedBundleIds = new Set(bundleVerificationRows.filter((row) => row.reviewReasons.length === 0).map((row) => row.governedBundleId));
  const missingBindings = REQUIRED_RELEASE_CONFIG_BINDINGS.filter((binding) => !bindingFamilies.includes(binding));
  const missingBundleFamilies = REQUIRED_GOVERNED_BUNDLE_FAMILIES.filter(
    (family) => !bundleRows.some((row) => row.bundleFamily === family && row.reviewReasons.length === 0 && governedBundleIds.includes(row.id)),
  );
  const unknownBundleIds = governedBundleIds.filter((bundleId) => !completeBundleIds.has(bundleId));
  const unverifiedBundleIds = governedBundleIds.filter((bundleId) => completeBundleIds.has(bundleId) && !verifiedBundleIds.has(bundleId));
  const semanticMutationAttempts = bundleRows
    .filter((row) => row.reviewReasons.length === 0)
    .filter((row, index, rows) =>
      rows.some(
        (candidate, candidateIndex) =>
          candidateIndex !== index &&
          candidate.bundleFamily === row.bundleFamily &&
          candidate.semanticVersion === row.semanticVersion &&
          candidate.canonicalContentHash !== row.canonicalContentHash &&
          !candidate.parentBundleId &&
          !candidate.supersededBy &&
          !candidate.mutationAttemptAuditId,
      )
    )
    .map((row) => row.id);
  const reviewReasons = [
    requiredPromptFieldReason("releaseId", manifest.releaseId),
    requiredPromptFieldReason("version", manifest.version),
    String(manifest.canonicalManifestHash ?? "").startsWith("sha256:") ? null : "canonicalManifestHash",
    requiredPromptFieldReason("codeCommitId", manifest.codeCommitId),
    requiredPromptFieldReason("rubricVersion", manifest.rubricVersion),
    requiredPromptFieldReason("scoredDimensionSchemaVersion", manifest.scoredDimensionSchemaVersion),
    requiredPromptFieldReason("releaseGateProfileId", manifest.releaseGateProfileId),
    requiredPromptFieldReason("visibilityPolicyId", manifest.visibilityPolicyId),
    requiredPromptFieldReason("uiExperimentPolicyId", manifest.uiExperimentPolicyId),
    normalizeStringArray(manifest.uxSimplificationPolicyIds).length ? null : "uxSimplificationPolicyIds",
    requiredPromptFieldReason("preSubmitAssistPolicyId", manifest.preSubmitAssistPolicyId),
    normalizeStringArray(manifest.scoreInputPolicyIds).length ? null : "scoreInputPolicyIds",
    normalizeStringArray(manifest.workflowProfileIds).length ? null : "workflowProfileIds",
    normalizeStringArray(manifest.raterInstructionRenderVersionIds).length ? null : "raterInstructionRenderVersionIds",
    normalizeStringArray(manifest.rubricLintConfigIds).length ? null : "rubricLintConfigIds",
    requiredPromptFieldReason("queuePolicySnapshotId", manifest.queuePolicySnapshotId),
    normalizeStringArray(manifest.labelSnapshotIds).length ? null : "labelSnapshotIds",
    normalizeStringArray(manifest.pairwiseComparisonSnapshotIds).length ? null : "pairwiseComparisonSnapshotIds",
    normalizeStringArray(manifest.metricConfigIds).length ? null : "metricConfigIds",
    normalizeStringArray(manifest.scoringCodeChecksums).length ? null : "scoringCodeChecksums",
    normalizeStringArray(manifest.parserConfigIds).length ? null : "parserConfigIds",
    normalizeStringArray(manifest.promptTemplateIds).length ? null : "promptTemplateIds",
    missingBindings.length ? `bindingFamilies:${missingBindings.join(",")}` : null,
    missingBundleFamilies.length ? `governedBundleFamilies:${missingBundleFamilies.join(",")}` : null,
    unknownBundleIds.length ? `governedBundleIds:${unknownBundleIds.join(",")}` : null,
    unverifiedBundleIds.length ? `governedBundleVerifications:${unverifiedBundleIds.join(",")}` : null,
    semanticMutationAttempts.length ? `semanticMutationAttempt:${semanticMutationAttempts.join(",")}` : null,
    requiredPromptFieldReason("frozenAt", manifest.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    releaseId: manifest.releaseId ?? null,
    version: manifest.version ?? null,
    canonicalManifestHash: manifest.canonicalManifestHash ?? null,
    governedBundleIds,
    bindingFamilies,
    missingBindings,
    missingBundleFamilies,
    unknownBundleIds,
    unverifiedBundleIds,
    semanticMutationAttempts,
    frozenAt: manifest.frozenAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "release_config_manifest_review_required" : "release_config_manifest_complete",
  };
}

function normalizeReleaseConfigManifestVerification(verification, rowSource) {
  const id = verification?.id ?? verification?.verificationId;
  if (!id) return null;
  const manifestId = verification.manifestId ?? verification.releaseConfigManifestId ?? null;
  const reviewReasons = [
    requiredPromptFieldReason("manifestId", manifestId),
    verification.verificationStatus === "passed" ? null : "verificationStatus",
    String(verification.expectedHash ?? "").startsWith("sha256:") ? null : "expectedHash",
    verification.observedHash === verification.expectedHash ? null : "observedHash",
    requiredPromptFieldReason("verifiedAt", verification.verifiedAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    manifestId,
    verificationStatus: verification.verificationStatus ?? null,
    expectedHash: verification.expectedHash ?? null,
    observedHash: verification.observedHash ?? null,
    verifiedAt: verification.verifiedAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "release_config_manifest_verification_review_required" : "release_config_manifest_verification_passed",
  };
}

function governedBundleFamilyEvidenceRow(bundleFamily, rows, verificationRows) {
  const completeRows = rows.filter((row) => row.bundleFamily === bundleFamily && row.reviewReasons.length === 0);
  const latestRow = completeRows.at(-1) ?? null;
  const verificationRow = latestRow
    ? verificationRows.find((row) => row.governedBundleId === latestRow.id && row.reviewReasons.length === 0) ?? null
    : null;
  return {
    bundleFamily,
    latestGovernedBundleId: latestRow?.id ?? null,
    latestGovernedBundleVerificationId: verificationRow?.id ?? null,
    canonicalContentHash: latestRow?.canonicalContentHash ?? null,
    materializedRowCount: latestRow?.materializedRowCount ?? null,
    appendOnlyActivationStatus: latestRow?.appendOnlyActivationStatus ?? null,
    status: latestRow && verificationRow
      ? "governed_bundle_family_complete"
      : latestRow
        ? "governed_bundle_verification_missing"
        : "governed_bundle_family_missing",
  };
}

const REQUIRED_QUALIFICATION_SCOPES = ["expert_rating", "adjudicator", "topic_specialist", "hidden_benchmark_expert", "primary_rater_anchor"];
const REQUIRED_QUALIFICATION_WORKFLOW_ELIGIBILITY = ["release_critical", "validation", "hidden_benchmark"];

const PROHIBITED_INCENTIVE_SIGNALS = [
  "rating_direction",
  "peer_agreement_before_feedback",
  "model_agreement",
  "gold_performance_before_permitted_feedback",
  "speed_beyond_qa_band",
  "hidden_benchmark_performance",
  "accepted_revision_count",
  "leaderboard_rank",
];

const LANGUAGE_ARTIFACT_TYPES = [
  "non_native_wording",
  "dialect_or_register",
  "machine_translation_residue",
  "typo_or_grammar_noise",
  "OCR_or_formatting_noise",
  "awkward_but_determinate",
];

const MODEL_PROVIDER_PROTECTED_RUN_CLASSES = ["model_evaluation", "model_judge", "critique_generation", "model_assisted_check"];

const SOURCE_RECOGNITION_TYPES = [
  "source_recognized",
  "author_or_style_recognized",
  "prior_coursework_or_forum_exposure",
  "model_generation_route_recognized",
  "other_prior_exposure",
];
const SOURCE_RECOGNITION_BLIND_EFFECT_FRAGMENTS = ["excluded", "blocked", "nonblind", "non_blind", "non_independent", "paused", "reassign", "review"];
const BLIND_DENOMINATOR_COUNTING_FORBIDDEN_FRAGMENTS = ["count_as_independent", "count as independent", "counts_as_independent", "counts as independent", "fresh blind", "fresh_blind"];
const SOURCE_RECOGNITION_FORBIDDEN_BLIND_EFFECT_FRAGMENTS = BLIND_DENOMINATOR_COUNTING_FORBIDDEN_FRAGMENTS;

function defaultVolunteerIncentivePolicy(releaseId) {
  return {
    id: `volunteer-incentive-policy-${releaseId}`,
    policyVersion: "volunteer-incentive-rlhf84-v1",
    allowedCompensationCreditInputs: ["eligible_completed_work", "role", "time_commitment", "training_completion"],
    prohibitedIncentiveSignals: PROHIBITED_INCENTIVE_SIGNALS,
    speedEffortGuardrails: "private QA-safe effort bands only; no public speed rewards",
    publicRecognitionPolicy: "acknowledge participation without score, agreement, speed, or benchmark ranking",
    privateProgressDashboardPolicy: "private non-gamified progress only",
    calibrationFeedbackUseLimits: "post-lock training-approved feedback only",
    hiddenBenchmarkGoldPerformanceExclusionPolicy: "never use hidden-benchmark or protected gold performance for incentives",
    leaderboardBadgeRestrictions: "no peer, model, gold, hidden-benchmark, or speed leaderboards",
    qaEscalationEffects: "QA routes remediation without public penalty or score incentives",
    frozenAt: "2026-10-01T00:00:00.000Z",
  };
}

function defaultRaterQualificationRecords(releaseId) {
  return REQUIRED_QUALIFICATION_SCOPES.map((qualificationScope) => ({
    id: `rater-qualification-${releaseId}-${qualificationScope}`,
    raterId: `qualified-${qualificationScope}`,
    qualificationScope,
    qualificationSource: qualificationScope === "primary_rater_anchor" ? "manual_expert_review" : "certification_pack",
    evidenceArtifactReference: `qualification-evidence-${qualificationScope}`,
    approvedRoles: qualificationScope === "adjudicator" ? ["expert", "adjudicator"] : ["expert"],
    topicFamilyScope: ["AI safety", "decision theory", "normative ethics", "philosophy of mind", "politics", "miscellaneous"],
    splitWorkflowEligibility: ["release_critical", "validation", "hidden_benchmark"],
    expiryReviewDate: "2027-01-31",
    approver: "seed-qualification-reviewer",
    approvedException: false,
    timestamp: "2026-10-01T00:00:00.000Z",
  }));
}

function defaultLanguageArtifactAssessment(releaseId) {
  return {
    id: `language-artifact-assessment-${releaseId}`,
    positionId: "pos-ai-prior",
    critiqueId: "crit-ai-base-rate",
    artifactType: "machine_translation_residue",
    sourceLanguage: "unknown",
    translationStatus: "not_translation_or_unknown",
    pinDownabilityImpact: "none",
    substantiveAmbiguityImpact: "none",
    correctnessImpact: "none",
    deadWeightImpact: "none",
    overallQualityImpact: "none",
    automaticScorePenaltyApplied: false,
    scoreChangeRationale: "Artifact flagged for fairness review without automatic LMCA score change.",
    reviewerRole: "expert",
    visibilityState: "release_safe_summary",
    timestamp: "2026-10-01T00:00:00.000Z",
  };
}

function defaultSourceRecognitionEvent(releaseId) {
  return {
    id: `source-recognition-${releaseId}`,
    assignmentId: "assign-ai-base-rate",
    raterId: "demo-rater",
    recognitionType: "source_recognized",
    raterAction: "safe_decline",
    independentBlindEligibilityEffect: "excluded_from_independent_protected_blind_denominator",
    protectedStatusHiddenFromRater: true,
    reviewerResolution: "paused_and_reassigned",
    timestamp: "2026-10-01T00:00:00.000Z",
  };
}

function defaultModelProviderDataHandlingPolicies(releaseId) {
  return MODEL_PROVIDER_PROTECTED_RUN_CLASSES.map((runClass) => ({
    id: `model-provider-data-handling-${releaseId}-${runClass}`,
    providerEndpointClass: `${runClass}-approved-endpoint`,
    coveredRunClass: runClass,
    approvedSplitContentClasses: ["release_critical", "protected_validation", "hidden_benchmark"],
    noTrainingOnInputsOutputs: true,
    noPromptOrOutputReuse: true,
    unnecessaryHumanReviewProhibited: true,
    logRetentionWindowDays: 30,
    subprocessorsSummary: "approved bounded processing route",
    deletionOrRetentionProofRequired: true,
    protectedContentEligible: true,
    approvalStatus: "approved",
    reviewer: "seed-provider-reviewer",
    approvedAt: "2026-10-01T00:00:00.000Z",
    expiresAt: "2026-12-31T00:00:00.000Z",
  }));
}

export function buildParticipantSafeguardEvidenceReport(releaseId, options = {}) {
  const submittedIncentiveRows = (options.volunteerIncentivePolicies ?? [])
    .map((policy) => normalizeVolunteerIncentivePolicy(policy, "submitted_workflow_volunteer_incentive_policy"))
    .filter(Boolean);
  const seedIncentiveRows = [normalizeVolunteerIncentivePolicy(defaultVolunteerIncentivePolicy(releaseId), "seed_volunteer_incentive_policy")];
  const submittedQualificationRows = (options.raterQualificationRecords ?? [])
    .map((record) => normalizeRaterQualificationRecord(record, "submitted_workflow_rater_qualification_record"))
    .filter(Boolean);
  const seedQualificationRows = defaultRaterQualificationRecords(releaseId).map((record) => normalizeRaterQualificationRecord(record, "seed_rater_qualification_record"));
  const qualificationRowsForGate = submittedQualificationRows.length ? submittedQualificationRows : seedQualificationRows;
  const submittedLanguageRows = (options.languageArtifactAssessments ?? [])
    .map((assessment) => normalizeLanguageArtifactAssessment(assessment, "submitted_workflow_language_artifact_assessment"))
    .filter(Boolean);
  const seedLanguageRows = [normalizeLanguageArtifactAssessment(defaultLanguageArtifactAssessment(releaseId), "seed_language_artifact_assessment")];
  const submittedSourceRecognitionRows = (options.sourceRecognitionEvents ?? [])
    .map((event) => normalizeSourceRecognitionEvent(event, "submitted_workflow_source_recognition_event"))
    .filter(Boolean);
  const seedSourceRecognitionRows = [normalizeSourceRecognitionEvent(defaultSourceRecognitionEvent(releaseId), "seed_source_recognition_event")];
  const submittedModelProviderRows = (options.modelProviderDataHandlingPolicies ?? [])
    .map((policy) => normalizeModelProviderDataHandlingPolicy(policy, "submitted_workflow_model_provider_data_handling_policy"))
    .filter(Boolean);
  const seedModelProviderRows = defaultModelProviderDataHandlingPolicies(releaseId).map((policy) =>
    normalizeModelProviderDataHandlingPolicy(policy, "seed_model_provider_data_handling_policy"),
  );
  const modelProviderRowsForGate = submittedModelProviderRows.length ? submittedModelProviderRows : seedModelProviderRows;
  const qualificationScopeRows = REQUIRED_QUALIFICATION_SCOPES.map((scope) => qualificationScopeEvidenceRow(scope, qualificationRowsForGate));
  const modelProviderRunClassRows = MODEL_PROVIDER_PROTECTED_RUN_CLASSES.map((runClass) => modelProviderRunClassEvidenceRow(runClass, modelProviderRowsForGate));
  const reviewSections = [
    ...submittedIncentiveRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "volunteer_incentive_policy", artifactId: row.id, reason }))),
    ...submittedQualificationRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "rater_qualification_record", artifactId: row.id, reason }))),
    ...submittedLanguageRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "language_artifact_assessment", artifactId: row.id, reason }))),
    ...submittedSourceRecognitionRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "source_recognition_event", artifactId: row.id, reason }))),
    ...submittedModelProviderRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: "model_provider_data_handling_policy", artifactId: row.id, reason }))),
    (submittedIncentiveRows.length ? submittedIncentiveRows : seedIncentiveRows).some((row) => row.reviewReasons.length === 0)
      ? null
      : { artifactType: "volunteer_incentive_policy", artifactId: "volunteer_incentive_policy", reason: "missing_complete_incentive_policy" },
    ...qualificationScopeRows.filter((row) => row.status !== "qualification_scope_complete").map((row) => ({
      artifactType: "rater_qualification_scope",
      artifactId: row.qualificationScope,
      reason: row.status,
    })),
    (submittedLanguageRows.length ? submittedLanguageRows : seedLanguageRows).some((row) => row.reviewReasons.length === 0)
      ? null
      : { artifactType: "language_artifact_assessment", artifactId: "language_artifact_assessment", reason: "missing_complete_language_artifact_path" },
    (submittedSourceRecognitionRows.length ? submittedSourceRecognitionRows : seedSourceRecognitionRows).some((row) => row.reviewReasons.length === 0)
      ? null
      : { artifactType: "source_recognition_event", artifactId: "source_recognition_event", reason: "missing_complete_source_recognition_path" },
    ...modelProviderRunClassRows.filter((row) => row.status !== "model_provider_run_class_complete").map((row) => ({
      artifactType: "model_provider_run_class",
      artifactId: row.coveredRunClass,
      reason: row.status,
    })),
  ].filter(Boolean);
  const submittedEvidenceComplete =
    submittedIncentiveRows.length > 0 &&
    submittedQualificationRows.length > 0 &&
    submittedLanguageRows.length > 0 &&
    submittedSourceRecognitionRows.length > 0 &&
    submittedModelProviderRows.length > 0 &&
    reviewSections.length === 0;
  return {
    id: `participant-safeguard-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    requiredQualificationScopes: REQUIRED_QUALIFICATION_SCOPES,
    prohibitedIncentiveSignals: PROHIBITED_INCENTIVE_SIGNALS,
    languageArtifactTypes: LANGUAGE_ARTIFACT_TYPES,
    sourceRecognitionTypes: SOURCE_RECOGNITION_TYPES,
    modelProviderProtectedRunClasses: MODEL_PROVIDER_PROTECTED_RUN_CLASSES,
    volunteerIncentivePolicyRows: [...seedIncentiveRows, ...submittedIncentiveRows],
    raterQualificationRows: [...seedQualificationRows, ...submittedQualificationRows],
    languageArtifactAssessmentRows: [...seedLanguageRows, ...submittedLanguageRows],
    sourceRecognitionRows: [...seedSourceRecognitionRows, ...submittedSourceRecognitionRows],
    modelProviderDataHandlingPolicyRows: [...seedModelProviderRows, ...submittedModelProviderRows],
    qualificationScopeRows,
    modelProviderRunClassRows,
    counts: {
      submittedVolunteerIncentivePolicyCount: submittedIncentiveRows.length,
      submittedRaterQualificationRecordCount: submittedQualificationRows.length,
      submittedLanguageArtifactAssessmentCount: submittedLanguageRows.length,
      submittedSourceRecognitionEventCount: submittedSourceRecognitionRows.length,
      submittedModelProviderDataHandlingPolicyCount: submittedModelProviderRows.length,
      passingQualificationScopeCount: qualificationScopeRows.filter((row) => row.status === "qualification_scope_complete").length,
      passingModelProviderRunClassCount: modelProviderRunClassRows.filter((row) => row.status === "model_provider_run_class_complete").length,
      reviewSectionCount: reviewSections.length,
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "participant_safeguard_review_required"
      : submittedEvidenceComplete
        ? "submitted_participant_safeguard_evidence_complete"
        : "seed_participant_safeguard_evidence_complete",
  };
}

function normalizeVolunteerIncentivePolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.volunteerIncentivePolicyId;
  if (!id) return null;
  const prohibitedSignals = normalizeStringArray(policy.prohibitedIncentiveSignals);
  const missingSignals = PROHIBITED_INCENTIVE_SIGNALS.filter((signal) => !prohibitedSignals.includes(signal));
  const reviewReasons = [
    requiredPromptFieldReason("policyVersion", policy.policyVersion ?? policy.version),
    normalizeStringArray(policy.allowedCompensationCreditInputs).length ? null : "allowedCompensationCreditInputs",
    missingSignals.length ? `prohibitedIncentiveSignals:${missingSignals.join(",")}` : null,
    policyMentions(policy.speedEffortGuardrails, ["qa"]) ? null : "speedEffortGuardrails",
    policyMentions(policy.publicRecognitionPolicy, ["without"]) || policyMentions(policy.publicRecognitionPolicy, ["no"]) ? null : "publicRecognitionPolicy",
    policyMentions(policy.privateProgressDashboardPolicy, ["private"]) && policyMentions(policy.privateProgressDashboardPolicy, ["non-gamified"])
      ? null
      : "privateProgressDashboardPolicy",
    policyMentions(policy.hiddenBenchmarkGoldPerformanceExclusionPolicy, ["hidden"]) && policyMentions(policy.hiddenBenchmarkGoldPerformanceExclusionPolicy, ["never"])
      ? null
      : "hiddenBenchmarkGoldPerformanceExclusionPolicy",
    policyMentions(policy.leaderboardBadgeRestrictions, ["no"]) ? null : "leaderboardBadgeRestrictions",
    requiredPromptFieldReason("frozenAt", policy.frozenAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    policyVersion: policy.policyVersion ?? policy.version ?? null,
    allowedCompensationCreditInputs: normalizeStringArray(policy.allowedCompensationCreditInputs),
    prohibitedIncentiveSignals: prohibitedSignals,
    missingSignals,
    reviewReasons,
    status: reviewReasons.length ? "volunteer_incentive_policy_review_required" : "volunteer_incentive_policy_complete",
  };
}

function normalizeRaterQualificationRecord(record, rowSource) {
  const id = record?.id ?? record?.raterQualificationRecordId;
  if (!id) return null;
  const qualificationScope = record.qualificationScope ?? record.scope ?? null;
  const qualificationSource = record.qualificationSource ?? null;
  const splitWorkflowEligibility = normalizeStringArray(record.splitWorkflowEligibility);
  const missingWorkflowEligibility = REQUIRED_QUALIFICATION_WORKFLOW_ELIGIBILITY.filter((lane) => !splitWorkflowEligibility.includes(lane));
  const reviewReasons = [
    requiredPromptFieldReason("raterId", record.raterId),
    REQUIRED_QUALIFICATION_SCOPES.includes(qualificationScope) ? null : "qualificationScope",
    ["credential", "certification_pack", "prior_rating_reliability", "manual_expert_review", "approved_exception"].includes(qualificationSource)
      ? null
      : "qualificationSource",
    requiredPromptFieldReason("evidenceArtifactReference", record.evidenceArtifactReference ?? record.evidenceArtifactId),
    normalizeStringArray(record.approvedRoles).length ? null : "approvedRoles",
    normalizeStringArray(record.topicFamilyScope).length ? null : "topicFamilyScope",
    splitWorkflowEligibility.length ? null : "splitWorkflowEligibility",
    ...missingWorkflowEligibility.map((lane) => `splitWorkflowEligibility:${lane}`),
    requiredPromptFieldReason("expiryReviewDate", record.expiryReviewDate),
    requiredPromptFieldReason("approver", record.approver),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    raterId: record.raterId ?? null,
    qualificationScope,
    qualificationSource,
    approvedRoles: normalizeStringArray(record.approvedRoles),
    topicFamilyScope: normalizeStringArray(record.topicFamilyScope),
    splitWorkflowEligibility,
    missingWorkflowEligibility,
    expiryReviewDate: record.expiryReviewDate ?? null,
    approvedException: qualificationSource === "approved_exception",
    reviewReasons,
    status: reviewReasons.length ? "rater_qualification_review_required" : "rater_qualification_complete",
  };
}

function normalizeLanguageArtifactAssessment(assessment, rowSource) {
  const id = assessment?.id ?? assessment?.languageArtifactAssessmentId;
  if (!id) return null;
  const artifactType = assessment.artifactType ?? null;
  const reviewReasons = [
    assessment.positionId || assessment.critiqueId || assessment.assignmentId || assessment.ratingId || assessment.adjudicationId ? null : "itemReference",
    LANGUAGE_ARTIFACT_TYPES.includes(artifactType) ? null : "artifactType",
    requiredPromptFieldReason("pinDownabilityImpact", assessment.pinDownabilityImpact),
    requiredPromptFieldReason("substantiveAmbiguityImpact", assessment.substantiveAmbiguityImpact),
    requiredPromptFieldReason("correctnessImpact", assessment.correctnessImpact),
    requiredPromptFieldReason("deadWeightImpact", assessment.deadWeightImpact),
    requiredPromptFieldReason("overallQualityImpact", assessment.overallQualityImpact),
    assessment.automaticScorePenaltyApplied === false ? null : "automaticScorePenaltyApplied",
    requiredPromptFieldReason("reviewerRole", assessment.reviewerRole),
    requiredPromptFieldReason("visibilityState", assessment.visibilityState),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    positionId: assessment.positionId ?? null,
    critiqueId: assessment.critiqueId ?? null,
    assignmentId: assessment.assignmentId ?? null,
    artifactType,
    sourceLanguage: assessment.sourceLanguage ?? null,
    translationStatus: assessment.translationStatus ?? null,
    automaticScorePenaltyApplied: assessment.automaticScorePenaltyApplied === true,
    reviewerRole: assessment.reviewerRole ?? null,
    visibilityState: assessment.visibilityState ?? null,
    reviewReasons,
    status: reviewReasons.length ? "language_artifact_assessment_review_required" : "language_artifact_assessment_complete",
  };
}

function normalizeSourceRecognitionEvent(event, rowSource) {
  const id = event?.id ?? event?.sourceRecognitionEventId;
  if (!id) return null;
  const recognitionType = event.recognitionType ?? null;
  const reviewReasons = [
    requiredPromptFieldReason("assignmentId", event.assignmentId),
    requiredPromptFieldReason("raterId", event.raterId),
    SOURCE_RECOGNITION_TYPES.includes(recognitionType) ? null : "recognitionType",
    ["safe_decline", "continue_nonblind", "request_review"].includes(event.raterAction) ? null : "raterAction",
    requiredPromptFieldReason("independentBlindEligibilityEffect", event.independentBlindEligibilityEffect),
    policyMentionsAny(event.independentBlindEligibilityEffect, SOURCE_RECOGNITION_BLIND_EFFECT_FRAGMENTS) ? null : "independentBlindEligibilityEffect",
    policyMentionsAny(event.independentBlindEligibilityEffect, SOURCE_RECOGNITION_FORBIDDEN_BLIND_EFFECT_FRAGMENTS)
      ? "independentBlindEligibilityEffect:counts_independent"
      : null,
    event.protectedStatusHiddenFromRater === true ? null : "protectedStatusHiddenFromRater",
    event.raterAction === "continue_nonblind" && !policyMentions(event.independentBlindEligibilityEffect, ["excluded"]) && !policyMentions(event.reviewerResolution, ["review"])
      ? "continuedRatingReview"
      : null,
  ].filter(Boolean);
  return {
    id,
    rowSource,
    assignmentId: event.assignmentId ?? null,
    raterId: event.raterId ?? null,
    recognitionType,
    raterAction: event.raterAction ?? null,
    independentBlindEligibilityEffect: event.independentBlindEligibilityEffect ?? null,
    protectedStatusHiddenFromRater: event.protectedStatusHiddenFromRater === true,
    reviewerResolution: event.reviewerResolution ?? null,
    reviewReasons,
    status: reviewReasons.length ? "source_recognition_review_required" : "source_recognition_path_complete",
  };
}

function normalizeModelProviderDataHandlingPolicy(policy, rowSource) {
  const id = policy?.id ?? policy?.modelProviderDataHandlingPolicyId;
  if (!id) return null;
  const coveredRunClass = policy.coveredRunClass ?? policy.runClass ?? null;
  const approvedClasses = normalizeStringArray(policy.approvedSplitContentClasses);
  const reviewReasons = [
    requiredPromptFieldReason("providerEndpointClass", policy.providerEndpointClass ?? policy.providerEndpoint),
    MODEL_PROVIDER_PROTECTED_RUN_CLASSES.includes(coveredRunClass) ? null : "coveredRunClass",
    approvedClasses.includes("hidden_benchmark") && approvedClasses.includes("protected_validation") ? null : "approvedSplitContentClasses",
    policy.noTrainingOnInputsOutputs === true ? null : "noTrainingOnInputsOutputs",
    policy.noPromptOrOutputReuse === true ? null : "noPromptOrOutputReuse",
    policy.unnecessaryHumanReviewProhibited === true ? null : "unnecessaryHumanReviewProhibited",
    Number.isFinite(policy.logRetentionWindowDays) && policy.logRetentionWindowDays >= 0 && policy.logRetentionWindowDays <= 30 ? null : "logRetentionWindowDays",
    requiredPromptFieldReason("subprocessorsSummary", policy.subprocessorsSummary),
    policy.deletionOrRetentionProofRequired === true ? null : "deletionOrRetentionProofRequired",
    policy.protectedContentEligible === true ? null : "protectedContentEligible",
    policy.approvalStatus === "approved" ? null : "approvalStatus",
    requiredPromptFieldReason("reviewer", policy.reviewer),
    requiredPromptFieldReason("expiresAt", policy.expiresAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    providerEndpointClass: policy.providerEndpointClass ?? policy.providerEndpoint ?? null,
    coveredRunClass,
    approvedSplitContentClasses: approvedClasses,
    noTrainingOnInputsOutputs: policy.noTrainingOnInputsOutputs === true,
    noPromptOrOutputReuse: policy.noPromptOrOutputReuse === true,
    unnecessaryHumanReviewProhibited: policy.unnecessaryHumanReviewProhibited === true,
    logRetentionWindowDays: policy.logRetentionWindowDays ?? null,
    subprocessorsSummary: policy.subprocessorsSummary ?? null,
    deletionOrRetentionProofRequired: policy.deletionOrRetentionProofRequired === true,
    protectedContentEligible: policy.protectedContentEligible === true,
    approvalStatus: policy.approvalStatus ?? null,
    reviewer: policy.reviewer ?? null,
    expiresAt: policy.expiresAt ?? null,
    reviewReasons,
    status: reviewReasons.length ? "model_provider_data_handling_review_required" : "model_provider_data_handling_complete",
  };
}

function qualificationScopeEvidenceRow(qualificationScope, rows) {
  const latestRow = rows.find((row) => row.qualificationScope === qualificationScope && row.reviewReasons.length === 0) ?? null;
  return {
    qualificationScope,
    raterQualificationRecordId: latestRow?.id ?? null,
    approvedRoles: latestRow?.approvedRoles ?? [],
    splitWorkflowEligibility: latestRow?.splitWorkflowEligibility ?? [],
    status: latestRow ? "qualification_scope_complete" : "qualification_scope_missing",
  };
}

function modelProviderRunClassEvidenceRow(coveredRunClass, rows) {
  const latestRow = rows.find((row) => row.coveredRunClass === coveredRunClass && row.reviewReasons.length === 0) ?? null;
  return {
    coveredRunClass,
    modelProviderDataHandlingPolicyId: latestRow?.id ?? null,
    protectedContentEligible: latestRow?.protectedContentEligible === true,
    status: latestRow ? "model_provider_run_class_complete" : "model_provider_run_class_missing",
  };
}

