    quarantineStalePropagationState: report.quarantineStalePropagationState ?? null,
    unblindingReason: report.unblindingReason ?? null,
    resolutionRecordId: report.resolutionRecordId ?? null,
    excludedFromLabelDenominator: report.excludedFromLabelDenominator === true,
