function normalizeCorrectnessClaimWeightWorksheet(worksheet, rowSource) {
  const id = worksheet?.id ?? worksheet?.correctnessClaimWeightWorksheetId;
  if (!id) return null;
  const claimSpanIds = normalizeStringArray(worksheet.claimSpanIds);
  const weights = Array.isArray(worksheet.claimSignificanceWeights) ? worksheet.claimSignificanceWeights : [];
  const statuses = normalizeStringArray(worksheet.correctnessCredencesStatuses);
  const weightSum = weights.reduce((sum, value) => sum + (Number.isFinite(value) ? value : 0), 0);
  const reviewReasons = [
    worksheet.ratingId || worksheet.adjudicationId || worksheet.verificationWorkspaceId ? null : "workflowReference",
    claimSpanIds.length ? null : "claimSpanIds",
    weights.length === claimSpanIds.length && weights.every((value) => Number.isFinite(value) && value >= 0) ? null : "claimSignificanceWeights",
    Math.abs(weightSum - 1) <= 0.001 ? null : "claimSignificanceWeightsSum",
    statuses.length === claimSpanIds.length ? null : "correctnessCredencesStatuses",
    Array.isArray(worksheet.unclearClaimExclusionFlags) ? null : "unclearClaimExclusionFlags",
    Number.isFinite(worksheet.advisoryAggregateCorrectnessEstimate) ? null : "advisoryAggregateCorrectnessEstimate",
    worksheet.submittedScoreOverrideFlag === true ? requiredPromptFieldReason("overrideExplanation", worksheet.overrideExplanation) : null,
    requiredPromptFieldReason("exposureBlindingState", worksheet.exposureBlindingState),
    requiredPromptFieldReason("createdBy", worksheet.createdBy),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    ratingId: worksheet.ratingId ?? null,
    adjudicationId: worksheet.adjudicationId ?? null,
    verificationWorkspaceId: worksheet.verificationWorkspaceId ?? null,
    claimSpanIds,
    claimSignificanceWeights: weights,
    correctnessCredencesStatuses: statuses,
    unclearClaimExclusionFlags: Array.isArray(worksheet.unclearClaimExclusionFlags) ? worksheet.unclearClaimExclusionFlags : [],
    advisoryAggregateCorrectnessEstimate: worksheet.advisoryAggregateCorrectnessEstimate ?? null,
    submittedScoreOverrideFlag: worksheet.submittedScoreOverrideFlag === true,
    overrideExplanation: worksheet.overrideExplanation ?? null,
    exposureBlindingState: worksheet.exposureBlindingState ?? null,
    createdBy: worksheet.createdBy ?? null,
    timestamp: worksheet.timestamp ?? null,
    reviewReasons,
    status: reviewReasons.length ? "correctness_claim_weight_worksheet_review_required" : "correctness_claim_weight_worksheet_complete",
  };
}

function normalizeProtectedArtifactRetentionRecord(record, rowSource) {
  const id = record?.id ?? record?.protectedArtifactRetentionId;
  if (!id) return null;
  const artifactType = record.artifactType ?? null;
  const suspectedProtectedContentLeak = record.suspectedProtectedContentLeak === true;
  const incidentErratumLinks = normalizeStringArray(record.incidentErratumLinks);
  const dependentArtifactClassesStaled = normalizeStringArray(record.dependentArtifactClassesStaled);
  const missingIncidentStaleClasses = REQUIRED_PROTECTED_ARTIFACT_INCIDENT_STALE_CLASSES
    .filter((artifactClass) => !dependentArtifactClassesStaled.includes(artifactClass));
  const reviewReasons = [
    REQUIRED_PROTECTED_ARTIFACT_TYPES.includes(artifactType) ? null : "artifactType",
    requiredPromptFieldReason("artifactIdOrStoragePointer", record.artifactIdOrStoragePointer ?? record.storagePointer),
    requiredPromptFieldReason("sourceSplitProtectionClass", record.sourceSplitProtectionClass),
    requiredPromptFieldReason("releaseConfigManifestId", record.releaseConfigManifestId),
    requiredPromptFieldReason("retentionDeletionPolicy", record.retentionDeletionPolicy),
    policyMentions(record.cacheOutboxPurgeStatus, ["purged"]) || policyMentions(record.cacheOutboxPurgeStatus, ["not_cached"]) ? null : "cacheOutboxPurgeStatus",
    policyMentions(record.backupSnapshotCoverage, ["split"]) ? null : "backupSnapshotCoverage",
    policyMentions(record.developmentStagingEligibility, ["revalidation"]) ? null : "developmentStagingEligibility",
    policyMentions(record.restoreTimeRevalidationStatus, ["passed"]) ? null : "restoreTimeRevalidationStatus",
    typeof record.suspectedProtectedContentLeak === "boolean" ? null : "suspectedProtectedContentLeak",
    policyMentions(record.incidentResponsePolicy, ["pause", "stale", "review"]) ? null : "incidentResponsePolicy",
    policyMentions(record.dependentArtifactStalePolicy, ["evaluation", "leaderboard", "label", "export"]) ? null : "dependentArtifactStalePolicy",
    suspectedProtectedContentLeak && !incidentErratumLinks.length ? "incidentErratumLinks" : null,
    suspectedProtectedContentLeak && missingIncidentStaleClasses.length ? `dependentArtifactClassesStaled:${missingIncidentStaleClasses.join(",")}` : null,
    suspectedProtectedContentLeak && !policyMentions(record.incidentReviewDecision, ["reason"]) ? "incidentReviewDecision:reason" : null,
    suspectedProtectedContentLeak && !policyMentions(record.dependentArtifactImpactStatus, ["stale"]) ? "dependentArtifactImpactStatus" : null,
    suspectedProtectedContentLeak && !policyMentions(record.submissionLanePauseStatus, ["pause"]) ? "submissionLanePauseStatus" : null,
    requiredPromptFieldReason("createdAt", record.createdAt),
    requiredPromptFieldReason("expiresAt", record.expiresAt ?? record.deletionAnonymizationTimestamp),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    artifactType,
    sourceSplitProtectionClass: record.sourceSplitProtectionClass ?? null,
    releaseConfigManifestId: record.releaseConfigManifestId ?? null,
    cacheOutboxPurgeStatus: record.cacheOutboxPurgeStatus ?? null,
    restoreTimeRevalidationStatus: record.restoreTimeRevalidationStatus ?? null,
    suspectedProtectedContentLeak,
    incidentResponsePolicy: record.incidentResponsePolicy ?? null,
    dependentArtifactStalePolicy: record.dependentArtifactStalePolicy ?? null,
    dependentArtifactClassesStaled,
    incidentErratumLinks,
    incidentReviewDecision: record.incidentReviewDecision ?? null,
    dependentArtifactImpactStatus: record.dependentArtifactImpactStatus ?? null,
    submissionLanePauseStatus: record.submissionLanePauseStatus ?? null,
    reviewReasons,
    status: reviewReasons.length ? "protected_artifact_retention_review_required" : "protected_artifact_retention_complete",
  };
}

function normalizeScoreConfidenceAnnotation(annotation, rowSource) {
  const id = annotation?.id ?? annotation?.scoreConfidenceAnnotationId ?? annotation?.raterScoreConfidenceId ?? annotation?.confidenceAnnotationId;
  if (!id) return null;
  const dimensionConfidences = normalizeDimensionConfidenceMap(annotation.dimensionConfidences ?? annotation.confidences);
  const missingDimensions = RUBRIC_DIMENSIONS.filter((dimension) => !Object.hasOwn(dimensionConfidences, dimension));
  const confidenceValues = Object.values(dimensionConfidences);
  const reviewReasons = [
    requiredPromptFieldReason("assignmentId", annotation.assignmentId),
    requiredPromptFieldReason("ratingId", annotation.ratingId),
    requiredPromptFieldReason("raterId", annotation.raterId),
    missingDimensions.length ? `dimensionConfidences:${missingDimensions.join(",")}` : null,
    confidenceValues.every((value) => Number.isFinite(value) && value >= 0 && value <= 1) ? null : "dimensionConfidences:range",
    requiredPromptFieldReason("scaleVersion", annotation.scaleVersion),
    policyMentions(annotation.annotationUsePolicy, ["not"]) && policyMentions(annotation.annotationUsePolicy, ["score"]) ? null : "annotationUsePolicy",
    annotation.excludedFromScoreComputation === true ? null : "excludedFromScoreComputation",
    annotation.visibleToPeersBeforeLock === false ? null : "visibleToPeersBeforeLock",
    requiredPromptFieldReason("timestamp", annotation.timestamp ?? annotation.createdAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    entityType: "RaterScoreConfidence",
    assignmentId: annotation.assignmentId ?? null,
    ratingId: annotation.ratingId ?? null,
    raterId: annotation.raterId ?? null,
    dimensionConfidences,
    scaleVersion: annotation.scaleVersion ?? null,
    excludedFromScoreComputation: annotation.excludedFromScoreComputation === true,
    visibleToPeersBeforeLock: annotation.visibleToPeersBeforeLock === true,
    reviewReasons,
    status: reviewReasons.length ? "score_confidence_annotation_review_required" : "score_confidence_annotation_complete",
  };
}

function normalizeRationaleEvidenceSpan(span, rowSource) {
  const id = span?.id ?? span?.spanId ?? span?.rationaleEvidenceSpanId;
  if (!id) return null;
  const spanTarget = span.spanTarget ?? span.target ?? null;
  const startOffset = Number(span.startOffset ?? span.start ?? span.characterStartOffset);
  const endOffset = Number(span.endOffset ?? span.end ?? span.characterEndOffset);
  const linkedDimensionOrFlag = span.linkedDimensionOrFlag ?? span.dimensionOrFlagLinked ?? span.dimension ?? span.flagKey ?? null;
  const visibilityState = span.visibilityState ?? null;
  const reviewReasons = [
    span.ratingId || span.adjudicationMemoId ? null : "ratingIdOrAdjudicationMemoId",
    requiredPromptFieldReason("itemTextVersionId", span.itemTextVersionId),
    ["position", "critique"].includes(spanTarget) ? null : "spanTarget",
    Number.isInteger(startOffset) && startOffset >= 0 ? null : "startOffset",
    Number.isInteger(endOffset) && endOffset > startOffset ? null : "endOffset",
    String(span.normalizedSelectedTextHash ?? "").startsWith("sha256:") ? null : "normalizedSelectedTextHash",
    RATIONALE_EVIDENCE_SPAN_LINK_CATEGORIES.includes(linkedDimensionOrFlag) ? null : "linkedDimensionOrFlag",
    requiredPromptFieldReason("noteId", span.noteId),
    RATIONALE_EVIDENCE_SPAN_VISIBILITY_STATES.includes(visibilityState) ? null : "visibilityState",
    span.hiddenUntilInitialRatingLock === true ? null : "hiddenUntilInitialRatingLock",
    span.rawSelectedTextStored === false ? null : "rawSelectedTextStored",
    requiredPromptFieldReason("timestamp", span.timestamp ?? span.createdAt),
  ].filter(Boolean);
  return {
    id,
    rowSource,
    ratingId: span.ratingId ?? null,
    adjudicationMemoId: span.adjudicationMemoId ?? null,
    itemTextVersionId: span.itemTextVersionId ?? null,
    spanTarget,
    startOffset: Number.isFinite(startOffset) ? startOffset : null,
    endOffset: Number.isFinite(endOffset) ? endOffset : null,
    normalizedSelectedTextHash: span.normalizedSelectedTextHash ?? null,
    linkedDimensionOrFlag,
    noteId: span.noteId ?? null,
    visibilityState,
    hiddenUntilInitialRatingLock: span.hiddenUntilInitialRatingLock === true,
    rawSelectedTextStored: span.rawSelectedTextStored === true,
    reviewReasons,
    status: reviewReasons.length ? "rationale_evidence_span_review_required" : "rationale_evidence_span_complete",
  };
}

function normalizeDimensionConfidenceMap(value) {
  if (Array.isArray(value)) {
    return Object.fromEntries(
      value
        .map((item) => [item?.dimension, item?.confidence])
        .filter(([dimension, confidence]) => RUBRIC_DIMENSIONS.includes(dimension) && Number.isFinite(confidence)),
    );
  }
  if (!value || typeof value !== "object") return {};
  return Object.fromEntries(
    Object.entries(value)
      .filter(([dimension]) => RUBRIC_DIMENSIONS.includes(dimension))
      .map(([dimension, confidence]) => [dimension, confidence]),
  );
}

