export function buildInteractionWorkflowEvidenceReport(releaseId, options = {}) {
  const groups = interactionWorkflowArtifactSpecs(releaseId).map((spec) => {
    const submittedRows = (options[spec.optionKey] ?? [])
      .map((resource) => normalizeInteractionWorkflowArtifact(resource, spec, `submitted_workflow_${spec.artifactType}`))
      .filter(Boolean);
    const seedRows = spec.seedRows.map((resource) => normalizeInteractionWorkflowArtifact(resource, spec, `seed_${spec.artifactType}`)).filter(Boolean);
    const rowsForGate = submittedRows.length ? submittedRows : seedRows;
    const complete = spec.requiredCoverageField
      ? (spec.requiredCoverageValues ?? []).every((value) =>
          rowsForGate.some((row) => row.reviewReasons.length === 0 && row[spec.requiredCoverageField] === value),
        )
      : rowsForGate.some((row) => row.reviewReasons.length === 0);
    return {
      spec,
      submittedRows,
      seedRows,
      rowsForGate,
      complete,
    };
  });
  const reviewSections = groups.flatMap((group) => [
    ...group.submittedRows.flatMap((row) => row.reviewReasons.map((reason) => ({ artifactType: group.spec.artifactType, artifactId: row.id, reason }))),
    group.complete
      ? null
      : { artifactType: group.spec.artifactType, artifactId: group.spec.artifactType, reason: "missing_complete_interaction_workflow_artifact" },
  ]).filter(Boolean);
  const counts = Object.fromEntries(
    groups.flatMap((group) => [
      [`submitted${group.spec.label}Count`, group.submittedRows.length],
      [`complete${group.spec.label}Count`, group.rowsForGate.filter((row) => row.reviewReasons.length === 0).length],
    ]),
  );
  const submittedEvidenceComplete = groups.every((group) => group.submittedRows.length > 0) && reviewSections.length === 0;
  return {
    id: `interaction-workflow-evidence-${releaseId}`,
    releaseId,
    generatedAt: new Date().toISOString(),
    requiredArtifactTypes: groups.map((group) => group.spec.artifactType),
    discussionIdentityStagingPolicies: DISCUSSION_IDENTITY_STAGING_POLICIES,
    discussionIdentityMaskPhaseStatuses: DISCUSSION_IDENTITY_MASK_PHASE_STATUSES,
    discussionRoleRevealPolicies: DISCUSSION_ROLE_REVEAL_POLICIES,
    ...Object.fromEntries(groups.map((group) => [group.spec.rowKey, [...group.seedRows, ...group.submittedRows]])),
    counts: {
      ...counts,
      submittedArtifactGroupCount: groups.filter((group) => group.submittedRows.length > 0).length,
      completeArtifactGroupCount: groups.filter((group) => group.complete).length,
      reviewSectionCount: reviewSections.length,
    },
    reviewSections,
    releaseUseStatus: reviewSections.length
      ? "interaction_workflow_evidence_review_required"
      : submittedEvidenceComplete
        ? "submitted_interaction_workflow_evidence_complete"
        : "seed_interaction_workflow_evidence_complete",
  };
}

function normalizeInteractionWorkflowArtifact(resource, spec, rowSource) {
  const id = resource?.id;
  if (!id) return null;
  const reviewReasons = [
    ...((spec.requiredFields ?? []).map((field) => requiredPromptFieldReason(field, artifactFieldValue(resource, field)))),
    ...((spec.arrayFields ?? []).map((field) => normalizeStringArray(artifactFieldValue(resource, field)).length ? null : field)),
    ...((spec.objectFields ?? []).map((field) => objectHasEntries(artifactFieldValue(resource, field)) ? null : field)),
    ...Object.entries(spec.objectKeys ?? {}).flatMap(([field, requiredKeys]) => {
      const value = artifactFieldValue(resource, field);
      return requiredKeys
        .filter((key) => !value || typeof value !== "object" || Array.isArray(value) || !Object.hasOwn(value, key))
        .map((key) => `${field}:${key}`);
    }),
    ...((spec.objectKeysFromArrayFields ?? []).flatMap((rule) => {
      const value = artifactFieldValue(resource, rule.objectField);
      const requiredKeys = normalizeStringArray(artifactFieldValue(resource, rule.arrayField));
      return requiredKeys
        .filter((key) => !value || typeof value !== "object" || Array.isArray(value) || !Object.hasOwn(value, key))
        .map((key) => `${rule.objectField}:${key}`);
    })),
    ...Object.entries(spec.allowedObjectValues ?? {}).flatMap(([field, allowedValues]) => {
      const value = artifactFieldValue(resource, field);
      if (!value || typeof value !== "object" || Array.isArray(value)) return [field];
      return Object.entries(value)
        .filter(([, entryValue]) => !allowedValues.includes(entryValue))
        .map(([key]) => `${field}:${key}`);
    }),
    ...Object.entries(spec.arrayIncludes ?? {}).flatMap(([field, requiredValues]) => {
      const value = normalizeStringArray(artifactFieldValue(resource, field));
      return requiredValues.filter((item) => !value.includes(item)).map((item) => `${field}:${item}`);
    }),
    ...((spec.objectKeysByFieldValue ?? []).flatMap((rule) => {
      const discriminator = artifactFieldValue(resource, rule.field);
      const requiredKeys = rule.values?.[discriminator] ?? [];
      const value = artifactFieldValue(resource, rule.objectField);
      return requiredKeys
        .filter((key) => !value || typeof value !== "object" || Array.isArray(value) || !Object.hasOwn(value, key))
        .map((key) => `${rule.objectField}:${key}`);
    })),
    ...((spec.numericFields ?? []).map((field) => Number.isFinite(artifactFieldValue(resource, field)) ? null : field)),
    ...((spec.numericRanges ?? []).map((rule) => {
      const value = artifactFieldValue(resource, rule.field);
      const min = rule.min ?? Number.NEGATIVE_INFINITY;
      const max = rule.max ?? Number.POSITIVE_INFINITY;
      return Number.isFinite(value) && value >= min && value <= max ? null : rule.field;
    })),
    ...((spec.booleanTrueFields ?? []).map((field) => artifactFieldValue(resource, field) === true ? null : field)),
    ...((spec.booleanFalseFields ?? []).map((field) => artifactFieldValue(resource, field) === false ? null : field)),
    ...((spec.booleanFields ?? []).map((field) => typeof artifactFieldValue(resource, field) === "boolean" ? null : field)),
    ...Object.entries(spec.exactFields ?? {}).map(([field, expectedValue]) => artifactFieldValue(resource, field) === expectedValue ? null : field),
    ...Object.entries(spec.stringIncludes ?? {}).flatMap(([field, requiredFragments]) => {
      const normalized = String(artifactFieldValue(resource, field) ?? "").toLowerCase();
      return requiredFragments.filter((fragment) => !normalized.includes(String(fragment).toLowerCase())).map((fragment) => `${field}:${fragment}`);
    }),
    ...((spec.oneOfFields ?? []).map((fields) => fields.some((field) => {
      const value = artifactFieldValue(resource, field);
      return value !== undefined && value !== null && value !== "";
    }) ? null : fields.join("|"))),
    ...Object.entries(spec.enumFields ?? {}).map(([field, allowedValues]) => allowedValues.includes(artifactFieldValue(resource, field)) ? null : field),
    ...((spec.distinctFieldSets ?? []).map((fields) => {
      const values = fields.map((field) => artifactFieldValue(resource, field));
      const normalizedValues = values.map((value) => (typeof value === "string" ? value.trim() : value)).filter((value) => value !== undefined && value !== null && value !== "");
      return normalizedValues.length === fields.length && new Set(normalizedValues).size === normalizedValues.length ? null : `${fields.join("|")}:distinct`;
    })),
  ].filter(Boolean);
  return {
    ...resource,
    id,
    rowSource,
    artifactType: spec.artifactType,
    reviewReasons,
    evidenceStatus: reviewReasons.length ? `${spec.artifactType}_review_required` : `${spec.artifactType}_complete`,
  };
}

function artifactFieldValue(resource, fieldPath) {
  if (!fieldPath || typeof fieldPath !== "string") return undefined;
  return fieldPath.split(".").reduce((value, key) => {
    if (value === undefined || value === null || typeof value !== "object") return undefined;
    return value[key];
  }, resource);
}

